LAB_DF = pd.read_excel("lab.xlsx")
PANEL_DF = pd.read_excel("Lab_panel.xlsx")

# Convert text columns to uppercase (once)
for col in LAB_DF.columns:
    if LAB_DF[col].dtype == "object":
        LAB_DF[col] = LAB_DF[col].map(lambda x: x.upper() if isinstance(x, str) else x)

for col in PANEL_DF.columns:
    if PANEL_DF[col].dtype == "object":
        PANEL_DF[col] = PANEL_DF[col].map(lambda x: x.upper() if isinstance(x, str) else x)


