def discussion_management_ahfl(filename=None, dos=None, config=None):
    if config is None:
        return [{"Discussed Management": ["No Evidence Found"]}]
    
    consult_file = config.get("consult_file", "Consult_Order_AHFL_NEW_ALL.xlsx")
    
    
    try:
        consult_df = pd.read_excel(consult_file)
        consult_df['DOS'] = pd.to_datetime(consult_df['DOS']).dt.strftime('%m/%d/%Y')
        consult_df.columns = consult_df.columns.str.strip()
        # Convert DOS column to string and normalize (handle datetime)
        consult_df['DOS'] = consult_df['DOS'].astype(str).str.strip()
        required_cols = ['Filename', 'DOS', 'Consult', 'Status']
        missing_cols = [col for col in required_cols if col not in consult_df.columns]
        if missing_cols:
            print(f"Missing columns: {missing_cols}")
            return [{"Discussed Management": ["No Evidence Found"]}]
    except Exception as e:
        print(f"Error reading consult file: {e}")
        return [{"Discussed Management": ["No Evidence Found"]}]
    
    if filename is None or dos is None:
        return [{"Discussed Management": ["No Evidence Found"]}]
    
    target_dos_normalized = normalize_date(str(dos))
    target_filename = str(filename).strip()
    
    # Debug: print what we are looking for
    # print(f"[DEBUG] Looking for Filename='{target_filename}', DOS='{target_dos_normalized}'")
    
    matched_rows = consult_df[consult_df['Filename'].astype(str).str.strip() == target_filename]
    # print(f"[DEBUG] Matched by filename: {len(matched_rows)} rows")
    
    matched_consults = []
    for _, row in matched_rows.iterrows():
        row_dos_norm = normalize_date(str(row['DOS']))
        if row_dos_norm == target_dos_normalized:
            matched_consults.append(row)
            # print(f"[DEBUG] Matched DOS: {row['DOS']} -> {row_dos_norm}")
    
    # print(f"[DEBUG] Total matched consults: {len(matched_consults)}")
    
    specialties = []
    for row in matched_consults:
        status = str(row.get('Status', '')).strip().lower()
        if status not in ['completed', 'compeletd', 'completd', 'active']:
            continue
        consult_text = str(row.get('Consult', ''))
        # Optional: remove leading date if present (better regex will handle anyway)
        consult_text = re.sub(r'^\d{1,2}/\d{1,2}/\d{4}\s+', '', consult_text)
        consult_text_upper = consult_text.upper()
        if any(re.search(p, consult_text_upper) for p in EXCLUDED_SPECIALTY_PATTERNS1):
            continue
        # More flexible pattern: match "consult to" then capture up to status or end
        specialty_match = re.search(
            r'consult\s+to\s+(.*?)(?=\s+(?:Completed|Active|Completd|Discontinued)\b|$)',
            consult_text,
            re.IGNORECASE
        )
        if specialty_match:
            specialty = specialty_match.group(1).strip()
            specialty = re.sub(r'\s+', ' ', specialty).upper()
            # Remove extra words like "Inpatient" that might be captured
            specialty = re.sub(r'^INPATIENT\s+', '', specialty)
            if specialty:
                specialties.append(specialty)
                # print(f"[DEBUG] Extracted specialty: {specialty}")
    
    specialties = sorted(list(set(specialties)))
    if specialties:
        return [{"Discussed Management": specialties}]
    return [{"Discussed Management": ["No Evidence Found"]}]

def independent_interpretation_ahfl(lab_str, assessment_str, hpi_str, Result_Date_str):
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str, Result_Date_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)
    text_upper = input_str.upper()
    interpretation_keywords = [
        "INDEPENDENTLY INTERPRETED", "INDEPENDENT INTERPRETATION",
        "PERSONALLY REVIEWED AND INTERPRETED", "REVIEWED AND INTERPRETED BY ME",
        "INTERPRETED BY ME", "I INTERPRETED THE EKG", "EKG INTERPRETED", "I INTERPRETED THE ECHO",
        "ECHO INTERPRETED", "MY ECHO INTERPRETATION", "I INTERPRETED THE XRAY",
        "I INTERPRETED THE CT", "I INTERPRETED THE MRI", "XRAY INTERPRETED",
        "CT INTERPRETED", "MRI INTERPRETED", "I INTERPRETED THE PFT",
        "PFT INTERPRETED", "I INTERPRETED THE HOLTER", "HOLTER INTERPRETED",
        "PACEMAKER INTERROGATION INTERPRETED", "MY EKG INTERPRETATION IS NSR",
        "MY CT INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
        "MY X-RAY INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
        "INTERPRETATION BY ME", "I PERSONALLY VIEWED AND INTERPRETED"
    ]
    interpretation_patterns = [
        r"I\s+(?:PERSONALLY\s+)?INTERPRETED\s+(?:THE\s+)?(?:EKG|ECHO|X-?RAY|CT|MRI|PFT|HOLTER|PACEMAKER)",
        r"MY\s+(?:EKG|ECHO|X-?RAY|CT|MRI)\s+INTERPRETATION(?:\s+IS|\s*:)\s+[^.\n]+",
        r"(?:EKG|ECHO|X-?RAY|CT|MRI|HOLTER|PFT)\s+INTERPRETED",
        r"INDEPENDENTLY\s+INTERPRETED",
        r"REVIEWED\s+AND\s+INTERPRETED\s+BY\s+ME"
    ]
    results = []
    for phrase in interpretation_keywords:
        if phrase in text_upper:
            results.append(phrase)
    for pattern in interpretation_patterns:
        for match in re.finditer(pattern, input_str, flags=re.IGNORECASE):
            results.append(match.group(0).strip())
    seen = set()
    unique_results = []
    for r in results:
        key = r.upper()
        if key not in seen:
            seen.add(key)
            unique_results.append(r)
    return [{"Independent Interpretation": unique_results or ["No Evidence Found"]}]

def independent_historian_ahfl(assessment_str, hospital_course_str, subjective_str, hpi_str):
    input_str = " ".join(filter(None, [assessment_str, hospital_course_str, subjective_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str).upper()
    relation_keywords = ["PARENT","GUARDIAN","SPOUSE","HUSBAND","WIFE","SON","DAUGHTER",
                         "FAMILY MEMBER","RELATIVE","BROTHER","SISTER","UNCLE","AUNT",
                         "GRANDMOTHER","GRANDFATHER","FRIEND","NEIGHBOR","CAREGIVER",
                         "CASE MANAGER","NURSE","PHYSICIAN ASSISTANT","CLINICAL STAFF",
                         "EMS PERSONNEL","EMT","PARAMEDIC","EMPLOYER","WITNESS","LEGAL GUARDIAN",
                         "SURROGATE DECISION-MAKER"]
    action_keywords = ["REPORTED","STATED","TOLD","MENTIONED","INFORMED","SAID",
                       "PROVIDED BY","GIVEN BY","OBTAINED FROM","HISTORY TAKEN FROM",
                       "HISTORY PROVIDED BY","OBSERVED BY","DOCUMENTED BY","COLLECTED FROM"]
    previous_next_relation = ["DISCUSSED","TOLD","THEM","REPORTED","STATED","MENTIONED","INFORMED","SAID",
                              "PROVIDED BY","GIVEN BY","OBTAINED FROM","HISTORY TAKEN FROM",
                              "HISTORY PROVIDED BY","OBSERVED BY","DOCUMENTED BY","COLLECTED FROM","MENTION"]
    phrase_patterns = [
        r"(?i)\bINDEPENDENT HISTORIAN\b",
        r"(?i)\bHISTORY PROVIDED BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bHISTORY TAKEN FROM\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bOBTAINED FROM\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bINFORMATION GIVEN BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bVERIFIED BY\s+(?:{})\b".format("|".join(relation_keywords))
    ]
    threshold = 90
    temp_chunks = []
    buffer = ""
    for part in input_str.split("\n"):
        if buffer and len(buffer.strip()) <= threshold:
            temp_chunks.append(buffer.strip())
            buffer = part
        else:
            if buffer:
                buffer += " " + part
            else:
                buffer = part
    if buffer.strip():
        temp_chunks.append(buffer.strip())
    sentences = []
    for chunk in temp_chunks:
        pieces = [s.strip() for s in re.split(r'[.;!]', chunk) if s.strip()]
        sentences.extend(pieces)
    results = []
    for i, sentence in enumerate(sentences):
        words = sentence.split()
        found_relation = any(word in relation_keywords for word in words)
        found_action = any(word in sentence for word in action_keywords)
        found_phrase = any(re.search(pattern, sentence) for pattern in phrase_patterns)
        if (found_relation and found_action) or found_phrase:
            results.append(sentence.strip())
        if i > 0:
            prev = sentences[i-1].upper()
            curr = sentence.upper()
            matched_prev = [word for word in relation_keywords if word in prev]
            matched_curr = [word for word in previous_next_relation if word in curr]
            if matched_prev and matched_curr:
                results.append(" ".join(matched_prev) + " " + " ".join(matched_curr))
    if results:
        unique_results = ", ".join(list(dict.fromkeys(results)))
        return [{"Independent Historian": unique_results}]
    return [{"Independent Historian": "No Evidence Found"}]

def process_row_ahfl(row, config):
    discussion = discussion_management_ahfl(filename=row["Filename"], dos=row["DOS"], config=config)
    interpretation = independent_interpretation_ahfl(row["lab_str"], row["assessment_str"], row["hpi_str"], row["Result_Date_str"])
    prior_review = review_prior_external_notes_ahfl(row["lab_str"], row["assessment_str"], row["hpi_str"], row["code_status_str"])
    lab_orders = lab_order_ahfl(row["assessment_str"])
    lab_review_result = lab_review_ahfl(row["lab_str"], row["DOS"])
    historian = independent_historian_ahfl(row["assessment_str"], row["hospital_course_str"], row["subjective_str"], row["hpi_str"])
    mdm2_level, label, reasons = Process_MDM2(discussion, interpretation, prior_review, lab_orders, lab_review_result, historian)
    prior_review_vals = flatten_list_of_dicts(prior_review, "Prior Review")
    lab_orders_simple = simplify_list_of_dicts(lab_orders, "Lab Order")
    lab_review_simple = simplify_list_of_dicts(lab_review_result, "Lab Review")
    discussion_vals = flatten_list_of_dicts(discussion, "Discussed Management")
    interpretation_vals = flatten_list_of_dicts(interpretation, "Independent Interpretation")
    historian_vals = flatten_list_of_dicts(historian, "Independent Historian")
    details_parts = []
    details_parts.append(f"Review Prior Notes> {prior_review_vals or ['No Evidence Found']}")
    details_parts.append(f"Lab Order> {lab_orders_simple or ['No Evidence Found']}")
    details_parts.append(f"Lab Review> {lab_review_simple or ['No Evidence Found']}")
    details_parts.append(f"Discussion Management/Test> {discussion_vals or ['No Evidence Found']}")
    details_parts.append(f"Independent Interpretation> {interpretation_vals or ['No Evidence Found']}")
    details_parts.append(f"Independent Historian> {historian_vals or ['No Evidence Found']}")
    details = "~".join(details_parts)
    sections = []
    def safe_text(value):
        return str(value).replace(";", ",").strip()
    if row.get("assessment_str"):
        sections.append(f"[Assessment]: {safe_text(row['assessment_str'])}")
    if row.get("hpi_str"):
        sections.append(f"[HPI]: {safe_text(row['hpi_str'])}")
    if row.get("lab_str"):
        sections.append(f"[Lab]: {safe_text(row['lab_str'])}")
    if row.get("phy_str"):
        sections.append(f"[Physical]: {safe_text(row['phy_str'])}")
    if row.get("hospital_course_str"):
        sections.append(f"[Hospital Course]: {safe_text(row['hospital_course_str'])}")
    if row.get("subjective_str"):
        sections.append(f"[Subjective]: {safe_text(row['subjective_str'])}")
    if row.get("objective_str"):
        sections.append(f"[Objective]: {safe_text(row['objective_str'])}")
    if row.get("Result_Date_str"):
        sections.append(f"[Result Date]: {safe_text(row['Result_Date_str'])}")
    combined_text = " ~ ".join(sections).replace("\n", " ").strip()
    chart = row["Filename"].replace("AHFL_", "").replace(".TIF", "")
    return pd.Series({
        "Filename": row["Filename"],
        "Chart": chart,
        "DOS": row["DOS"],
        "Visit": row["Visit"],
        "Visit Time": row["Visit_time"],
        "MDM2_Level": label.upper(),
        "REASONS FOR MDM2": details,
        "REFERENCE TEXT MDM2": combined_text,
        "Page_No": row["Page_No"]
    })


