def discussion_management_arn(assessment_str, lab_str, hospitalcourse_str, consultation_str):
    """
    consultation_str: The combined consultation data for the current row only
    """
    results = []

    # Check if it matches medical departments (your existing logic)
    medical_departments = {
        'CARDIOLOGY': ['CARDIOLOGY', 'CARDIAC', 'CARDIO', 'CV', 'CARDIOLOGIST'],
        'NEUROLOGY': ['NEUROLOGY', 'NEURO', 'NEUROLOGICAL', 'NEUROLOGIST'],
        'ONCOLOGY': ['ONCOLOGY', 'ONCO', 'CANCER', 'ONCOLOGIST', 'HEMATOLOGY/ONCOLOGY'],
        'PULMONOLOGY': ['PULMONOLOGY', 'PULMONARY', 'PULM', 'RESPIRATORY', 'CHEST', 'PULMONOLOGIST'],
        'GASTROENTEROLOGY': ['GASTROENTEROLOGY', 'GASTRO', 'GI', 'GASTROINTESTINAL', 'GASTROENTEROLOGIST'],
        'NEPHROLOGY': ['NEPHROLOGY', 'NEPHRO', 'RENAL', 'NEPHROLOGIST'],
        'INFECTIOUS_DISEASE': ['INFECTIOUS DISEASE', 'INFECTIOUS', 'ID', 'INFECTIOUS DISEASE SPECIALIST'],
        'UROLOGY': ['UROLOGY', 'URO', 'UROLOGICAL', 'UROLOGIST'],
        'HEMATOLOGY': ['HEMATOLOGY', 'HEME', 'BLOOD', 'HEMATOLOGIST'],
        'ENDOCRINOLOGY': ['ENDOCRINOLOGY', 'ENDO', 'ENDOCRINE', 'ENDOCRINOLOGIST'],
        'RHEUMATOLOGY': ['RHEUMATOLOGY', 'RHEUM', 'RHEUMATOLOGICAL', 'RHEUMATOLOGIST'],
        'DERMATOLOGY': ['DERMATOLOGY', 'DERM', 'DERMATOLOGIST'],
        
        'ORTHOPEDICS': ['ORTHOPEDICS', 'ORTHO', 'ORTHOPEDIC', 'ORTHOPEDIST'],
        'PHYSICAL_THERAPY': ['PHYSICAL THERAPY', 'PT', 'PHYSICAL THERAPIST'],
        'OCCUPATIONAL_THERAPY': ['OCCUPATIONAL THERAPY', 'OT', 'OCCUPATIONAL THERAPIST'],
        'SPEECH_THERAPY': ['SPEECH THERAPY', 'SPEECH', 'ST', 'SPEECH LANGUAGE PATHOLOGY', 'SLP', 'SPEECH PATHOLOGIST'],
        'RESPIRATORY_THERAPY': ['RESPIRATORY THERAPY', 'RT', 'RESPIRATORY THERAPIST'],
        'PSYCHIATRY': ['PSYCHIATRY', 'PSYCH', 'PSYCHIATRIC', 'PSYCHIATRIST'],
        'SOCIAL_WORK': ['SOCIAL WORK', 'SOCIAL WORKER', 'SOCIAL SERVICES'],
        'CASE_MANAGEMENT': ['CASE MANAGEMENT', 'CASE MANAGER'],
        'CARE_MANAGEMENT': ['CARE MANAGEMENT', 'CONSULT TO CARE'],
        'CRITICAL_CARE': ['CRITICAL CARE', 'ICU', 'INTENSIVE CARE', 'CRITICAL CARE MEDICINE'],
        'PALLIATIVE_CARE': ['PALLIATIVE CARE', 'PALLIATIVE', 'PALLIATIVE MEDICINE'],
    }

    # --- DEFINE find_medical_department FUNCTION ---
    def find_medical_department(text):
            """Check if text contains any medical department"""
            text_upper = text.upper().strip()
            
            # Special handling for PT/OT combinations
            pt_ot_combinations = [
                'PT/OT', 'OT/PT', 'PT/OT/ST', 'PT OT', 'OT PT', 'PT OT ST',
                'PHYSICAL THERAPY/OCCUPATIONAL THERAPY', 'OCCUPATIONAL THERAPY/PHYSICAL THERAPY'
            ]
            
            for combo in pt_ot_combinations:
                if combo in text_upper:
                    return "PT/OT"
            
            for main_dept, variations in medical_departments.items():
                for variation in variations:
                    # Exact word matching to avoid partial matches
                    if re.search(r'\b' + re.escape(variation) + r'\b', text_upper):
                        return main_dept.replace('_', ' ')
            return None
    
    # --- Step 1: Load and clean consultation terms from CURRENT ROW ---
    try:
        #print(f"Debug: Processing consultation data for current row")
        
        # Get consultation data from current row only (from consultation_str)
        raw_consultation_terms = []
        if consultation_str and pd.notna(consultation_str) and str(consultation_str).strip():
            raw_consultation_terms = [str(consultation_str)]
        
        #print(f"DEBUG: Found {len(raw_consultation_terms)} raw consultation terms for this row")
        
        # Clean the consultation terms (your existing logic)
        clean_consultation_terms = []
        seen_terms = set()
        
        for term in raw_consultation_terms:
            #print(f"DEBUG: Processing term: '{term}'")
            
            # Split multi-line text into individual lines
            lines = term.split('\n')
            #print(f"DEBUG: Split into {len(lines)} lines")
            
            for line_num, line in enumerate(lines):
                #print(f"DEBUG: Processing line {line_num}: '{line}'")
                
                # Clean each line separately
                cleaned_term = line.strip().upper()

                # Skip empty terms
                if not cleaned_term:
                    continue
                    
                # Remove common noise patterns
                if re.search(r'\b\d+of\d+\b', cleaned_term) or 'PAGE' in cleaned_term:
                    continue
                    
                # Remove hospital/discharge summary text
                if any(noise in cleaned_term for noise in ['HOSPITALIST', 'DISCHARGE SUMMARY', 'WESTERN ARIZONA', 'REGIONAL MEDICAL', 'ONECONTENT']):
                    continue
                    
                # Remove doctor names
                if re.search(r'\bDR\.?\s+[A-Z]', cleaned_term) or re.search(r'[A-Z]+\s+PHY\b', cleaned_term):
                    continue
                    
                # Remove quotes and special characters
                cleaned_term = re.sub(r'["\']', '', cleaned_term)
                
                # Remove specific noisy patterns
                noisy_patterns = [
                    r'PATIENT IN THE PROCESS OF TRANSFERRING.*',
                    r'EMERGENCY ROOM.*',
                    r'SEE .*',
                    r'GENERATED BY.*',
                    r'GENERATED ON.*',
                    r'ATTENDING.*',
                    r'ADMITTED.*',
                    r'ENCOUNTER.*',
                    r'NAME.*',
                ]
            
                for pattern in noisy_patterns:
                    cleaned_term = re.sub(pattern, '', cleaned_term).strip()
                
                # Skip if term is too short or just noise
                if len(cleaned_term) < 3 or cleaned_term in ['NONE', '2OF3', '3OF4', 'NA', 'N/A', '']:
                    continue
                
                #print(f"DEBUG: After cleaning: '{cleaned_term}'")
                
                           
                # Check if the cleaned term matches any medical department
                matched_department = None
                for main_dept, variations in medical_departments.items():
                    for variation in variations:
                        if re.search(r'\b' + re.escape(variation) + r'\b', cleaned_term):
                            matched_department = main_dept.replace('_', ' ')
                            break
                    if matched_department:
                        break
                
                if matched_department and matched_department not in seen_terms:
                    clean_consultation_terms.append(matched_department)
                    seen_terms.add(matched_department)
                    #print(f"DEBUG: ADDED: {matched_department} CONSULTED")
        
        # Add consultation terms to results
        for term in clean_consultation_terms:
            results.append(f"{term} CONSULTED")
            
        #print(f"DEBUG: Consultation results for this row: {results}")
            
    except Exception as e:
        #print(f"DEBUG: Error processing consultation data: {e}")
        import traceback
        traceback.print_exc()

    # --- Step 2: If no consultations found in consultation_str, apply discussion management logic ---
    if not results:
        #print("DEBUG: No consultations found in consultation_str, applying discussion management logic")
        # Combine input strings
        input_str = " ".join(filter(None, [assessment_str, lab_str, hospitalcourse_str]))
        input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)
        
        # --- Step 2: Combined Exclusion Patterns ---
        input_str = re.sub(
            r'(?ix)'
            r'(?:'
            r'CONSULTANTS?\s*[:-]?\s*(?:\n|\r|\r\n)?\s*NOT(?:\s+ON\s+FILE)?'
            r'|CONSULTANTS?\s*[:-]?\s*(?:\n|\r|\r\n|\s)*NOT\s+ON\s+FILE'
            r'|\bONCOLOGY\s+FOLLOW(?:\s*UP)?\b'
            r'|\bFOLLOWS?\s+(?:UP\s+WITH|WITH)\s+[A-Z][A-Z\s]+\b'
            r'|\bCONSIDER\s+(?:A\s+)?CONSULTS?(?:ATION)?\b'
            r'|\b(MIGHT|MAY)\s+NEED\s+[A-Z\s]*(CONSULTS?|CONSULTATION)\b'
            r'|\bMEDICINE\s+WAS\s+CONSULTED\b'
            r'|\b(FOLLOW(?:\s*[\n\r]\s*|\s*[-\s]*)UP|FLUP)\s+[A-Z\s]*(CULTURES?|CONSULTS?|CONSULTATION)\b'
            r'|\b(?:TELE\s+)?[A-Z\s]*CONSULT(?:S|ATION)?\s+(?:ORDER\s+PLACED|ORDERED|REQUEST(?:ED|ING)?)\b'
            r'|\bREFER\s+(?:TO\s+)?THE?\s*DISCHARGE\s+SUMMARY\b'
            r'|\b[A-Z][A-Z\s]+CONSULT\S*\s+WILL\s+(?:BE\s+)?GREATLY\s+APPRECIATE(?:D)?\b'
            r'|\b(?:GENERAL\s+)?SURGER(Y|ICAL)\s+CONSULTS?(?:ATION)?\b'
            r'|\b(?:PENDING\s+[A-Z\s]*(CONSULTS?|CONSULTATION)|[A-Z\s]*(CONSULTS?|CONSULTATION)\s+(IS\s+)?PENDING)\b'
            r'|\bMANAGEMENT\s+CONSULT(?:ED|S?|ATION)?\b'
            r'|\bHOSPICE\s+CONSULT(?:ED|S?|ATION)?\b'
            r'|\bCONSULT(?:ED|S?|ATION)?\s+FOR\s+(?:FURTHER\s+)?(RECOMMENDATIONS?|MANAGEMENT|ADVICE|INPUT)\b'
            r'|\bAPPRECIATE\s+[A-Z\s]*CONSULTATION\b'
            r'|\b[A-Z\s]*EVALUATION\s+REQUESTED\b'
            r'|\bTHANKS?(?:\s*YOU)?(?:\s+VERY\s+MUCH)?\s+FOR\s+THE\s+CONSULTATION\b'
            r'|DISCUSSED\s+(?:PLAN|CASE|CARE|TREATMENT)?\s*(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY|RELATIVES?|HIS\s+WIFE|HER\s+HUSBAND|SPOUSE|SON|DAUGHTER|CHILD|CHILDREN|CAREGIVER)\b'
            r'|SPOKE\s+(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY|RELATIVES?|HIS\s+WIFE|HER\s+HUSBAND|SPOUSE|SON|DAUGHTER|CHILD|CHILDREN|CAREGIVER)\b'
            r'|TALKED\s+(?:TO|WITH)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY|RELATIVES?|HIS\s+WIFE|HER\s+HUSBAND|SPOUSE)\b'
            r'|CASE\s+DISCUSSED\s+(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY)\b'
            r'|FOLLOW\s+UP\s+(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?)\b'
            # NEW EXCLUSIONS: Following and recommendation patterns
            r'|\b[A-Z][A-Za-z\s]*\s+FOLLOWING\s+[A-Z][A-Za-z\s]*\b'
            r'|\bFOLLOWING\s+BY\s+[A-Z][A-Za-z\s]+\b'
            r'|\bFOLLOWED\s+BY\s+[A-Z][A-Za-z\s]+\b'
            r'|\bPER\s+[A-Z][A-Za-z\s]+\s+RECOMMENDATION\b'
            r'|\bAS\s+PER\s+[A-Z][A-Za-z\s]+\s+RECOMMENDATION\b'
            r'|\bACCORDING\s+TO\s+[A-Z][A-Za-z\s]+\s+RECOMMENDATION\b'
            r'|\bRECOMMENDATION\s+FROM\s+[A-Z][A-Za-z\s]+\b'
            r'|\bCONSULT\s+TO\s+TELE\s+PULMONOLOGY\b'
            r'|\bCONSULT\s+TO\s+(TELE\s+)?[A-Z][A-Za-z]+\b'
            r'|\bWILL\s+NEED\s+[A-Z][A-Za-z]+\s+CONSULT\b'
            r'|\bTELE\s+[A-Z][A-Za-z]+\s+CONSULTED\b'
            r'|\bDISCUSS\s+WITH\s+[A-Z][A-Za-z]+\s+TOMORROW\b'
            r')',
            '',
            input_str
        )
        
        # Pattern 1: "consult/consulted" + department
        consult_patterns = [
            r'(?:CONSULT|CONSULTED|CONSULTATION)\s+(?:WITH\s+)?(?:THE\s+)?([A-Z][A-Za-z\s\/]+?(?=\s|\.|,|$|;))',
            r'([A-Z][A-Za-z\s\/]+)\s+(?:CONSULT|CONSULTED|CONSULTATION)',
            r'CONSULT\s+(?:FOR\s+)?([A-Z][A-Za-z\s\/]+)',
            r'\bCONSULTANTS?\s*[:\-]\s*([A-Z][A-Za-z\/\s]+)\b',
            r'\bCONSULTANTS?\s*(?:IS|ARE)?\s*([A-Z][A-Za-z\/\s]+)\b',
            r'([A-Z][A-Za-z]+)\s+CONSULTED\s+[A-Z][A-Za-z]+',  # handles "Neuro consulted Asthma
        ]

        # --- ADD COMPREHENSIVE PATTERNS HERE ---
        comprehensive_patterns = [
            r'(\b(?:[A-Z][A-Za-z]+)(?:\s+[A-Z][A-Za-z]+)*?)\s+CONSULTED(?:\s+[A-Z][A-Za-z]+)*',  # "Neuro consulted Asthma"
            r'CONSULTED\s+(\b(?:[A-Z][A-Za-z]+)(?:\s+[A-Z][A-Za-z]+)*)',  # "Consulted Neurology for asthma"
            r'(\b(?:[A-Z][A-Za-z]+)(?:\s+[A-Z][A-Za-z]+)*?)\s+CONSULT(?:\s+[A-Z][A-Za-z]+)*',  # "Neuro consult placed"
            # ADD MISSpelling patterns:
            r'(\b(?:[A-Z][A-Za-z]+)(?:\s+[A-Z][A-Za-z]+)*?)\s+CONSTULED(?:\s+[A-Z][A-Za-z]+)*',  # "Neuro constuled"
            r'(\b(?:[A-Z][A-Za-z]+)(?:\s+[A-Z][A-Za-z]+)*?)\s+CONSULED(?:\s+[A-Z][A-Za-z]+)*',   # "Neuro consuled"
        ]

        # Combine both pattern lists
        all_consult_patterns = consult_patterns + comprehensive_patterns
        
        # Pattern 2: "discuss/discussed" + department  
        discuss_patterns = [
            r'(?:DISCUSS|DISCUSSED|DISCUSSION)\s+(?:WITH\s+)?(?:THE\s+)?([A-Z][A-Za-z\s\/]+?(?=\s|\.|,|$|;))',
            r'([A-Z][A-Za-z\s\/]+)\s+(?:DISCUSS|DISCUSSED|DISCUSSION)',
            r'DISCUSSED\s+(?:CASE\s+)?WITH\s+([A-Z][A-Za-z\s\/]+)',
            r'SPOKE\s+WITH\s+([A-Z][A-Za-z\s\/]+)',
            r'TALKED\s+WITH\s+([A-Z][A-Za-z\s\/]+)',
            r'\b[A-Z][A-Za-z]+\s+Dr\.\s*[A-Z][A-Za-z]+\s+consulted\b',
            r'\b[A-Z][A-Za-z]+\s+Dr\.\s*[A-Z][A-Za-z\.]+\s+[A-Za-z]+\s+consulted\b',
            r'\b[A-Z][A-Za-z\s]+?\s+Dr\.\s*[A-Z][A-Za-z\.]+\s*[A-Za-z]*\s+consulted\b',
            r'\bNEPHROLOGY\s+DR\.\s*SLOAN\s+CONSULTED\b',
            r'\b[A-Z][A-Za-z]+\s+Dr\.\s*[A-Z][A-Za-z]+\s+consulted\b',
            r'DISCUSS(?:ED)?\s+(?:PLAN|CASE|CARE|TREATMENT)?\s*WITH\s+([A-Z][A-Za-z\s,\/]+)',
            r'I\s+personally\s+discussed[\s\S]*?(?:nursing|case management|respiratory|therap(?:y|ies)|pharmacy)',
        ]
        
                
        # Search for consult patterns - USE THE COMBINED LIST
        for pattern in all_consult_patterns:  # CHANGED: now using combined list
            matches = re.finditer(pattern, input_str, re.IGNORECASE)
            for match in matches:
                if match.lastindex:
                    department_text = match.group(1).strip()
                    department = find_medical_department(department_text)
                    if department:
                        result = f"CONSULTED {department}"
                        if result not in results:
                            results.append(result)
        
        # Search for discuss patterns
        for pattern in discuss_patterns:
            matches = re.finditer(pattern, input_str, re.IGNORECASE)
            for match in matches:
                if match.lastindex:
                    department_text = match.group(1).strip()
                    department = find_medical_department(department_text)
                    if department:
                        result = f"DISCUSSED WITH {department}"
                        if result not in results:
                            results.append(result)
        
       
    else:
        #print("DEBUG: Using consultation_str data")
        pass

    # Remove duplicates and return
    results = list(set(results))
    return [{"Discussed Management": results if results else ["No Evidence Found"]}]



def independent_interpretation_arn(lab_str, assessment_str, hpi_str, hospitalcourse_str):
    # --- Step 1: Combine safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str, hospitalcourse_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)

    # --- Step 2: Keywords (generic only, no variants) ---
    interpretation_keywords = [
            "INDEPENDENTLY INTERPRETED", "INDEPENDENT INTERPRETATION",
            "PERSONALLY REVIEWED AND INTERPRETED", "REVIEWED AND INTERPRETED BY ME",
            "INTERPRETED BY ME", "MY INTERPRETATION", "MY EKG INTERPRETATION",
            "I INTERPRETED THE EKG", "EKG INTERPRETED", "I INTERPRETED THE ECHO",
            "ECHO INTERPRETED", "MY ECHO INTERPRETATION", "I INTERPRETED THE XRAY",
            "I INTERPRETED THE CT", "I INTERPRETED THE MRI", "XRAY INTERPRETED",
            "CT INTERPRETED", "MRI INTERPRETED", "I INTERPRETED THE PFT",
            "PFT INTERPRETED", "I INTERPRETED THE HOLTER", "HOLTER INTERPRETED",
            "PACEMAKER INTERROGATION INTERPRETED", "MY EKG INTERPRETATION IS NSR",
            "MY CT INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
            "MY X-RAY INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
            "INTERPRETATION BY ME", "I PERSONALLY VIEWED AND INTERPRETED", "INDEPENDENT REVIEW OF", "REVIEW AND INTERPRETATION OF",
            "PERSONALLY REVIEWED AND INTERPRETED", "REVIEWED AND INTERPRETED"
    ]

    # --- Step 3: Regex patterns (handles variants) ---
    interpretation_patterns = [
            r"I\s+(PERSONALLY\s+)?INTERPRETED\s+(THE\s+)?(EKG|ECHO|XRAY|X-RAY|CT|MRI|PFT|HOLTER|PACEMAKER)",
            r"MY\s+(EKG|ECHO|XRAY|CT|MRI|INTERPRETATION)",
            r"(EKG|ECHO|XRAY|CT|MRI|HOLTER|PACEMaker|PFT)\s+INTERPRETED",
            r"INDEPENDENTLY\s+INTERPRETED",
            r"REVIEWED\s+AND\s+INTERPRETED\s+BY\s+ME",
            r"(?:^|\W)MY\s+(CT|X-?RAY|EKG)\s+INTERPRETATION(?::| IS)\s+.*",
            r"INDEPENDENT\s+REVIEW\s+OF\s+(?:THE\s+)?(CHEST\s+X-?RAY|CT|MRI|X-?RAY|IMAGING)",
            r"REVIEW\s+AND\s+INTERPRETATION\s+OF\s+(?:THE\s+)?(CXR|CHEST\s+X-?RAY|CT|MRI|X-?RAY|IMAGING)",
            r"(?:PERSONALLY\s+)?REVIEWED?\s+AND\s+INTERPRETED?\s+(?:THE\s+)?(?:IMAGING|STUDIES|CXR|X-?RAY|CT|MRI)",
            r"I\s+(?:PERSONALLY\s+)?(?:REVIEWED|INTERPRETED)\s+(?:THE\s+)?(?:IMAGING|CHEST\s+X-?RAY|CXR|CT|MRI)"
    ]


    results = []

    # --- Step 4: Keyword matches ---
    for phrase in interpretation_keywords:
        if phrase in input_str.upper():
            results.append(phrase)

    # --- Step 5: Regex matches ---
    for pattern in interpretation_patterns:
        for match in re.finditer(pattern, input_str, flags=re.IGNORECASE):
            results.append(match.group(0).strip())

    # --- Step 6: Unique + ordered ---
    seen = set()
    unique_results = [x for x in results if not (x in seen or seen.add(x))]

    return [{"Independent Interpretation": unique_results or ["No Evidence Found"]}]


def independent_historian_arn(assessment_str, hpi_str):
    # --- Step 1: Combine safely with spacing ---
    input_str = " ".join(filter(None, [assessment_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str).upper()

    # ===== FIXED: CLEAR SEPARATION BETWEEN MEDICAL vs NON-MEDICAL SOURCES =====
    
    # --- NON-MEDICAL relation keywords (family/friends/caregivers) ---
    non_medical_relations = ["PARENT", "GUARDIAN", "SPOUSE", "HUSBAND", "WIFE", "SON", "DAUGHTER", "FAMILY",
                            "FAMILY MEMBER", "RELATIVE", "BROTHER", "SISTER", "UNCLE", "AUNT",
                            "GRANDMOTHER", "GRANDFATHER", "FRIEND", "NEIGHBOR", "CAREGIVER",
                            "EMPLOYER", "WITNESS", "LEGAL GUARDIAN", "SURROGATE DECISION-MAKER",
                            "SIGNIFICANT OTHER", "PARTNER", "BOYFRIEND", "GIRLFRIEND"]
    
    # --- MEDICAL PROFESSIONALS (EXCLUDE THESE) ---
    medical_professionals = ["NURSE", "PHYSICIAN", "DOCTOR", "DR", "MD", "DO", "NP", "PA", 
                            "PHYSICIAN ASSISTANT", "CLINICAL STAFF", "EMS PERSONNEL", "EMT", 
                            "PARAMEDIC", "CASE MANAGER", "SOCIAL WORKER", "THERAPIST",
                            "RESPIRATORY THERAPIST", "PHARMACIST", "DIETITIAN"]
    
    # --- Action keywords ---
    action_keywords = ["REPORTED", "STATED", "TOLD", "MENTIONED", "INFORMED", "SAID",
                      "PROVIDED BY", "GIVEN BY", "OBTAINED FROM", "HISTORY TAKEN FROM",
                      "HISTORY PROVIDED BY", "OBSERVED BY", "DOCUMENTED BY", "COLLECTED FROM"]

    # --- Step 4: IMPROVED Phrase patterns (NON-MEDICAL ONLY) ---
    phrase_patterns = [
        r"(?i)\bINDEPENDENT HISTORIAN\b",
        r"(?i)\bHISTORY PROVIDED BY\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bHISTORY TAKEN FROM\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bOBTAINED FROM\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bINFORMATION GIVEN BY\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bVERIFIED BY\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bALL HISTORY (?:OBTAINED|PROVIDED) FROM\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bUNABLE TO PROVIDE HISTORY.*?(?:OBTAINED|FROM)\s+(?:{})\b".format("|".join(non_medical_relations)),
    ]

    # --- NEW: Clear exclusion patterns for medical professionals ---
    exclusion_patterns = [
        r"(?i)\b(?:HISTORY|INFORMATION).*?(?:{})\b".format("|".join(medical_professionals)),
        r"(?i)\b(?:OBTAINED|PROVIDED).*?(?:{})\b".format("|".join(medical_professionals)),
    ]

    # --- Step 6: Split into sentences ---
    threshold = 90
    temp_chunks = []
    buffer = ""

    for part in input_str.split("\n"):
        if buffer and len(buffer.strip()) <= threshold:
            temp_chunks.append(buffer.strip())
            buffer = part
        else:
            if buffer:
                buffer += " " + part
            else:
                buffer = part
    if buffer.strip():
        temp_chunks.append(buffer.strip())

    sentences = []
    for chunk in temp_chunks:
        pieces = [s.strip() for s in re.split(r'[.;!]', chunk) if s.strip()]
        sentences.extend(pieces)

    results = []

    # --- Step 7: IMPROVED sentence checking ---
    for i, sentence in enumerate(sentences):
        # FIRST: Check if this sentence contains MEDICAL professionals (EXCLUDE)
        contains_medical = any(re.search(pattern, sentence) for pattern in exclusion_patterns)
        if contains_medical:
            continue  # Skip medical professional references
        
        # SECOND: Check for clear independent historian patterns
        found_clear_pattern = any(re.search(pattern, sentence) for pattern in phrase_patterns)
        if found_clear_pattern:
            # Extract the specific relationship if mentioned
            for relation in non_medical_relations:
                if relation in sentence:
                    results.append(f"HISTORY FROM {relation}")
                    break
            else:
                results.append("INDEPENDENT HISTORIAN USED")
            continue
        
        # THIRD: Check for relation + action combination (NON-MEDICAL ONLY)
        words = sentence.split()
        found_relation = any(relation in words for relation in non_medical_relations)
        found_action = any(action in sentence for action in action_keywords)
        
        if found_relation and found_action:
            # Extract the specific non-medical relationship
            for relation in non_medical_relations:
                if relation in sentence:
                    results.append(f"HISTORY FROM {relation}")
                    break

    # --- Step 8: Return CLEAN results ---
    if results:
        # Remove duplicates and take the most specific one
        unique_results = []
        seen = set()
        for result in results:
            if result not in seen:
                seen.add(result)
                unique_results.append(result)
        
        # If multiple, prefer the most specific one
        if len(unique_results) > 1:
            # Look for the most specific relationship mentioned
            specific_results = [r for r in unique_results if any(rel in r for rel in non_medical_relations)]
            if specific_results:
                unique_results = [specific_results[0]]
        
        return [{"Independent Historian": unique_results[0]}]
    else:
        return [{"Independent Historian": "No Evidence Found"}]


def process_row_arn(row, config):
    """
    Process a single row for facility ARN.
    Expects the following helper functions to be defined:
        review_prior_external_notes_arn(lab_str, assessment_str, hpi_str)
        independent_interpretation_arn(lab_str, assessment_str, hpi_str, hospitalcourse_str)
        discussion_management_arn(assessment_str, lab_str, hospitalcourse_str, consultation_str)
        lab_order_arn(assessment_str)
        lab_review_arn(lab_str, dos=None)
        independent_historian_arn(assessment_str, hpi_str)
    """
    # --- Run helper functions ---
    discussion = discussion_management_arn(
        row["assessment_str"], row["lab_str"], row["hospitalcourse_str"], row["consultation_str"]
    )
    interpretation = independent_interpretation_arn(
        row["lab_str"], row["assessment_str"], row["hpi_str"], row["hospitalcourse_str"]
    )
    prior_review = review_prior_external_notes_arn(
        row["lab_str"], row["assessment_str"], row["hpi_str"]
    )
    lab_orders = lab_order_arn(row["assessment_str"])
    lab_review_result = lab_review_arn(row["lab_str"], row["DOS"])
    historian = independent_historian_arn(row["assessment_str"], row["hpi_str"])

    # --- Run MDM2 logic (uses utils.Process_MDM2) ---
    from utils import Process_MDM2, flatten_list_of_dicts, simplify_list_of_dicts
    mdm2_level, label, reasons = Process_MDM2(
        discussion, interpretation, prior_review,
        lab_orders, lab_review_result, historian
    )

    # --- Flatten results for the REASONS column ---
    prior_review_vals = flatten_list_of_dicts(prior_review, "Prior Review")
    lab_orders_simple = simplify_list_of_dicts(lab_orders, "Lab Order")
    lab_review_simple = simplify_list_of_dicts(lab_review_result, "Lab Review")
    discussion_vals = flatten_list_of_dicts(discussion, "Discussed Management")
    interpretation_vals = flatten_list_of_dicts(interpretation, "Independent Interpretation")
    historian_vals = flatten_list_of_dicts(historian, "Independent Historian")

    details_parts = [
        f"Review Prior Notes> {prior_review_vals or ['No Evidence Found']}",
        f"Lab Order> {lab_orders_simple or ['No Evidence Found']}",
        f"Lab Review> {lab_review_simple or ['No Evidence Found']}",
        f"Discussion Management/Test> {discussion_vals or ['No Evidence Found']}",
        f"Independent Interpretation> {interpretation_vals or ['No Evidence Found']}",
        f"Independent Historian> {historian_vals or ['No Evidence Found']}"
    ]
    details = "~".join(details_parts)

    # --- Build reference text (selected sections) ---
    def safe_text(value):
        return str(value).replace(";", ",").strip()

    sections = []
    if row.get("assessment_str"):
        sections.append(f"[Assessment]: {safe_text(row['assessment_str'])}")
    if row.get("hpi_str"):
        sections.append(f"[HPI]: {safe_text(row['hpi_str'])}")
    if row.get("hospitalcourse_str"):
        sections.append(f"[Hospital Course]: {safe_text(row['hospitalcourse_str'])}")
    if row.get("lab_str"):
        sections.append(f"[Lab]: {safe_text(row['lab_str'])}")
    if row.get("objective_str"):
        sections.append(f"[Objective]: {safe_text(row['objective_str'])}")
    if row.get("consultation_str"):
        sections.append(f"[Consultation]: {safe_text(row['consultation_str'])}")
    combined_text = " ~ ".join(sections).replace("\n", " ").strip()

    # --- Extract Chart ID (remove prefix and extension) ---
    chart = row["Filename"].replace("ARN_", "").replace(".TIF", "")

    # --- Return Series with expected column names ---
    return pd.Series({
        "Filename": row["Filename"],
        "Chart": chart,
        "DOS": row["DOS"],
        "Visit": row["Visit"],
        "Visit Time": row["Visit_time"],
        "MDM2_Level": label.upper(),
        "REASONS FOR MDM2": details,
        "REFERENCE TEXT MDM2": combined_text,
        "Page No": row["Page_No"]
    })


