def review_prior_external_notes_bcs(lab_str, assessment_str, hpi_str):
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str]))
    lab_text = input_str.upper().strip()
    keywords = [
        "PRIOR EXTERNAL NOTES", "EXTERNAL PROVIDER NOTES", "OUTSIDE RECORDS",
        "OUTSIDE NOTES", "REVIEWED PRIOR NOTES", "REVIEWED OUTSIDE NOTES",
        "REVIEWED PCP NOTES", "REVIEWED CONSULT NOTES", "REVIEWED SPECIALIST NOTES",
        "PREVIOUS RECORDS REVIEWED", "EXTERNAL RECORDS REVIEWED", 
        "EXTERNAL DOCUMENTS REVIEWED", "ED REVIEWED", "I HAVE REVIEWED IMAGING", "ECG REVIEWED BY",
        "I REVIEWED RELEVANT LABS, IMAGING AND PRIOR RECORDS", "REVIEWED AND AGREE WITH THE ABOVE FINDINGS", "REVIEWED BY NEUROLOGY", "REVIEWED BY ME",
        "ECG: REVIEWED", "CG: REVIEWED", "LABS AND THE IMAGES REVIEWED AND CONSIDERED IN THE EVALUATION OF PATIENT", 
        "LABS AND IMAGES REVIEWED AND CONSIDERED IN THE EVALUATION OF PATIENT",
        "I REVIEWED RELEVANT LABS, MAGING AND PRIOR RECORDS AND UPDATED HOME MEDICATION RECONCILIATION", "KG REVIEW", "EKG READ BY ME", "G REVIEWE",
        "REVIEWED BOTH EKGS", "G REVIEWED", "MRI REVIEWED", "EKG REVIE"
    ]
    patterns = [
        r"REVIEW(?:ED|ING)?\s+(?:PRIOR|EXTERNAL|OUTSIDE)\s+(?:NOTES|RECORDS)",
        r"NOTES\s+FROM\s+(?:PCP|CARDIOLOGY|RADIOLOGY|ONCOLOGY|NEUROLOGY)",
        r"CONSULT\s+NOTES\s+REVIEW(?:ED|ING)?",
        r"OUTSIDE\s+HOSPITAL\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"PREVIOUS\s+VISIT\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"RADIOLOGICAL\s+(?:IMAGING|STUDIES)\s+REVIEWED\s+BY\s+ME",
        r"ALL\s+RADIOLOGICAL\s+STUDIES\s+HAVE\s+BEEN\s+REVIEWED(?:\s+BY\s+ME)?",
        r"REVIEWED\s+BY\s+ME\s+AND\s+I\s+AGREE\s+WITH\s+RADIOLOG(?:IST|ICAL)\s+READING",
        r"I\s+AGREE\s+WITH\s+THE\s+SUMMARY\s+OF\s+THE\s+RADIOLOGICAL\s+INTERPRETATIONS(?:s+LISTED\s+BELOW)?"
    ]
    results = []
    for kw in keywords:
        if kw in lab_text:
            results.append({"Prior Review": kw})
    for pattern in patterns:
        match = re.search(pattern, lab_text)
        if match:
            results.append({"Prior Review": match.group(0)})
    if results:
        vals = [item["Prior Review"] for item in results]
        unique_vals = list(dict.fromkeys(vals))
        best_match = max(unique_vals, key=len)
        return [{"Prior Review": best_match}]
    return [{"Prior Review": "No Evidence Found"}]

def lab_order_bcs(assessment_str):
    lab_df = LAB_DF
    group_test_df = PANEL_DF
    input_str = (assessment_str or "").upper()
    input_str_normalized = re.sub(r'[-\s]+', ' ', input_str)
    input_str_normalized = re.sub(r'\bAXIALT\b', 'AXIAL', input_str_normalized)
    input_str_normalized = re.sub(r'\bCOMPUTERIZED\b', 'COMPUTED', input_str_normalized)
    input_str_normalized = re.sub(r'\bTOMOGRAPHY:\b', 'TOMOGRAPHY', input_str_normalized)
    results = []
    matched_labs = set()
    strong_medication_patterns = [
        r'^\s*\b(?:CONTINUE|HOLD|START)\b.*\b(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
        r'^\s*.*\b\d+\s*(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
    ]
    lines = input_str_normalized.split('\n')
    filtered_lines = []
    for line in lines:
        line = line.strip()
        if not line:
            continue
        is_pure_medication = any(re.search(med_pat, line, re.IGNORECASE) for med_pat in strong_medication_patterns)
        if not is_pure_medication:
            filtered_lines.append(line)
    filtered_text = ' '.join(filtered_lines)
    exclusion_terms = ['MG', 'MCG', 'TABLET', 'CAPSULE', 'TAB', 'PO', 'IV', 'BID', 'TID', 'QDAY']
    diet_context_patterns = [
        r'\bLOW\s+SODIUM\s+DIET\b',
        r'\bLOW\s*:\s*(?:SODIUM\s*/\s*DIABETIC|DIABETIC\s*/\s*SODIUM)\s+DIET\b',
        r'\bLOW\s*:\s*(?:SODIUM|DIABETIC)\s+DIET\b'
        r'\bRESTRICTED\s+SODIUM\s+DIET\b',
        r'\bSODIUM\s+RESTRICTION\b',
        r'\bSODIUM\s+INTAKE\b',
        r'\bREPLACE\s+POTASSIUM(?:\s+\w+){0,3}\b',
        r'\bSODIUM\s*/\s*DIABETIC\s+DIET\b',
        r'\bDIABETIC\s*/\s*SODIUM\s+DIET\b'
    ]
    glucose_monitor_patterns = [
        r'\bMONITOR\s+BLOOD\s+GLUCOSE\b',
        r'\bMONITOR\s+GLUCOSE\s+LEVELS?\b',
        r'\bCHECK\s+BLOOD\s+GLUCOSE\b',
        r'\bCHECK\s+GLUCOSE\s+LEVELS?\b',
        r'\bCHECK\s+BLOOD\s+GLUCOSE\s+(?:\d+\s*(?:TIMES\s*)?|\bTWICE\b|\bONCE\b|\bTHRICE\b)?\s*(?:DAILY|A\s*DAY)\b'
    ]
    sodium_diet_context = any(re.search(pat, filtered_text) for pat in diet_context_patterns)
    glucose_monitor_context = any(re.search(pat, filtered_text) for pat in glucose_monitor_patterns)
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_normalized = re.sub(r'[-\s]+', ' ', lab_name.upper())
        if lab_name_normalized in exclusion_terms:
            continue
        if sodium_diet_context and lab_name_normalized in ["SODIUM", "NA"]:
            continue
        if re.search(r'\b' + re.escape(lab_name_normalized) + r'\b', filtered_text):
            matched_labs.add(lab_name)
    enhanced_order_patterns = [
        (r'\b(?:COMPUTED\s+)?(?:AXIAL\s+)?TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bCT\s+(?:SCAN)?\b', 'CT SCAN'),
        (r'\bCAT\s+SCAN\b', 'CT SCAN'),
        (r'\bAXIAL\s+TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bMRI\b', 'MRI'),
        (r'\bX-?RAY\b', 'X-RAY'),
        (r'\bULTRASOUND\b', 'ULTRASOUND'),
        (r'\bECHOCARDIOGRAM\b', 'ECHOCARDIOGRAM'),
        (r'\bEKG\b', 'EKG'),
        (r'\bECG\b', 'ECG'),
        (r'\bBLOOD\s+CULTURES?\b', 'BLOOD CULTURE'),
        (r'\bURINE\s+CULTURES?\b', 'URINE CULTURE'),
        (r'\bSPUTUM\s+CULTURES?\b', 'SPUTUM CULTURE'),
        (r'\bWOUND\s+CULTURES?\b', 'WOUND CULTURE'),
        (r'\b(?:REPEAT|REPEATED)\s+BLOOD\s+CULTURES?\b', 'BLOOD CULTURE'),
        (r'\b(?:OBTAIN|GET|ORDER|SEND)\s+(?:BLOOD|URINE)\s+CULTURES?\b', 'CULTURE'),
        (r'\bCULTURES?\s+(?:DRAWN|OBTAINED|SENT)\b', 'CULTURE'),
        (r'\bCULTURES?\s+(?:NEGATIVE|POSITIVE)\b', 'CULTURE'),
        (r'\bOBTAIN\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bGET\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bORDER\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bNEED\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
    ]
    for pattern, test_name in enhanced_order_patterns:
        if re.search(pattern, filtered_text, re.IGNORECASE):
            matched_labs.add(test_name)
    deduplication_rules = {
        'CT SCAN': ['CT', 'COMPUTED TOMOGRAPHY'],
        'COMPUTED TOMOGRAPHY': ['CT'],
        'ECHOCARDIOGRAM': ['ECHO'],
        'CAROTID DOPPLER': ['DOPPLER'],
        'URINE CULTURE': ['URINE'],
    }
    for primary_term, terms_to_remove in deduplication_rules.items():
        if primary_term in matched_labs:
            for term in terms_to_remove:
                if term in matched_labs:
                    matched_labs.remove(term)
    specific_imaging_terms = ['MRI', 'CT SCAN', 'COMPUTED TOMOGRAPHY', 'X-RAY', 'ULTRASOUND', 'ECHOCARDIOGRAM', 'EKG', 'ECG']
    if any(term in matched_labs for term in specific_imaging_terms) and 'IMAGING STUDY' in matched_labs:
        matched_labs.remove('IMAGING STUDY')
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]
        panel_labs_normalized = [re.sub(r'[-\s]+', ' ', lab.upper()) for lab in panel_labs]
        if panel_labs and all(re.search(r'\b' + re.escape(lab_norm) + r'\b', filtered_text) for lab_norm in panel_labs_normalized):
            results.append({"Lab Order": panel_name})
            matched_labs = matched_labs - set(panel_labs)
    for lab in matched_labs:
        results.append({"Lab Order": lab})
    unique_results = []
    seen_labs = set()
    for result in results:
        lab_name = result["Lab Order"]
        if lab_name not in seen_labs:
            seen_labs.add(lab_name)
            unique_results.append(result)
    if not unique_results:
        return [{"Lab Order": "No Evidence Found"}]
    return unique_results

def lab_review_bcs(lab_str, dos=None):
    lab_df = LAB_DF
    group_test_df = PANEL_DF
    def has_dates(text):
        date_pattern = r'(\d{1,2}/\d{1,2}/\d{2,4}|[A-Za-z]{3}-\d{1,2}-\d{4})'
        return bool(re.search(date_pattern, text))
    if dos and has_dates(lab_str):
        filtered_lab_str = get_lab_content_by_dos(lab_str, dos)
    else:
        filtered_lab_str = lab_str
    input_str = (filtered_lab_str or "").upper()
    results = []
    matched_labs = set()
    short_lab_mapping = {
        'CA': 'CALCIUM', 'K': 'POTASSIUM', 'NA': 'SODIUM', 'MG': 'MAGNESIUM',
        'CL': 'CHLORIDE', 'P': 'PHOSPHORUS', 'FE': 'IRON', 'HGB': 'HEMOGLOBIN',
        'HCT': 'HEMATOCRIT', 'WBC': 'WHITE BLOOD CELL COUNT', 'RBC': 'RED BLOOD CELL COUNT',
        'PLT': 'PLATELET COUNT', 'PLATELETS': 'PLATELET COUNT', 'PT': 'PROTHROMBIN TIME',
        'INR': 'INTERNATIONAL NORMALIZED RATIO', 'BUN': 'BLOOD UREA NITROGEN', 
        'CR': 'CREATININE', 'CREAT': 'CREATININE', 'AST': 'ASPARTATE AMINOTRANSFERASE',
        'ALT': 'ALANINE AMINOTRANSFERASE', 'ALP': 'ALKALINE PHOSPHATASE', 
        'TBIL': 'BILIRUBIN TOTAL', 'BILIRUBIN': 'BILIRUBIN TOTAL', 'TOTAL BILIRUBIN': 'BILIRUBIN TOTAL',
        'ALB': 'ALBUMIN', 'TP': 'TOTAL PROTEIN', 'CO2': 'CARBON DIOXIDE', 'BICARB': 'CARBON DIOXIDE',
        'SGPT': 'ALANINE AMINOTRANSFERASE', 'SGOT': 'ASPARTATE AMINOTRANSFERASE', 'POC BEDSIDE GLUCOSE': 'GLUCOSE'
    }
    def is_lab_present(lab_name, text):
        lab_upper = lab_name.upper()
        if re.search(r'\b' + re.escape(lab_upper) + r'\b', text, re.IGNORECASE):
            return True
        for abbr, full_name in short_lab_mapping.items():
            if full_name == lab_upper:
                if re.search(r'\b' + re.escape(abbr) + r'\b', text, re.IGNORECASE):
                    return True
        word_order_variations = {
            'BILIRUBIN TOTAL': [r'TOTAL\s+BILIRUBIN', r'BILIRUBIN,\s*TOTAL'],
        }
        if lab_upper in word_order_variations:
            for pattern in word_order_variations[lab_upper]:
                if re.search(pattern, text, re.IGNORECASE):
                    return True
        return False
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    panel_definitions = {}
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = []
        for col in lab_columns:
            if pd.notna(row[col]):
                lab_name = str(row[col]).upper().strip()
                if lab_name == 'RED BLOOD CELL COUNT  ':
                    lab_name = 'RED BLOOD CELL COUNT'
                if lab_name:
                    panel_labs.append(lab_name)
        if panel_labs:
            panel_definitions[panel_name] = panel_labs
    detected_panels = []
    panel_components_found = set()
    for panel_name, required_labs in panel_definitions.items():
        all_components_found = True
        for lab in required_labs:
            if not is_lab_present(lab, input_str):
                all_components_found = False
                break
        if all_components_found:
            detected_panels.append(panel_name)
            for lab in required_labs:
                panel_components_found.add(lab)
                for abbr, full_name in short_lab_mapping.items():
                    if full_name == lab:
                        panel_components_found.add(abbr)
    for panel in detected_panels:
        results.append({"Lab Review": panel})
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_clean = lab_name.upper().strip()
        if lab_name_clean in panel_components_found:
            continue
        if re.search(r'\b' + re.escape(lab_name_clean) + r'\b', input_str, re.IGNORECASE):
            matched_labs.add(lab_name)
    for lab in matched_labs:
        if lab.upper() not in panel_components_found:
            results.append({"Lab Review": lab})
    imaging_patterns = [
        (r'\b(CT\s+SCAN|CT|CAT\s+SCAN)\b', 'CT SCAN'),
        (r'\b(X-?RAY|X\s+RAY|XR\s+CHEST|XR)\b', 'X-RAY'), 
        (r'\b(MRI\s+SCAN|MRI)\b', 'MRI'),
        (r'\b(ULTRASOUND|US)\b', 'ULTRASOUND'),
        (r'\b(?:ECHOCARDIOGRAM|ECHO)\b', 'ECHOCARDIOGRAM'),
        (r'\b(MAMMOGRAM)\b', 'MAMMOGRAM'),
        (r'\b(DOPPLER)\b', 'DOPPLER'),
        (r'\b(FLUOROSCOPY)\b', 'FLUOROSCOPY'),
        (r'\b(ANGIOGRAM)\b', 'ANGIOGRAM'),
    ]
    culture_patterns = [
        (r'\b(BLOOD\s+CULTURE)\b', 'BLOOD CULTURE'),
        (r'\b(URINE\s+CULTURE)\b', 'URINE CULTURE'),
        (r'\b(SPUTUM\s+CULTURE)\b', 'SPUTUM CULTURE'),
        (r'\b(WOUND\s+CULTURE)\b', 'WOUND CULTURE'),
        (r'\b(AEROBIC\s+CULTURE)\b', 'AEROBIC CULTURE'),
        (r'\b(ANAEROBIC\s+CULTURE)\b', 'ANAEROBIC CULTURE'),
    ]
    for pattern, test_name in imaging_patterns + culture_patterns:
        if re.search(pattern, input_str, re.IGNORECASE):
            results.append({"Lab Review": test_name})
    panel_components = {
        'COMPLETE BLOOD COUNT': ['WBC', 'RBC', 'HGB', 'HCT', 'PLT', 'PLATELET COUNT', 
                                'WHITE BLOOD CELL COUNT', 'RED BLOOD CELL COUNT', 'HEMOGLOBIN', 
                                'HEMATOCRIT', 'MCV', 'MCH', 'MCHC', 'RDW', 'MPV'],
        'BASIC METABOLIC PANEL': ['NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
                                 'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
                                 'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM'],
        'COMPREHENSIVE METABOLIC PANEL': ['NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
                                         'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
                                         'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM', 'ALBUMIN', 
                                         'TOTAL PROTEIN', 'ALKALINE PHOSPHATASE', 'ALANINE AMINOTRANSFERASE', 
                                         'ASPARTATE AMINOTRANSFERASE', 'BILIRUBIN TOTAL', 'ALT', 'AST', 'SGPT',
                                         'ALKALINE', 'PHOSPHATASE', 'TBIL', 'BILIRUBIN'],
        'ELECTROLYTE PANEL': ['NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
                             'CO2', 'CARBON DIOXIDE', 'BICARB'],
        'HEPATIC FUNCTION PANEL': ['ALBUMIN', 'TOTAL PROTEIN', 'BILIRUBIN TOTAL', 
                                  'ALKALINE PHOSPHATASE', 'ALANINE AMINOTRANSFERASE', 
                                  'ASPARTATE AMINOTRANSFERASE', 'ALT', 'AST', 'SGPT',
                                  'ALKALINE', 'PHOSPHATASE', 'TBIL', 'BILIRUBIN'],
        'RENAL FUNCTION PANEL': ['NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
                                'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
                                'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM', 'ALBUMIN', 'PHOSPHORUS'],
        'LIPID PANEL': ['CHOLESTEROL', 'TRIGLYCERIDES', 'HDL CHOLESTEROL', 'LDL CHOLESTEROL'],
        'URINALYSIS': ['URINE COLOR', 'URINE APPEARANCE', 'URINE GLUCOSE', 'URINE BILIRUBIN', 
                      'URINE BLOOD', 'URINE PROTEIN', 'URINE NITRITE', 'URINE LEUKOCYTES', 
                      'URINE SPECIFIC GRAVITY', 'URINE PH', 'UROBILINOGEN', 'URINE']
    }
    equivalence_map = {
        "CBC": "COMPLETE BLOOD COUNT",
        "BMP": "BASIC METABOLIC PANEL", 
        "CMP": "COMPREHENSIVE METABOLIC PANEL",
        "LFT": "LIVER FUNCTION TESTS",
        "RFT": "RENAL FUNCTION TESTS",
        "HEPATIC FUNCTION PANEL": "LIVER FUNCTION TESTS",
        "XR CHEST": "X-RAY",
        "XR": "X-RAY",
        "PT INR": "INTERNATIONAL NORMALIZED RATIO",
        "PROTIME": "PROTHROMBIN TIME",
        "PTT": "PARTIAL THROMBOPLASTIN TIME",
        "APTT": "PARTIAL THROMBOPLASTIN TIME",
        "ALKALINE": "ALKALINE PHOSPHATASE",
        "PHOSPHATASE": "ALKALINE PHOSPHATASE",
        "SGPT": "ALANINE AMINOTRANSFERASE",
        "SGOT": "ASPARTATE AMINOTRANSFERASE"
    }
    equivalence_map.update(short_lab_mapping)
    cleaned_results = []
    seen_items = set()
    for entry in results:
        item = entry["Lab Review"].upper().strip()
        normalized_item = equivalence_map.get(item, item)
        if normalized_item not in seen_items:
            seen_items.add(normalized_item)
            cleaned_results.append({"Lab Review": normalized_item})
    final_results = []
    panel_groups = {
        'LIVER FUNCTION TESTS': ['HEPATIC FUNCTION PANEL', 'LFT'],
        'COMPREHENSIVE METABOLIC PANEL': ['CMP'],
        'COMPLETE BLOOD COUNT': ['CBC'],
        'BASIC METABOLIC PANEL': ['BMP']
    }
    always_panel_components = {
        'URINALYSIS': ['URINE COLOR', 'URINE APPEARANCE', 'URINE GLUCOSE', 'URINE BILIRUBIN', 
                    'URINE BLOOD', 'URINE PROTEIN', 'URINE NITRITE', 'URINE LEUKOCYTES', 
                    'URINE SPECIFIC GRAVITY', 'URINE PH', 'UROBILINOGEN', 'URINE', 'PH'],
        'COMPLETE BLOOD COUNT': ['WBC', 'RBC', 'HGB', 'HCT', 'PLT', 'PLATELET COUNT', 
                                'WHITE BLOOD CELL COUNT', 'RED BLOOD CELL COUNT', 'HEMOGLOBIN', 
                                'HEMATOCRIT', 'MCV', 'MCH', 'MCHC', 'RDW', 'MPV'],
        'COMPREHENSIVE METABOLIC PANEL': ['NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
                                        'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
                                        'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM', 'ALBUMIN', 
                                        'TOTAL PROTEIN', 'ALKALINE PHOSPHATASE', 'ALANINE AMINOTRANSFERASE', 
                                        'ASPARTATE AMINOTRANSFERASE', 'BILIRUBIN TOTAL', 'ALT', 'AST', 'SGPT',
                                        'ALKALINE', 'PHOSPHATASE', 'TBIL', 'BILIRUBIN'],
    }
    always_keep_categories = [
        'CT SCAN', 'X-RAY', 'MRI', 'ULTRASOUND', 'ECHOCARDIOGRAM',
        'TROPONIN', 'LIPASE', 'HCG', 'MAGNESIUM',
        'INTERNATIONAL NORMALIZED RATIO', 'PROTHROMBIN TIME', 'PARTIAL THROMBOPLASTIN TIME'
    ]
    included_panels = set()
    for entry in cleaned_results:
        item = entry["Lab Review"].upper()
        should_include = True
        if item in always_keep_categories:
            should_include = True
        else:
            for primary_panel, equivalent_panels in panel_groups.items():
                if item in equivalent_panels:
                    if primary_panel not in included_panels:
                        entry["Lab Review"] = primary_panel
                        included_panels.add(primary_panel)
                    else:
                        should_include = False
                    break
                elif item == primary_panel:
                    if item not in included_panels:
                        included_panels.add(item)
                    else:
                        should_include = False
                    break
            if should_include:
                for panel_name, components in always_panel_components.items():
                    if item in components:
                        should_include = False
                        break
        if should_include:
            final_results.append(entry)
    final_cleaned_results = []
    ct_scan_found = any(entry["Lab Review"] == "CT SCAN" for entry in results)
    seen = set()
    equivalents = {'CBC': 'COMPLETE BLOOD COUNT', 'BMP': 'BASIC METABOLIC PANEL'}
    for entry in results:
        lab_name = entry["Lab Review"]
        if lab_name == "CT" and ct_scan_found:
            continue
        normalized_name = equivalents.get(lab_name, lab_name)
        if normalized_name not in seen:
            seen.add(normalized_name)
            final_cleaned_results.append({"Lab Review": normalized_name})
    if not final_cleaned_results:
        return [{"Lab Review": "No Evidence Found"}]
    return final_cleaned_results

def discussion_management_bcs(assessment_str, lab_str, DVT_Prophylaxis_str):
    results = []

    # Combine input strings
    input_str = " ".join(filter(None, [assessment_str, lab_str, DVT_Prophylaxis_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)
    
    # --- Step 2: Combined Exclusion Patterns ---
    input_str = re.sub(
        r'(?ix)'
        r'(?:'
        r'CONSULTANTS?\s*[:-]?\s*(?:\n|\r|\r\n)?\s*NOT(?:\s+ON\s+FILE)?'
        r'|CONSULTANTS?\s*[:-]?\s*(?:\n|\r|\r\n|\s)*NOT\s+ON\s+FILE'
        r'|\bONCOLOGY\s+FOLLOW(?:\s*UP)?\b'
        r'|\bFOLLOWS?\s+(?:UP\s+WITH|WITH)\s+[A-Z][A-Z\s]+\b'
        r'|\bCONSIDER\s+(?:A\s+)?CONSULTS?(?:ATION)?\b'
        r'|\b(MIGHT|MAY)\s+NEED\s+[A-Z\s]*(CONSULTS?|CONSULTATION)\b'
        r'|\bMEDICINE\s+WAS\s+CONSULTED\b'
        r'|\b(FOLLOW(?:\s*[\n\r]\s*|\s*[-\s]*)UP|FLUP)\s+[A-Z\s]*(CULTURES?|CONSULTS?|CONSULTATION)\b'
        r'|\b(?:TELE\s+)?[A-Z\s]*CONSULT(?:S|ATION)?\s+(?:ORDER\s+PLACED|ORDERED|REQUEST(?:ED|ING)?)\b'
        r'|\bREFER\s+(?:TO\s+)?THE?\s*DISCHARGE\s+SUMMARY\b'
        r'|\b[A-Z][A-Z\s]+CONSULT\S*\s+WILL\s+(?:BE\s+)?GREATLY\s+APPRECIATE(?:D)?\b'
        r'|\b(?:GENERAL\s+)?SURGER(Y|ICAL)\s+CONSULTS?(?:ATION)?\b'
        r'|\b(?:PENDING\s+[A-Z\s]*(CONSULTS?|CONSULTATION)|[A-Z\s]*(CONSULTS?|CONSULTATION)\s+(IS\s+)?PENDING)\b'
        r'|\bMANAGEMENT\s+CONSULT(?:ED|S?|ATION)?\b'
        r'|\bHOSPICE\s+CONSULT(?:ED|S?|ATION)?\b'
        r'|\bCONSULT(?:ED|S?|ATION)?\s+FOR\s+(?:FURTHER\s+)?(RECOMMENDATIONS?|MANAGEMENT|ADVICE|INPUT)\b'
        r'|\bAPPRECIATE\s+[A-Z\s]*CONSULTATION\b'
        r'|\b[A-Z\s]*EVALUATION\s+REQUESTED\b'
        r'|\bTHANKS?(?:\s*YOU)?(?:\s+VERY\s+MUCH)?\s+FOR\s+THE\s+CONSULTATION\b'
        r'|DISCUSSED\s+(?:PLAN|CASE|CARE|TREATMENT)?\s*(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY|RELATIVES?|HIS\s+WIFE|HER\s+HUSBAND|SPOUSE|SON|DAUGHTER|CHILD|CHILDREN|CAREGIVER)\b'
        r'|SPOKE\s+(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY|RELATIVES?|HIS\s+WIFE|HER\s+HUSBAND|SPOUSE|SON|DAUGHTER|CHILD|CHILDREN|CAREGIVER)\b'
        r'|TALKED\s+(?:TO|WITH)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY|RELATIVES?|HIS\s+WIFE|HER\s+HUSBAND|SPOUSE)\b'
        r'|CASE\s+DISCUSSED\s+(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY)\b'
        r'|FOLLOW\s+UP\s+(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?)\b'
        r'|\b[A-Z][A-Za-z\s]*\s+FOLLOWING\s+[A-Z][A-Za-z\s]*\b'
        r'|\bFOLLOWING\s+BY\s+[A-Z][A-Za-z\s]+\b'
        r'|\bFOLLOWED\s+BY\s+[A-Z][A-Za-z\s]+\b'
        r'|\bPER\s+[A-Z][A-Za-z\s]+\s+RECOMMENDATION\b'
        r'|\bAS\s+PER\s+[A-Z][A-Za-z\s]+\s+RECOMMENDATION\b'
        r'|\bACCORDING\s+TO\s+[A-Z][A-Za-z\s]+\s+RECOMMENDATION\b'
        r'|\bRECOMMENDATION\s+FROM\s+[A-Z][A-Za-z\s]+\b'
        r')',
        '',
        input_str
    )
    
    # Comprehensive medical departments/specialties with their variations
    medical_departments = {
        # Medical Specialties
        'CARDIOLOGY': ['CARDIOLOGY', 'CARDIAC', 'CARDIO', 'CV', 'CARDIOLOGIST'],
        'NEUROLOGY': ['NEUROLOGY', 'NEURO', 'NEUROLOGICAL', 'NEUROLOGIST'],
        'ONCOLOGY': ['ONCOLOGY', 'ONCO', 'CANCER', 'ONCOLOGIST', 'HEMATOLOGY/ONCOLOGY'],
        'PULMONOLOGY': ['PULMONOLOGY', 'PULMONARY', 'PULM', 'RESPIRATORY', 'CHEST', 'PULMONOLOGIST'],
        'GASTROENTEROLOGY': ['GASTROENTEROLOGY', 'GASTRO', 'GI', 'GASTROINTESTINAL', 'GASTROENTEROLOGIST'],
        'NEPHROLOGY': ['NEPHROLOGY', 'NEPHRO', 'RENAL', 'NEPHROLOGIST'],
        'INFECTIOUS_DISEASE': ['INFECTIOUS DISEASE', 'INFECTIOUS', 'ID', 'INFECTIOUS DISEASE SPECIALIST'],
        'UROLOGY': ['UROLOGY', 'URO', 'UROLOGICAL', 'UROLOGIST'],
        'HEMATOLOGY': ['HEMATOLOGY', 'HEME', 'BLOOD', 'HEMATOLOGIST'],
        'ENDOCRINOLOGY': ['ENDOCRINOLOGY', 'ENDO', 'ENDOCRINE', 'ENDOCRINOLOGIST'],
        'RHEUMATOLOGY': ['RHEUMATOLOGY', 'RHEUM', 'RHEUMATOLOGICAL', 'RHEUMATOLOGIST'],
        'DERMATOLOGY': ['DERMATOLOGY', 'DERM', 'DERMATOLOGIST'],
        'ORTHOPEDICS': ['ORTHOPEDICS', 'ORTHO', 'ORTHOPEDIC', 'ORTHOPEDIST'],
        
        # Surgical Specialties
        'SURGERY': ['SURGERY', 'SURGICAL', 'GENERAL SURGERY', 'SURGEON'],
        'NEUROSURGERY': ['NEUROSURGERY', 'NEUROSURGICAL', 'NEUROSURGEON'],
        'CARDIOTHORACIC_SURGERY': ['CARDIOTHORACIC', 'CT SURGERY', 'CARDIAC SURGERY', 'THORACIC SURGERY'],
        'PLASTIC_SURGERY': ['PLASTIC SURGERY', 'PLASTIC SURGICAL', 'PLASTIC SURGEON'],
        'VASCULAR_SURGERY': ['VASCULAR SURGERY', 'VASCULAR SURGICAL', 'VASCULAR SURGEON'],
        
        # Therapy Services
        'PHYSICAL_THERAPY': ['PHYSICAL THERAPY', 'PT', 'PHYSICAL THERAPIST'],
        'OCCUPATIONAL_THERAPY': ['OCCUPATIONAL THERAPY', 'OT', 'OCCUPATIONAL THERAPIST'],
        'SPEECH_THERAPY': ['SPEECH THERAPY', 'SPEECH', 'ST', 'SPEECH LANGUAGE PATHOLOGY', 'SLP', 'SPEECH PATHOLOGIST'],
        'RESPIRATORY_THERAPY': ['RESPIRATORY THERAPY', 'RT', 'RESPIRATORY THERAPIST'],
        
        # Mental Health
        'PSYCHIATRY': ['PSYCHIATRY', 'PSYCH', 'PSYCHIATRIC', 'PSYCHIATRIST'],
        'PSYCHOLOGY': ['PSYCHOLOGY', 'PSYCHOLOGIST'],
        'BEHAVIORAL_HEALTH': ['BEHAVIORAL HEALTH', 'BEHAVIORAL'],
        
        # Support Services
        'PALLIATIVE_CARE': ['PALLIATIVE CARE', 'PALLIATIVE', 'HOSPICE', 'PALLIATIVE MEDICINE'],
        'SOCIAL_WORK': ['SOCIAL WORK', 'SOCIAL WORKER', 'SOCIAL SERVICES'],
        'CASE_MANAGEMENT': ['CASE MANAGEMENT', 'CASE MANAGER', 'CM'],
        'DIETARY': ['DIETARY', 'NUTRITION', 'DIETICIAN', 'DIETITIAN', 'NUTRITIONIST'],
        'PHARMACY': ['PHARMACY', 'PHARMACIST', 'CLINICAL PHARMACY'],
        
        # Diagnostic Services
        'RADIOLOGY': ['RADIOLOGY', 'RADIOLOGICAL', 'RADIOLOGIST', 'IMAGING'],
        'PATHOLOGY': ['PATHOLOGY', 'PATHOLOGIST', 'PATH'],
        'ANESTHESIOLOGY': ['ANESTHESIOLOGY', 'ANESTHESIA', 'ANESTHESIOLOGIST'],
        
        # Emergency & Critical Care
        'EMERGENCY_MEDICINE': ['EMERGENCY MEDICINE', 'ER', 'ED', 'EMERGENCY ROOM', 'EMERGENCY DEPARTMENT'],
        'CRITICAL_CARE': ['CRITICAL CARE', 'ICU', 'INTENSIVE CARE', 'INTENSIVIST'],
        
        # Primary Care
        'INTERNAL_MEDICINE': ['INTERNAL MEDICINE', 'INTERNIST', 'IM'],
        'FAMILY_MEDICINE': ['FAMILY MEDICINE', 'FAMILY PRACTICE', 'FP', 'FAMILY PHYSICIAN'],
        'GERIATRICS': ['GERIATRICS', 'GERIATRIC', 'GERIATRICIAN'],
        
        # Other Specialties
        'OPHTHALMOLOGY': ['OPHTHALMOLOGY', 'OPHTHALMO', 'EYE', 'OPHTHALMOLOGIST'],
        'OTOLARYNGOLOGY': ['OTOLARYNGOLOGY', 'ENT', 'EAR NOSE THROAT', 'OTOLARYNGOLOGIST'],
        'PODIATRY': ['PODIATRY', 'PODIATRIST', 'FOOT', 'PODIATRIC'],
        'ALLERGY_IMMUNOLOGY': ['ALLERGY', 'IMMUNOLOGY', 'ALLERGY/IMMUNOLOGY', 'ALLERGIST'],
        'REHABILITATION': ['REHABILITATION', 'REHAB', 'PM&R', 'PHYSIATRY', 'PHYSIATRIST'],

        'GYNAECOLOGY': ['GYNAECOLOGY', 'GYN', 'GYNECOLOGY']
    }
    
    # Pattern 1: "consult/consulted" + department
    consult_patterns = [
        r'(?:CONSULT|CONSULTED|CONSULTATION)\s+(?:WITH\s+)?(?:THE\s+)?([A-Z][A-Za-z\s\/]+?(?=\s|\.|,|$|;))',
        r'([A-Z][A-Za-z\s\/]+)\s+(?:CONSULT|CONSULTED|CONSULTATION)',
        r'CONSULT\s+(?:FOR\s+)?([A-Z][A-Za-z\s\/]+)',
        r'CONSULT\s+(?:PT[/\s]?OT|OT[/\s]?PT|PT[/\s]OT[/\s]ST)',
        r'(PT[/\s]?OT|OT[/\s]?PT|PT[/\s]OT[/\s]ST)\s+CONSULT',
    ]
    
    # Pattern 2: "discuss/discussed" + department  
    discuss_patterns = [
        r'(?:DISCUSS|DISCUSSED|DISCUSSION)\s+(?:WITH\s+)?(?:THE\s+)?([A-Z][A-Za-z\s\/]+?(?=\s|\.|,|$|;))',
        r'([A-Z][A-Za-z\s\/]+)\s+(?:DISCUSS|DISCUSSED|DISCUSSION)',
        r'DISCUSSED\s+(?:CASE\s+)?WITH\s+([A-Z][A-Za-z\s\/]+)',
        r'SPOKE\s+WITH\s+([A-Z][A-Za-z\s\/]+)',
        r'TALKED\s+WITH\s+([A-Z][A-Za-z\s\/]+)',
    ]
    
    def find_medical_department(text):
        """Check if text contains any medical department"""
        text_upper = text.upper().strip()
        
        # Special handling for PT/OT combinations
        pt_ot_combinations = [
            'PT/OT', 'OT/PT', 'PT/OT/ST', 'PT OT', 'OT PT', 'PT OT ST',
            'PHYSICAL THERAPY/OCCUPATIONAL THERAPY', 'OCCUPATIONAL THERAPY/PHYSICAL THERAPY'
        ]
        
        for combo in pt_ot_combinations:
            if combo in text_upper:
                return "PT/OT"
        
        for main_dept, variations in medical_departments.items():
            for variation in variations:
                # Exact word matching to avoid partial matches
                if re.search(r'\b' + re.escape(variation) + r'\b', text_upper):
                    return main_dept.replace('_', ' ')
        return None
    
    # Search for consult patterns
    for pattern in consult_patterns:
        matches = re.finditer(pattern, input_str, re.IGNORECASE)
        for match in matches:
            if match.lastindex:  # If there's a captured group
                department_text = match.group(1).strip()
                department = find_medical_department(department_text)
                if department:
                    result = f"CONSULTED {department}"
                    if result not in results:
                        results.append(result)
            else:
                # For patterns without capture groups (like PT/OT specific patterns)
                department = find_medical_department(match.group(0))
                if department:
                    result = f"CONSULTED {department}"
                    if result not in results:
                        results.append(result)
    
    # Search for discuss patterns
    for pattern in discuss_patterns:
        matches = re.finditer(pattern, input_str, re.IGNORECASE)
        for match in matches:
            if match.lastindex:
                department_text = match.group(1).strip()
                department = find_medical_department(department_text)
                if department:
                    result = f"DISCUSSED WITH {department}"
                    if result not in results:
                        results.append(result)
    
    # Remove duplicates and return
    results = list(set(results))
    
    return [{"Discussed Management": results if results else ["No Evidence Found"]}]

def independent_interpretation_bcs(lab_str, assessment_str, hpi_str):
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)
    input_upper = input_str.upper()
    interpretation_keywords = [
        "INDEPENDENTLY INTERPRETED", "INDEPENDENT INTERPRETATION",
        "PERSONALLY REVIEWED AND INTERPRETED", "REVIEWED AND INTERPRETED BY ME",
        "INTERPRETED BY ME", "MY INTERPRETATION", "MY EKG INTERPRETATION",
        "I INTERPRETED THE EKG", "EKG INTERPRETED", "I INTERPRETED THE ECHO",
        "ECHO INTERPRETED", "MY ECHO INTERPRETATION", "I INTERPRETED THE XRAY",
        "I INTERPRETED THE CT", "I INTERPRETED THE MRI", "XRAY INTERPRETED",
        "CT INTERPRETED", "MRI INTERPRETED", "I INTERPRETED THE PFT",
        "PFT INTERPRETED", "I INTERPRETED THE HOLTER", "HOLTER INTERPRETED",
        "PACEMAKER INTERROGATION INTERPRETED",
        "MY EKG INTERPRETATION IS NSR",
        "MY CT INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
        "MY X-RAY INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
        "INTERPRETATION BY ME", "REVIEWED BY ME",
        "I PERSONALLY VIEWED AND INTERPRETED",
        "ECG: INTERPRETED BY ME", "ECG: EKG INTERPRETED BY ME",
        "ECG: LAST EKG INTERPRETED BY ED", "ECG: INTERPRETED BY",
        "REPEAT EKG INTERPRETED BY ME"
    ]
    interpretation_patterns = [
        r"I\s+(?:PERSONALLY\s+)?INTERPRETED\s+(?:THE\s+)?(EKG|ECHO|XRAY|X-RAY|CT|MRI|PFT|HOLTER|PACEMAKER)",
        r"MY\s+(EKG|ECHO|XRAY|CT|MRI|INTERPRETATION)",
        r"(EKG|ECHO|XRAY|CT|MRI|HOLTER|PACEMAKER|PFT)\s+INTERPRETED",
        r"INDEPENDENTLY\s+INTERPRETED",
        r"REVIEWED\s+AND\s+INTERPRETED\s+BY\s+ME",
        r"(?:^|\W)MY\s+(CT|X-?RAY|EKG)\s+INTERPRETATION(?::| IS)\s+.*"
    ]
    results = []
    for phrase in interpretation_keywords:
        if phrase in input_upper:
            results.append(phrase)
    for pattern in interpretation_patterns:
        matches = re.findall(pattern, input_str, flags=re.IGNORECASE)
        if matches:
            if isinstance(matches[0], tuple):
                matches = [" ".join(m).strip() for m in matches]
            results.extend(matches)
    cleaned = []
    seen = set()
    for r in results:
        r_clean = re.sub(r'[^A-Z ]+', '', r.upper()).strip()
        if not any(r_clean in existing or existing in r_clean for existing in seen):
            seen.add(r_clean)
            cleaned.append(r)
    return [{"Independent Interpretation": cleaned or ["No Evidence Found"]}]

def independent_historian_bcs(assessment_str, hpi_str, lab_str):
    input_str = " ".join(filter(None, [assessment_str, hpi_str, lab_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str).upper()
    non_medical_relations = ["PARENT","GUARDIAN","SPOUSE","HUSBAND","WIFE","SON","DAUGHTER","FAMILY",
                            "FAMILY MEMBER","RELATIVE","BROTHER","SISTER","UNCLE","AUNT",
                            "GRANDMOTHER","GRANDFATHER","FRIEND","NEIGHBOR","CAREGIVER",
                            "EMPLOYER","WITNESS","LEGAL GUARDIAN","SURROGATE DECISION-MAKER",
                            "SIGNIFICANT OTHER","PARTNER","BOYFRIEND","GIRLFRIEND"]
    medical_professionals = ["NURSE","PHYSICIAN","DOCTOR","DR","MD","DO","NP","PA",
                            "PHYSICIAN ASSISTANT","CLINICAL STAFF","EMS PERSONNEL","EMT",
                            "PARAMEDIC","CASE MANAGER","SOCIAL WORKER","THERAPIST",
                            "RESPIRATORY THERAPIST","PHARMACIST","DIETITIAN"]
    action_keywords = ["REPORTED","STATED","TOLD","MENTIONED","INFORMED","SAID",
                      "PROVIDED BY","GIVEN BY","OBTAINED FROM","HISTORY TAKEN FROM",
                      "HISTORY PROVIDED BY","OBSERVED BY","DOCUMENTED BY","COLLECTED FROM"]
    phrase_patterns = [
        r"(?i)\bINDEPENDENT HISTORIAN\b",
        r"(?i)\bHISTORY PROVIDED BY\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bHISTORY TAKEN FROM\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bOBTAINED FROM\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bINFORMATION GIVEN BY\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bVERIFIED BY\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bALL HISTORY (?:OBTAINED|PROVIDED) FROM\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bUNABLE TO PROVIDE HISTORY.*?(?:OBTAINED|FROM)\s+(?:{})\b".format("|".join(non_medical_relations)),
    ]
    exclusion_patterns = [
        r"(?i)\b(?:HISTORY|INFORMATION).*?(?:{})\b".format("|".join(medical_professionals)),
        r"(?i)\b(?:OBTAINED|PROVIDED).*?(?:{})\b".format("|".join(medical_professionals)),
    ]
    threshold = 90
    temp_chunks = []
    buffer = ""
    for part in input_str.split("\n"):
        if buffer and len(buffer.strip()) <= threshold:
            temp_chunks.append(buffer.strip())
            buffer = part
        else:
            if buffer:
                buffer += " " + part
            else:
                buffer = part
    if buffer.strip():
        temp_chunks.append(buffer.strip())
    sentences = []
    for chunk in temp_chunks:
        pieces = [s.strip() for s in re.split(r'[.;!]', chunk) if s.strip()]
        sentences.extend(pieces)
    results = []
    for i, sentence in enumerate(sentences):
        contains_medical = any(re.search(pattern, sentence) for pattern in exclusion_patterns)
        if contains_medical:
            continue
        found_clear_pattern = any(re.search(pattern, sentence) for pattern in phrase_patterns)
        if found_clear_pattern:
            for relation in non_medical_relations:
                if relation in sentence:
                    results.append(f"HISTORY FROM {relation}")
                    break
            else:
                results.append("INDEPENDENT HISTORIAN USED")
            continue
        words = sentence.split()
        found_relation = any(relation in words for relation in non_medical_relations)
        found_action = any(action in sentence for action in action_keywords)
        if found_relation and found_action:
            for relation in non_medical_relations:
                if relation in sentence:
                    results.append(f"HISTORY FROM {relation}")
                    break
    if results:
        unique_results = []
        seen = set()
        for result in results:
            if result not in seen:
                seen.add(result)
                unique_results.append(result)
        if len(unique_results) > 1:
            specific_results = [r for r in unique_results if any(rel in r for rel in non_medical_relations)]
            if specific_results:
                unique_results = [specific_results[0]]
        return [{"Independent Historian": unique_results[0]}]
    return [{"Independent Historian": "No Evidence Found"}]

def process_row_bcs(row, config):
    discussion = discussion_management_bcs(row["lab_str"], row["assessment_str"], row["DVT_Prophylaxis_str"])
    interpretation = independent_interpretation_bcs(row["lab_str"], row["assessment_str"], row["hpi_str"])
    prior_review = review_prior_external_notes_bcs(row["lab_str"], row["assessment_str"], row["hpi_str"])
    lab_orders = lab_order_bcs(row["assessment_str"])
    lab_review_result = lab_review_bcs(row["lab_str"], row["DOS"])
    historian = independent_historian_bcs(row["assessment_str"], row["hpi_str"], row["lab_str"])
    mdm2_level, label, reasons = Process_MDM2(discussion, interpretation, prior_review, lab_orders, lab_review_result, historian)
    prior_review_vals = flatten_list_of_dicts(prior_review, "Prior Review")
    lab_orders_simple = simplify_list_of_dicts(lab_orders, "Lab Order")
    lab_review_simple = simplify_list_of_dicts(lab_review_result, "Lab Review")
    discussion_vals = flatten_list_of_dicts(discussion, "Discussed Management")
    interpretation_vals = flatten_list_of_dicts(interpretation, "Independent Interpretation")
    historian_vals = flatten_list_of_dicts(historian, "Independent Historian")
    details_parts = []
    details_parts.append(f"Review Prior Notes> {prior_review_vals or ['No Evidence Found']}")
    details_parts.append(f"Lab Order> {lab_orders_simple or ['No Evidence Found']}")
    details_parts.append(f"Lab Review> {lab_review_simple or ['No Evidence Found']}")
    details_parts.append(f"Discussion Management/Test> {discussion_vals or ['No Evidence Found']}")
    details_parts.append(f"Independent Interpretation> {interpretation_vals or ['No Evidence Found']}")
    details_parts.append(f"Independent Historian> {historian_vals or ['No Evidence Found']}")
    details = "~".join(details_parts)
    chart = row["Filename"].replace("BCS_", "").replace(".TIF", "")
    sections = []
    def safe_text(value):
        return str(value).replace(";", ",").strip()
    if row.get("assessment_str"):
        sections.append(f"[Assessment]: {safe_text(row['assessment_str'])}")
    if row.get("hpi_str"):
        sections.append(f"[HPI]: {safe_text(row['hpi_str'])}")
    if row.get("lab_str"):
        sections.append(f"[Lab]: {safe_text(row['lab_str'])}")
    if row.get("DVT_Prophylaxis_str"):
        sections.append(f"[DVT Prophylaxis]: {safe_text(row['DVT_Prophylaxis_str'])}")
    if row.get("objective_str"):
        sections.append(f"[Objective]: {safe_text(row['objective_str'])}")
    combined_text = " ~ ".join(sections).replace("\n", " ").strip()
    return pd.Series({
        "Filename": row["Filename"],
        "Chart": row["Chart"],
        "DOS": row["DOS"],
        "Visit": row["Visit"],
        "Visit Time": row["Visit_time"],
        "MDM2_Level": label.upper(),
        "REASONS FOR MDM2": details,
        "REFERENCE TEXT MDM2": combined_text,
        "Page_No": row["Page_No"]
    })


