# CSCC (uses consult file, similar to AHFL)
# =============================================================================

def review_prior_external_notes_cscc(lab_str, assessment_str, hpi_str):
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str]))
    lab_text = input_str.upper().strip()
    keywords = [
        "PRIOR EXTERNAL NOTES", "EXTERNAL PROVIDER NOTES", "OUTSIDE RECORDS",
        "OUTSIDE NOTES", "REVIEWED PRIOR NOTES", "REVIEWED OUTSIDE NOTES",
        "REVIEWED PCP NOTES", "REVIEWED CONSULT NOTES", "REVIEWED SPECIALIST NOTES",
        "PREVIOUS RECORDS REVIEWED", "EXTERNAL RECORDS REVIEWED",
        "EXTERNAL DOCUMENTS REVIEWED", "ED REVIEWED", "I HAVE REVIEWED ALL, DOCUMENTATION BY THE RESIDENT AND, AGREE",
        "ED REVIEWED","I HAVE REVIEWED IMAGING", "I HAVE REVIEWED LABS",
        "I REVIEWED RELEVANT LABS, IMAGING AND PRIOR RECORDS", "REVIEWED AND AGREE WITH THE ABOVE FINDINGS", "REVIEWED BY NEUROLOGY", 
        "REVIEWED BY ME", "I REVIEWED RELEVANT LABS, MAGING AND PRIOR RECORDS AND UPDATED HOME MEDICATION RECONCILIATION"
    ]
    patterns = [
        r"REVIEW(?:ED|ING)?\s+(?:PRIOR|EXTERNAL|OUTSIDE)\s+(?:NOTES|RECORDS)",
        r"NOTES\s+FROM\s+(?:PCP|CARDIOLOGY|RADIOLOGY|ONCOLOGY|NEUROLOGY)",
        r"CONSULT\s+NOTES\s+REVIEW(?:ED|ING)?",
        r"OUTSIDE\s+HOSPITAL\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"PREVIOUS\s+VISIT\s+RECORDS\s+REVIEW(?:ED|ING)?"
    ]
    results = []
    for kw in keywords:
        if kw in lab_text:
            results.append({"Prior Review": kw})
    for pattern in patterns:
        match = re.search(pattern, lab_text)
        if match:
            results.append({"Prior Review": match.group(0)})
    return results if results else [{"Prior Review": "No Evidence Found"}]

def lab_with_value_present(lab_name, text):
    pattern = rf'''
        \b{re.escape(lab_name)}\b
        \s*
        (?:\:|=)?
        \s*
        (?:OF|IS|WAS|FOUND\s+TO\s+BE)?
        \s*
        -?\d+(\.\d+)?
        \s*
        (?:[A-Z/%]+)?
    '''
    return re.search(pattern, text, re.VERBOSE) is not None

def lab_order_cscc(assessment_str):
    lab_df = LAB_DF
    group_test_df = PANEL_DF
    input_str = (assessment_str or "").upper()
    results = []
    matched_labs = set()

    CONTEXT_EXCLUSIONS = {
        'URINE': [r'STRAINING\s+URINE', r'URINE\s+OUTPUT', r'URINARY\s+TRACT\s+INFECTION', r'BLOOD\s+IN\s+URINE'],
        'BLOOD': [r'BLOOD\s+PRESSURE', r'BLOOD\s+IN\s+URINE', r'COUGHING\s+BLOOD'],
        'POTASSIUM': [r'ORAL\s+POTASSIUM', r'POTASSIUM\s+SUPPLEMENT', r'POTASSIUM\s+REPLETION'],
        'SODIUM': [r'CURRENTLY\s+SODIUM\s+IMPROVED', r'ORAL\s+SODIUM', r'SODIUM\s+SUPPLEMENT', r'\b\d+(\.\d+)?\s*MG\b', r'SODIUM\s+CHLORIDE'],
        'CREATININE': [r'STABLE\s+CREATININE', r'BASELINE\s+CREATININE', r'CREATININE\s+CLEARANCE'],
        'URINE CULTURE': [r'PENDING\s+URINE\s+CULTURE', r'URINE\s+CULTURE'],
        'MG': [r'\b\d+(\.\d+)?\s*MG\b'],
        'HEMOGLOBIN': [r'HEMOGLOBIN\s+OF\s+\d+(\.\d+)?', r'DROP\s+IN\s+HEMOGLOBIN'],
        'HEMATOCRIT': [r'HEMATOCRIT\s+OF\s+\d+(\.\d+)?', r'DROP\s+IN\s+HEMATOCRIT'],
        'VENOUS': [r'DEEP\s+VENOUS\s+THROMBOSIS', r'VENOUS\s+ULTRASOUND'],
        'CT': [r'CT\s+SCAN',  r'SUSPECTED\s+ON\s+THE\s+CT\s+SCAN'],
        'PH': [r'PH\s+OF\s+\d+(\.\d+)?'],
        'PCO2': [r'PCO2\s+OF\s+\d+(\.\d+)?'],
        'PO2': [r'PO2\s+OF\s+\d+(\.\d+)?'],
        'PLATELET': [r'REPLACE\s+PLATELETS', r'UNIT\s+OF\s+PLATELETS'],
        'PROTEIN': [r'PROTEIN[-\s]*CALORIE\s+MALNUTRITION', r'PROTEIN\s+DEFICIENT'],
        'CHLORIDE': [r'SODIUM\s+CHLORIDE'],
        'HIDA': [r'HIDA\s+SCAN'],
        'ULTRASOUND': [r'ULTRASOUND\s+REVIEWED', r'ULTRASOUND\s+OF\s+THE\s+ABDOMEN'], 
    }

    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        if re.search(r'\b' + re.escape(lab_name) + r'\b', input_str):
            if lab_with_value_present(lab_name, input_str):
                continue
            excluded = False
            if lab_name in CONTEXT_EXCLUSIONS:
                for excl_pattern in CONTEXT_EXCLUSIONS[lab_name]:
                    if re.search(excl_pattern, input_str, re.IGNORECASE):
                        excluded = True
                        break
            if not excluded:
                matched_labs.add(lab_name)

    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]
        if panel_labs and all(re.search(r'\b' + re.escape(lab) + r'\b', input_str) for lab in panel_labs):
            results.append({"Lab Order": panel_name})
            matched_labs = matched_labs - set(panel_labs)

    for lab in matched_labs:
        results.append({"Lab Order": lab})

    if not results:
        return [{"Lab Order": "No Evidence Found"}]
    return results

def lab_review_cscc(lab_str, dos=None):
    lab_df = LAB_DF
    group_test_df = PANEL_DF
    if dos:
        filtered_lab_str = get_lab_content_by_dos(lab_str, dos)
    else:
        filtered_lab_str = lab_str

    input_str = (filtered_lab_str or "").upper()
    results = []
    matched_labs = set()

    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        if re.search(r'\b' + re.escape(lab_name) + r'\b', input_str):
            matched_labs.add(lab_name)

    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]
        if panel_labs and all(re.search(r'\b' + re.escape(lab) + r'\b', input_str) for lab in panel_labs):
            results.append({"Lab Review": panel_name})
            matched_labs = matched_labs - set(panel_labs)

    for lab in matched_labs:
        results.append({"Lab Review": lab})

    equivalence_map = {
        "CMP": "COMPREHENSIVE METABOLIC PANEL",
        "BMP": "BASIC METABOLIC PANEL",
        "CBC": "COMPLETE BLOOD COUNT",
        "LFT": "LIVER FUNCTION TESTS",
        "RFT": "RENAL FUNCTION TESTS",
        "HEPATIC FUNCTION PANEL": "LIVER FUNCTION TESTS"
    }
    normalized = []
    seen = set()
    for entry in results:
        test = entry["Lab Review"].upper().strip()
        normalized_name = equivalence_map.get(test, test)
        if normalized_name not in seen:
            seen.add(normalized_name)
            normalized.append({"Lab Review": normalized_name})

    if not normalized:
        return [{"Lab Review": "No Evidence Found"}]
    return normalized

# ----------------------------------------------------------------------
# Discussion Management
# ----------------------------------------------------------------------
EXCLUDED_SPECIALTY_PATTERNS1 = [
    r'\bHOSPITALIST\b', r'\bHOSP\b', r'\bCASE\s*MANAGEMENT\b', r'\bCASE\s*MGMT\b',
    r'\bCARE\s*MANAGEMENT\b', r'\bCARE\s*MGMT\b', r'\bPHARMACIST\b', r'\bPHARM\b',
    r'\bRX\b', r'\bNURSING\b', r'\bNURSE\b', r'\bRN\b'
]
CREDENTIALS = {'MD', 'DO', 'NP', 'PA', 'RN', 'MD,', 'DO,', 'NP,', 'PA,', 'RN,'}

def clean_consult_text(text):
    if not isinstance(text, str):
        return ''
    text = re.sub(r'\btol\b', 'to', text, flags=re.IGNORECASE)
    text = re.sub(r'\bCasel\b', 'Case', text, flags=re.IGNORECASE)
    text = re.sub(r'\s+', ' ', text).strip()
    return text

def extract_specialty(consult_text):
    consult_text = clean_consult_text(consult_text)
    pattern = re.compile(
        r'consult\s+to[l]?\s*[\']?\s*(.*?)(?=\s+(?:Completed|Active|Discontinued|Compeletd)\b|$)',
        re.IGNORECASE
    )
    match = pattern.search(consult_text)
    if not match:
        return None
    captured = match.group(1).strip()
    if not captured:
        return None
    words = captured.split()
    stop_idx = len(words)
    for i, w in enumerate(words):
        if ',' in w or w.upper() in CREDENTIALS:
            stop_idx = i
            break
    specialty = ' '.join(words[:stop_idx]).strip()
    specialty = re.sub(r'[,\'"]+$', '', specialty)
    return specialty.upper() if specialty else None

def discussion_management_cscc(filename=None, dos=None, config=None):
    if config is None:
        return [{"Discussed Management": ["No Evidence Found"]}]
    
    consult_file = config.get("consult_file", "Consult_Order_CSCC_NEW_ALL.xlsx") # CSCC_Consult
    
    consult_df = pd.read_excel(consult_file)
    if filename is None or dos is None:
        return [{"Discussed Management": ["No Evidence Found"]}]

    consult_df.columns = consult_df.columns.str.strip()
    required = ['Filename', 'DOS', 'Consult', 'Status']
    if any(col not in consult_df.columns for col in required):
        return [{"Discussed Management": ["No Evidence Found"]}]

    target_dos = normalize_date(dos)
    target_filename = str(filename).strip()
    # Prepare a temporary copy for this call
    temp = consult_df.copy()
    temp['Filename_clean'] = temp['Filename'].astype(str).str.strip().str.replace(r'^CSCC_', '', regex=False)
    temp['DOS_norm'] = temp['DOS'].apply(lambda x: normalize_date(str(x)))

    mask_filename = temp['Filename'].astype(str).str.strip() == target_filename
    if not mask_filename.any():
        target_clean = target_filename.replace("CSCC_", "")
        mask_filename = temp['Filename_clean'] == target_clean

    mask = mask_filename & (temp['DOS_norm'] == target_dos)
    matched = temp[mask]

    specialties = []
    for _, row in matched.iterrows():
        status_val = row.get('Status')
        status = '' if pd.isna(status_val) else str(status_val).strip().lower()
        if status not in ['', 'completed', 'active', 'compeletd']:
            continue

        consult = str(row.get('Consult', ''))
        consult_upper = consult.upper()
        if any(re.search(p, consult_upper) for p in EXCLUDED_SPECIALTY_PATTERNS1):
            continue

        spec = extract_specialty(consult)
        if spec:
            specialties.append(spec)

    specialties = sorted(set(specialties))
    if specialties:
        return [{"Discussed Management": specialties}]
    else:
        return [{"Discussed Management": ["No Evidence Found"]}]

# ----------------------------------------------------------------------
# Independent Interpretation
# ----------------------------------------------------------------------
def independent_interpretation_cscc(lab_str, assessment_str, hpi_str, phy_str):
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str, phy_str]))
    input_str = re.sub(r'\s+', ' ', input_str).strip()

    def score_interpretation(text):
        text_upper = text.upper()
        score = 0
        if re.search(r"I\s*PERSONALLY", text_upper):
            score += 2
        if re.search(r"INTERPRET", text_upper):
            score += 2
        modality_patterns = [
            r"X[- ]?R", r"CXR", r"\bCT\b", r"CT\s*SC", r"\bMRI\b", r"\bMR\b",
            r"ULTRA", r"\bUSG\b", r"\bECG\b", r"\bEKG\b", r"\bEC\b"
        ]
        if any(re.search(p, text_upper) for p in modality_patterns):
            score += 3
        if "NAN" in text_upper:
            score -= 1
        if "NEW IMAGING TEST" in text_upper:
            score -= 2
        if "VITALS AND NURSING NOTE" in text_upper:
            score -= 3
        if re.search(r"LAB|CLINICAL LAB|CULTURE|BLOOD|GLUCOSE", text_upper):
            if not any(re.search(p, text_upper) for p in modality_patterns):
                score -= 3
        return score

    base_pattern = r"I\s*PERSONALLY\s*(?:VIEWED|REVIEWED)?\s*AND\s*INTERPRETED"
    matches = []
    for m in re.finditer(base_pattern, input_str, flags=re.IGNORECASE):
        start = m.start()
        end = len(input_str)
        delim_match = re.search(r"[:.\n]", input_str[start:])
        if delim_match:
            end = start + delim_match.start()
        snippet = input_str[start:end].strip()
        if snippet:
            snippet = re.sub(r'\s+(?:nan|n|null)\s*$', '', snippet, flags=re.IGNORECASE)
            matches.append(snippet)

    pattern2 = r"\b(MRI|CT|X-?RAY|ECG|EKG)\s+RESULTS\s+REVIEWED\b"
    for m in re.finditer(pattern2, input_str, flags=re.IGNORECASE):
        matches.append(m.group(0).strip())

    scored_matches = [s for s in matches if score_interpretation(s) >= 3]
    scored_matches.sort(key=len, reverse=True)
    final_results = []
    for candidate in scored_matches:
        if not any(candidate in kept for kept in final_results):
            final_results.append(candidate)

    return [{"Independent Interpretation": final_results if final_results else ["No Evidence Found"]}]


def independent_historian_cscc(assessment_str, hospital_course_str, subjective_str, hpi_str):
    input_str = " ".join(filter(None, [assessment_str, hospital_course_str, subjective_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str).upper()

    relation_keywords = ["PARENT", "GUARDIAN", "SPOUSE", "HUSBAND", "WIFE", "SON", "DAUGHTER",
                         "FAMILY MEMBER", "RELATIVE", "BROTHER", "SISTER", "UNCLE", "AUNT",
                         "GRANDMOTHER", "GRANDFATHER", "FRIEND", "NEIGHBOR", "CAREGIVER",
                         "CASE MANAGER", "NURSE", "PHYSICIAN ASSISTANT", "CLINICAL STAFF",
                         "EMS PERSONNEL", "EMT", "PARAMEDIC", "EMPLOYER", "WITNESS", "LEGAL GUARDIAN",
                         "SURROGATE DECISION-MAKER"]
    action_keywords = ["REPORTED", "STATED", "TOLD", "MENTIONED", "INFORMED", "SAID",
                       "PROVIDED BY", "GIVEN BY", "OBTAINED FROM", "HISTORY TAKEN FROM",
                       "HISTORY PROVIDED BY", "OBSERVED BY", "DOCUMENTED BY", "COLLECTED FROM"]
    previous_next_relation = ["DISCUSSED", "TOLD", "THEM", "REPORTED", "STATED", "TOLD", "MENTIONED", "INFORMED", "SAID",
                              "PROVIDED BY", "GIVEN BY", "OBTAINED FROM", "HISTORY TAKEN FROM",
                              "HISTORY PROVIDED BY", "OBSERVED BY", "DOCUMENTED BY", "COLLECTED FROM", "MENTION"]
    phrase_patterns = [
        r"(?is)\bINDEPENDENT\s+HISTORIAN\s+NECESSARY\s*[:\-]?\s*(?:IS\s+)?([A-Z\s']{{1,100}})",
        r"(?i)\bINDEPENDENT\s+HISTORIAN\s*[:\-]?\s*(?:IS\s+)?(?:{})?\b(?:\s+[A-Z][A-Za-z']{{1,25}}){{0,3}}\b".format("|".join(relation_keywords)),
        r"(?i)\bHISTORY PROVIDED BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bHISTORY TAKEN FROM\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bOBTAINED FROM\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bINFORMATION GIVEN BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bVERIFIED BY\s+(?:{})\b".format("|".join(relation_keywords))
    ]
    exclusion_patterns = [
        r"(?i)\bINDEPENDENT HISTORIAN\s*(?:NECESSARY|REQUIRED)?[:\s\-]*\b(?:NONE|NIL|NO|NOT REQUIRED|NOT INDICATED|NOT APPLICABLE|NA)\b",
        r"(?i)\bNO\s+INDEPENDENT\s+HISTORIAN\b",
        r"(?i)\bINDEPENDENT\s+HISTORIAN[:\s\-]+NOT\s+(?:REQUIRED|NEEDED|INDICATED)\b"
    ]

    threshold = 90
    temp_chunks = []
    buffer = ""
    for part in input_str.split("\n"):
        if buffer and len(buffer.strip()) <= threshold:
            temp_chunks.append(buffer.strip())
            buffer = part
        else:
            buffer = f"{buffer} {part}" if buffer else part
    if buffer.strip():
        temp_chunks.append(buffer.strip())

    sentences = []
    for chunk in temp_chunks:
        pieces = [s.strip() for s in re.split(r'[.;!]', chunk) if s.strip()]
        sentences.extend(pieces)

    results = []
    for i, sentence in enumerate(sentences):
        if any(re.search(pat, sentence) for pat in exclusion_patterns):
            continue
        words = sentence.split()
        found_relation = any(word in relation_keywords for word in words)
        found_action = any(word in sentence for word in action_keywords)
        found_phrase = any(re.search(pattern, sentence) for pattern in phrase_patterns)
        if (found_relation and found_action) or found_phrase:
            results.append(sentence.strip())
        if i > 0:
            prev = sentences[i-1].upper()
            curr = sentence.upper()
            matched_prev = [word for word in relation_keywords if word in prev]
            matched_curr = [word for word in previous_next_relation if word in curr]
            if matched_prev and matched_curr:
                results.append(" ".join(matched_prev) + " " + " ".join(matched_curr))

    if results:
        unique_results = ", ".join(results)
        return [{"Independent Historian": unique_results}]
    else:
        return [{"Independent Historian": "No Evidence Found"}]


def process_row_cscc(row, config):
    """
    Process a single row for facility CSCC.
    Expects the following helper functions to be defined:
        review_prior_external_notes_cscc(lab_str, assessment_str, hpi_str)
        independent_interpretation_cscc(lab_str, assessment_str, hpi_str, phy_str)
        discussion_management_cscc(filename=None, dos=None)   # uses consult file
        lab_order_cscc(assessment_str)
        lab_review_cscc(lab_str, dos=None)
        independent_historian_cscc(assessment_str, hospital_course_str, subjective_str, hpi_str)
    """
    # --- Run helper functions ---
    discussion = discussion_management_cscc(
        filename=row["Filename"], dos=row["DOS"], config=config)
    interpretation = independent_interpretation_cscc(
        row["lab_str"], row["assessment_str"], row["hpi_str"], row["phy_str"])
    prior_review = review_prior_external_notes_cscc(
        row["lab_str"], row["assessment_str"], row["hpi_str"])
    lab_orders = lab_order_cscc(row["assessment_str"])
    lab_review_result = lab_review_cscc(row["lab_str"], row["DOS"])
    historian = independent_historian_cscc(
        row["assessment_str"], row["hospital_course_str"],
        row["subjective_str"], row["hpi_str"])

    # --- Run MDM2 logic (uses utils.Process_MDM2) ---
    from utils import Process_MDM2, flatten_list_of_dicts, simplify_list_of_dicts
    mdm2_level, label, reasons = Process_MDM2(
        discussion, interpretation, prior_review,
        lab_orders, lab_review_result, historian
    )

    # --- Flatten results for the REASONS column ---
    prior_review_vals = flatten_list_of_dicts(prior_review, "Prior Review")
    lab_orders_simple = simplify_list_of_dicts(lab_orders, "Lab Order")
    lab_review_simple = simplify_list_of_dicts(lab_review_result, "Lab Review")
    discussion_vals = flatten_list_of_dicts(discussion, "Discussed Management")
    interpretation_vals = flatten_list_of_dicts(interpretation, "Independent Interpretation")
    historian_vals = flatten_list_of_dicts(historian, "Independent Historian")

    details_parts = [
        f"Review Prior Notes> {prior_review_vals or ['No Evidence Found']}",
        f"Lab Order> {lab_orders_simple or ['No Evidence Found']}",
        f"Lab Review> {lab_review_simple or ['No Evidence Found']}",
        f"Discussion Management/Test> {discussion_vals or ['No Evidence Found']}",
        f"Independent Interpretation> {interpretation_vals or ['No Evidence Found']}",
        f"Independent Historian> {historian_vals or ['No Evidence Found']}"
    ]
    details = "~".join(details_parts)

    # --- Build reference text (selected sections) ---
    def safe_text(value):
        return str(value).replace(";", ",").strip()

    sections = []
    if row.get("assessment_str"):
        sections.append(f"[Assessment]: {safe_text(row['assessment_str'])}")
    if row.get("hpi_str"):
        sections.append(f"[HPI]: {safe_text(row['hpi_str'])}")
    if row.get("lab_str"):
        sections.append(f"[Lab]: {safe_text(row['lab_str'])}")
    if row.get("phy_str"):
        sections.append(f"[Physical]: {safe_text(row['phy_str'])}")
    if row.get("hospital_course_str"):
        sections.append(f"[Hospital Course]: {safe_text(row['hospital_course_str'])}")
    if row.get("subjective_str"):
        sections.append(f"[Subjective]: {safe_text(row['subjective_str'])}")
    if row.get("objective_str"):
        sections.append(f"[Objective]: {safe_text(row['objective_str'])}")
    if row.get("drug_management_str"):
        sections.append(f"[Drug Management]: {safe_text(row['drug_management_str'])}")
    combined_text = " ~ ".join(sections).replace("\n", " ").strip()

    # --- Extract Chart ID (remove prefix and extension) ---
    chart = row["Filename"].replace("CSCC_", "").replace(".TIF", "")

    # --- Return Series with expected column names ---
    return pd.Series({
        "Filename": row["Filename"],
        "Chart": chart,
        "DOS": row["DOS"],
        "Visit": row["Visit"],
        "Visit Time": row["Visit_time"],
        "MDM2_Level": label.upper(),
        "REASONS FOR MDM2": details,
        "REFERENCE TEXT MDM2": combined_text,
        "Page_No": row["Page_No"]
    })

# =============================================================================
# CSM (uses consult file, similar to AHFL)
# =============================================================================

def review_prior_external_notes_csm(lab_str, assessment_str, hpi_str):
    # --- Step 1: Combine inputs safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str]))
    lab_text = input_str.upper().strip()

    # --- Step 2: Keywords indicating external notes review ---
    keywords = [
        "PRIOR EXTERNAL NOTES", "EXTERNAL PROVIDER NOTES", "OUTSIDE RECORDS",
        "OUTSIDE NOTES", "REVIEWED PRIOR NOTES", "REVIEWED OUTSIDE NOTES",
        "REVIEWED PCP NOTES", "REVIEWED CONSULT NOTES", "REVIEWED SPECIALIST NOTES",
        "PREVIOUS RECORDS REVIEWED", "EXTERNAL RECORDS REVIEWED", 
        "EXTERNAL DOCUMENTS REVIEWED", "ED REVIEWED", "I HAVE REVIEWED IMAGING",
        "ECG REVIEWED BY",
        "I REVIEWED RELEVANT LABS, IMAGING AND PRIOR RECORDS",
        "REVIEWED AND AGREE WITH THE ABOVE FINDINGS",
        "REVIEWED BY NEUROLOGY", "REVIEWED BY ME",
        "ECG: REVIEWED", "CG: REVIEWED",
        "LABS AND THE IMAGES REVIEWED AND CONSIDERED IN THE EVALUATION OF PATIENT", 
        "LABS AND IMAGES REVIEWED AND CONSIDERED IN THE EVALUATION OF PATIENT",
        "I REVIEWED RELEVANT LABS, MAGING AND PRIOR RECORDS AND UPDATED HOME MEDICATION RECONCILIATION",
        "G: REVIEWED",
        "CHEST CT REVIEWED"
    ]

    # --- Step 3: Regex patterns for flexible matching ---
    patterns = [
        r"REVIEW(?:ED|ING)?\s+(?:PRIOR|EXTERNAL|OUTSIDE)\s+(?:NOTES|RECORDS)",
        r"NOTES\s+FROM\s+(?:PCP|CARDIOLOGY|RADIOLOGY|ONCOLOGY|NEUROLOGY)",
        r"CONSULT\s+NOTES\s+REVIEW(?:ED|ING)?",
        r"OUTSIDE\s+HOSPITAL\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"PREVIOUS\s+VISIT\s+RECORDS\s+REVIEW(?:ED|ING)?"
    ]

    results = []

    # --- Step 4: Exact keyword search ---
    for kw in keywords:
        if kw in lab_text:
            results.append({"Prior Review": kw})

    # --- Step 5: Regex search ---
    for pattern in patterns:
        match = re.search(pattern, lab_text)
        if match:
            results.append({"Prior Review": match.group(0)})

    # --- Step 5.1: OCR normalization + deduplication (ONLY ADDITION) ---
    seen = set()
    normalized_results = []

    for item in results:
        value = item["Prior Review"]

        if value in ["G: REVIEWED", "CG: REVIEWED"]:
            value = "ECG: REVIEWED"

        if value not in seen:
            seen.add(value)
            normalized_results.append({"Prior Review": value})


    # --- Step 6: Return results ---
    return normalized_results if normalized_results else [{"Prior Review": "No Evidence Found"}]


def independent_interpretation_csm(
    lab_str,
    assessment_str,
    hpi_str,
    objective_str,
    current_medication_infusions_str
):
    # ---------------------------------------------------------
    # STEP 1: Combine text
    # ---------------------------------------------------------
    input_str = " ".join(filter(None, [
        lab_str, assessment_str, hpi_str, objective_str, current_medication_infusions_str
    ]))
    input_str = re.sub(r'\s+', ' ', input_str).strip()

    # ---------------------------------------------------------
    # STEP 2: Scoring function
    # ---------------------------------------------------------
    def score_interpretation(text):
        text_upper = text.upper()
        score = 0

        if re.search(r"I\s*PERSONALLY", text_upper):
            score += 2
        if re.search(r"INTERPRET", text_upper):
            score += 2

        # Modality patterns (added MR)
        modality_patterns = [
            r"X[- ]?R", r"CXR", r"\bCT\b", r"CT\s*SC", r"\bMRI\b", r"\bMR\b",  # MR added
            r"ULTRA", r"\bUSG\b", r"\bECG\b", r"\bEKG\b", r"\bEC\b"
        ]
        if any(re.search(p, text_upper) for p in modality_patterns):
            score += 3

        if "NAN" in text_upper:
            score -= 1
        if "NEW IMAGING TEST" in text_upper:
            score -= 2
        if "VITALS AND NURSING NOTE" in text_upper:
            score -= 3

        if re.search(r"LAB|CLINICAL LAB|CULTURE|BLOOD|GLUCOSE", text_upper):
            if not any(re.search(p, text_upper) for p in modality_patterns):
                score -= 3

        return score

    # ---------------------------------------------------------
    # STEP 3: Extraction
    # ---------------------------------------------------------
    # 3.1 Find full statements up to the first colon/period/newline
    base_pattern = r"I\s*PERSONALLY\s*(?:VIEWED|REVIEWED)?\s*AND\s*INTERPRETED"
    matches = []
    for m in re.finditer(base_pattern, input_str, flags=re.IGNORECASE):
        start = m.start()
        # Find the end: first colon, period, or newline after the start
        end = len(input_str)
        delim_match = re.search(r"[:.\n]", input_str[start:])
        if delim_match:
            end = start + delim_match.start()
        snippet = input_str[start:end].strip()
        if snippet:
            # Clean up trailing noise like "nan", "n", "null"
            snippet = re.sub(r'\s+(?:nan|n|null)\s*$', '', snippet, flags=re.IGNORECASE)
            matches.append(snippet)

    # 3.2 Short fragments: modality + "results reviewed"
    pattern2 = r"\b(MRI|CT|X-?RAY|ECG|EKG)\s+RESULTS\s+REVIEWED\b"
    for m in re.finditer(pattern2, input_str, flags=re.IGNORECASE):
        matches.append(m.group(0).strip())

    # ---------------------------------------------------------
    # STEP 4: Score and deduplicate
    # ---------------------------------------------------------
    scored_matches = [s for s in matches if score_interpretation(s) >= 3]
    scored_matches.sort(key=len, reverse=True)

    final_results = []
    for candidate in scored_matches:
        if not any(candidate in kept for kept in final_results):
            final_results.append(candidate)

    return [{
        "Independent Interpretation": final_results if final_results else ["No Evidence Found"]
    }]

#----------------------------------------------------------------------------------------------
# Helper function to check if lab name is followed by a numeric value (indicating it's not just mentioned)
#----------------------------------------------------------------------------------------------
def lab_with_value_present(lab_name, text):
    """
    Returns True if lab_name appears followed by numeric value
    with optional connector words and optional units.
    """

    pattern = rf'''
        \b{re.escape(lab_name)}\b
        \s*
        (?:\:|=)?                      # optional : or =
        \s*
        (?:OF|IS|WAS|FOUND\s+TO\s+BE)?  # optional words
        \s*
        -?\d+(\.\d+)?                  # number
        \s*
        (?:[A-Z/%]+)?                  # optional unit (MG/DL, MMHG, %, etc.)
    '''

    return re.search(pattern, text, re.VERBOSE) is not None


def lab_order_csm(assessment_str):

    lab_df = LAB_DF
    group_test_df = PANEL_DF
    # --- Step 2: Normalize input text ---
    input_str = (assessment_str or "").upper()

    results = []
    matched_labs = set()

    # Step 3
    CONTEXT_EXCLUSIONS = {
        'URINE': [r'STRAINING\s+URINE', r'URINE\s+OUTPUT', r'URINARY\s+TRACT\s+INFECTION', r'BLOOD\s+IN\s+URINE'],
        'BLOOD': [r'BLOOD\s+PRESSURE', r'BLOOD\s+IN\s+URINE', r'COUGHING\s+BLOOD'],
        'POTASSIUM': [r'ORAL\s+POTASSIUM', r'POTASSIUM\s+SUPPLEMENT', r'POTASSIUM\s+REPLETION'],
        'SODIUM': [r'CURRENTLY\s+SODIUM\s+IMPROVED', r'ORAL\s+SODIUM', r'SODIUM\s+SUPPLEMENT', r'\b\d+(\.\d+)?\s*MG\b', r'SODIUM\s+CHLORIDE'],
        'CREATININE': [r'STABLE\s+CREATININE', r'BASELINE\s+CREATININE', r'CREATININE\s+CLEARANCE'],
        'URINE CULTURE': [r'PENDING\s+URINE\s+CULTURE', r'URINE\s+CULTURE'],
        'MG': [r'\b\d+(\.\d+)?\s*MG\b'],
        'HEMOGLOBIN': [r'HEMOGLOBIN\s+OF\s+\d+(\.\d+)?', r'DROP\s+IN\s+HEMOGLOBIN'],
        'HEMATOCRIT': [r'HEMATOCRIT\s+OF\s+\d+(\.\d+)?', r'DROP\s+IN\s+HEMATOCRIT'],
        'VENOUS': [r'DEEP\s+VENOUS\s+THROMBOSIS', r'VENOUS\s+ULTRASOUND'],
        'CT': [r'CT\s+SCAN',  r'SUSPECTED\s+ON\s+THE\s+CT\s+SCAN'],
        'PH': [r'PH\s+OF\s+\d+(\.\d+)?'],
        'PCO2': [r'PCO2\s+OF\s+\d+(\.\d+)?'],
        'PO2': [r'PO2\s+OF\s+\d+(\.\d+)?'],
        'PLATELET': [r'REPLACE\s+PLATELETS', r'UNIT\s+OF\s+PLATELETS'],
        'PROTEIN': [r'PROTEIN[-\s]*CALORIE\s+MALNUTRITION', r'PROTEIN\s+DEFICIENT'],
        'CHLORIDE': [r'SODIUM\s+CHLORIDE'],
        'HIDA': [r'HIDA\s+SCAN'],
        'ULTRASOUND': [r'ULTRASOUND\s+REVIEWED', r'ULTRASOUND\s+OF\s+THE\s+ABDOMEN'], 
        # Add more as needed
    }

    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        if re.search(r'\b' + re.escape(lab_name) + r'\b', input_str):

            # 🚫 NEW: Skip if lab appears with numeric value
            if lab_with_value_present(lab_name, input_str):
                continue

            # Check if it matches any exclusion pattern
            excluded = False
            if lab_name in CONTEXT_EXCLUSIONS:
                for excl_pattern in CONTEXT_EXCLUSIONS[lab_name]:
                    if re.search(excl_pattern, input_str, re.IGNORECASE):
                        excluded = True
                        break
            
            if not excluded:
                matched_labs.add(lab_name)

    # --- Step 4: Check panels (only if ALL labs are present) ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]

        if panel_labs and all(re.search(r'\b' + re.escape(lab) + r'\b', input_str) for lab in panel_labs):
            results.append({"Lab Order": panel_name})
            # Remove labs that are part of this full panel
            matched_labs = matched_labs - set(panel_labs)

    # --- Step 5: Add remaining unmatched individual labs ---
    for lab in matched_labs:
        results.append({"Lab Order": lab})

    # --- Step 6: If nothing found ---
    if not results:
        return [{"Lab Order": "No Evidence Found"}]
    
    #print(f"Debug: lab_order results: {results}")
    return results

def lab_review_csm(lab_str, dos=None):
    """Modified to filter by DOS and handle multiple formats"""

    lab_df = LAB_DF
    group_test_df = PANEL_DF
    # --- Step 2: Filter lab content by DOS if provided ---
    if dos:
        filtered_lab_str = get_lab_content_by_dos(lab_str, dos)
    else:
        filtered_lab_str = lab_str

    # --- Step 3: Normalize input text ---
    input_str = (filtered_lab_str or "").upper()

    # --- Step 3a: Remove the exclusion sentence from matching consideration ---
    # Pattern to match "No results found for: "INR", "PROTIME" or similar variations
    exclusion_pattern = r'NO RESULTS FOUND FOR:?\s*["\']?INR["\']?(?:\s*,\s*["\']?PROTIME["\']?)?'
    input_str = re.sub(exclusion_pattern, '', input_str)

    results = []
    matched_labs = set()

    # --- Step 4: Check individual labs ---
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        # Use word boundaries to avoid partial matches
        if re.search(r'\b' + re.escape(lab_name) + r'\b', input_str):
            matched_labs.add(lab_name)

    # --- Step 5: Check panels (only if ALL labs are present) ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]

        if panel_labs and all(re.search(r'\b' + re.escape(lab) + r'\b', input_str) for lab in panel_labs):
            results.append({"Lab Review": panel_name})
            # Remove labs that are part of this full panel
            matched_labs = matched_labs - set(panel_labs)

    # --- Step 6: Add remaining unmatched individual labs ---
    for lab in matched_labs:
        results.append({"Lab Review": lab})

    # --- Step 7: Deduplicate equivalent tests ---
    equivalence_map = {
        "CMP": "COMPREHENSIVE METABOLIC PANEL",
        "BMP": "BASIC METABOLIC PANEL",
        "CBC": "COMPLETE BLOOD COUNT",
        "LFT": "LIVER FUNCTION TESTS",
        "RFT": "RENAL FUNCTION TESTS",
        "HEPATIC FUNCTION PANEL": "LIVER FUNCTION TESTS"
    }

    # Normalize results to avoid duplicates
    normalized = []
    seen = set()

    for entry in results:
        test = entry["Lab Review"].upper().strip()
        # Convert equivalent short forms to full name
        normalized_name = equivalence_map.get(test, test)

        # Avoid adding duplicates
        if normalized_name not in seen:
            seen.add(normalized_name)
            normalized.append({"Lab Review": normalized_name})

    # --- Step 8: If nothing found ---
    if not normalized:
        return [{"Lab Review": "No Evidence Found"}]

    return normalized


