def discussion_management_csm(filename=None, dos=None, config=None):
    if config is None:
        return [{"Discussed Management": ["No Evidence Found"]}]
    
    consult_file = config.get("consult_file", "Consult_Order_CSM_NEW_ALL.xlsx")

    try:
        consult_df = pd.read_excel(consult_file)
        consult_df.columns = consult_df.columns.str.strip()
        # Normalize DOS to string (MM/DD/YYYY)
        consult_df['DOS'] = pd.to_datetime(consult_df['DOS']).dt.strftime('%m/%d/%Y')
        required_cols = ['Filename', 'DOS', 'Consult', 'Status']
        missing_cols = [col for col in required_cols if col not in consult_df.columns]
        if missing_cols:
            return [{"Discussed Management": ["No Evidence Found"]}]
    except Exception as e:
        print(f"Error reading consult file: {e}")
        return [{"Discussed Management": ["No Evidence Found"]}]

    if filename is None or dos is None:
        return [{"Discussed Management": ["No Evidence Found"]}]

    target_dos_normalized = normalize_date(str(dos))
    target_filename = str(filename).strip()

    # Match rows by Filename and DOS
    matched_rows = consult_df[consult_df['Filename'].astype(str).str.strip() == target_filename]
    matched_consults = []
    for _, row in matched_rows.iterrows():
        row_dos_norm = normalize_date(str(row['DOS']))
        if row_dos_norm == target_dos_normalized:
            matched_consults.append(row)

    # List of known medical specialties (used to clean captured text)
    MEDICAL_SPECIALTIES = [
        'CARE TRANSITIONS',
        'CARDIOLOGY',
        'CARDIOTHORACIC SURGERY',
        'CASE MANAGEMENT',
        'CHEST PAIN COORDINATOR',
        'DIETITIAN',
        'ELECTROPHYSIOLOGY',
        'GASTROENTEROLOGY',
        'GENERAL SURGERY',
        'GI',
        'HEMATOLOGY',
        'HOSPITALIST',
        'INFECTIOUS DISEASES',
        'INTENSIVIST',
        'NEPHROLOGY',
        'NEUROLOGY',
        'NEUROSURGERY',
        'NUTRITIONAL SERVICES',
        'OB/GYN',
        'ONCOLOGY',
        'ORTHOPEDIC',
        'ORTHOPEDIC SURGERY',
        'PALLIATIVE CARE',
        'PODIATRY',
        'PULMONOLOGY',
        'RADIATION ONCOLOGY',
        'SEPSIS COORDINATOR',
        'SOCIAL WORK',
        'SPIRITUAL CARE',
        'STROKE COORDINATOR',
        'UROLOGY',
        'VASCULAR ACCESS TEAM',
        'VASCULAR SURGERY',
        'WOUND CARE'
    ]
    # Normalize to uppercase for easy comparison
    MEDICAL_SPECIALTIES = [s.upper() for s in MEDICAL_SPECIALTIES]
    # Sort by length descending to match longest phrases first (e.g., "CRITICAL CARE" before "CARE")
    MEDICAL_SPECIALTIES.sort(key=len, reverse=True)

    specialties = []
    for row in matched_consults:
        # Treat blank/NaN Status as "active"
        status_raw = row.get('Status', '')
        if pd.isna(status_raw) or str(status_raw).strip() == '':
            status = 'active'
        else:
            status = str(status_raw).strip().lower()

        if status not in ['active', 'completed', 'compeletd']:
            continue

        consult_text = str(row.get('Consult', ''))
        # Remove leading date (e.g., "10/02/2024 ")
        consult_text = re.sub(r'^\d{1,2}/\d{1,2}/\d{4}\s+', '', consult_text)
        # Fix common typo "consultt"
        consult_text = re.sub(r'\bconsultt\b', 'consult', consult_text, flags=re.IGNORECASE)

        consult_text_upper = consult_text.upper()
        if any(re.search(p, consult_text_upper) for p in EXCLUDED_SPECIALTY_PATTERNS1):
            continue

        # Capture from "consult to" up to the first comma, status word, or end of string
        match = re.search(
            r'consult\s+to[\' ]?\s*(.*?)(?:,|\s+(?:Completed|Active|Completd|Discontinued)\b|$)',
            consult_text,
            re.IGNORECASE
        )
        if not match:
            continue

        captured = match.group(1).strip()
        # Remove common prefix words (Inpatient, ED, Pharmacy, Tele)
        captured = re.sub(r'^(?:Inpatient|ED|Pharmacy|Tele)\s+', '', captured, flags=re.IGNORECASE)

        # Find the best matching specialty from the list
        best_match = None
        captured_upper = captured.upper()
        for spec in MEDICAL_SPECIALTIES:
            # Check if the captured text starts with the specialty (whole word boundary)
            pattern = r'^' + re.escape(spec) + r'\b'
            if re.search(pattern, captured_upper):
                best_match = spec
                break

        if best_match:
            specialties.append(best_match)
        else:
            # Fallback: use the cleaned captured text as is (but remove provider name stopword)
            # e.g., if no specialty matched, try to take the first word if there are multiple
            words = captured.split()
            if len(words) > 1 and words[1][0].isupper():   # heuristic: second word looks like a name
                possible_spec = words[0].upper()
                if possible_spec in MEDICAL_SPECIALTIES:
                    specialties.append(possible_spec)
                else:
                    specialties.append(possible_spec)   # anyway
            else:
                specialty = re.sub(r'\s+', ' ', captured).upper()
                if specialty.strip():
                    specialties.append(specialty)

    # Deduplicate and sort
    specialties = sorted(list(set(specialties)))
    return [{"Discussed Management": specialties if specialties else ["No Evidence Found"]}]

def independent_historian_csm(assessment_str, hospital_course_str, subjective_str, hpi_str):
    # --- Step 1: Combine safely with spacing ---
    input_str = " ".join(filter(None, [assessment_str, hospital_course_str, subjective_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str).upper()

    # --- Step 3: Relation keywords ---
    relation_keywords = ["PARENT", "GUARDIAN", "SPOUSE", "HUSBAND", "WIFE", "SON", "DAUGHTER",
                            "FAMILY MEMBER", "RELATIVE", "BROTHER", "SISTER", "UNCLE", "AUNT",
                            "GRANDMOTHER", "GRANDFATHER", "FRIEND", "NEIGHBOR", "CAREGIVER",
                            "CASE MANAGER", "NURSE", "PHYSICIAN ASSISTANT", "CLINICAL STAFF",
                            "EMS PERSONNEL", "EMT", "PARAMEDIC", "EMPLOYER", "WITNESS", "LEGAL GUARDIAN",
                            "SURROGATE DECISION-MAKER"]

    # --- Step 3: Action keywords ---
    action_keywords = ["REPORTED", "STATED", "TOLD", "MENTIONED", "INFORMED", "SAID",
                        "PROVIDED BY", "GIVEN BY", "OBTAINED FROM", "HISTORY TAKEN FROM",
                        "HISTORY PROVIDED BY", "OBSERVED BY", "DOCUMENTED BY", "COLLECTED FROM"]
    previous_next_relation = ["DISCUSSED", "TOLD", "THEM", "REPORTED" "REPORTED", "STATED", "TOLD", "MENTIONED", "INFORMED", "SAID",
                        "PROVIDED BY", "GIVEN BY", "OBTAINED FROM", "HISTORY TAKEN FROM",
                        "HISTORY PROVIDED BY", "OBSERVED BY", "DOCUMENTED BY", "COLLECTED FROM", "MENTION"]

    # --- Step 4: Phrase patterns ---
    phrase_patterns = [
        r"(?i)\bINDEPENDENT HISTORIAN\b",
        r"(?i)\bHISTORY PROVIDED BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bHISTORY TAKEN FROM\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bOBTAINED FROM\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bINFORMATION GIVEN BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bVERIFIED BY\s+(?:{})\b".format("|".join(relation_keywords))
        ]

    # --- Step 6: Split into sentences ---
    # sentences = [s.strip() for s in re.split(r'[.;!]', input_str) if s.strip()]

    '''First split based on \n, but only break if the chunk before \n is short enough (like ≤ 90 chars).
    Then, for each chunk, further split it on . ; ! into sentences.'''

    threshold = 90  # max length to allow splitting at \n
    temp_chunks = []
    buffer = ""

    # --- Step 1: Smart split on \n ---
    for part in input_str.split("\n"):
        if buffer and len(buffer.strip()) <= threshold:
            # If last chunk is short → treat as sentence break
            temp_chunks.append(buffer.strip())
            buffer = part
        else:
            # Otherwise merge with previous text
            if buffer:
                buffer += " " + part
            else:
                buffer = part
    # Add final buffer
    if buffer.strip():
        temp_chunks.append(buffer.strip())

    # --- Step 2: Further split on punctuation (. ; !) ---
    sentences = []
    for chunk in temp_chunks:
        pieces = [s.strip() for s in re.split(r'[.;!]', chunk) if s.strip()]
        sentences.extend(pieces)

    results = []

    # --- Step 7: Check each sentence ---
    for i, sentence in enumerate(sentences):
        words = sentence.split()

        found_relation = any(word in relation_keywords for word in words)
        found_action = any(word in sentence for word in action_keywords)
        found_phrase = any(re.search(pattern, sentence) for pattern in phrase_patterns)

        if (found_relation and found_action) or found_phrase:
            results.append(sentence.strip())
        if i > 0:  # check against previous
            prev = sentences[i-1].upper()
            curr = sentence.upper()

            ## All the keywords that matched are strored as list 
            matched_prev = [word for word in relation_keywords if word in prev]
            matched_curr = [word for word in previous_next_relation if word in curr]

            if matched_prev and matched_curr:
                results.append(" ".join(matched_prev) + " " + " ".join(matched_curr))
                # results.append(sentence)

    # --- Step 8: Return results ---
    if results:
        # Unique + preserve order
        
        unique_results = ", ".join([x for x in results])
        return [{"Independent Historian": unique_results}]
    else:
        return [{"Independent Historian": "No Evidence Found"}]

def process_row_csm(row, config):
    """
    Process a single row for facility CSM.
    Expects the following helper functions to be defined:
        review_prior_external_notes_csm(lab_str, assessment_str, hpi_str)
        independent_interpretation_csm(lab_str, assessment_str, hpi_str, objective_str, current_medication_infusions_str)
        discussion_management_csm(filename, dos)   # uses consult file
        lab_order_csm(assessment_str)
        lab_review_csm(lab_str, dos=None)
        independent_historian_csm(assessment_str, hospital_course_str, subjective_str, hpi_str)
    """
    # --- Run helper functions ---
    discussion = discussion_management_csm(filename=row["Filename"], dos=row["DOS"], config=config)
    interpretation = independent_interpretation_csm(
        row["lab_str"], row["assessment_str"], row["hpi_str"],
        row["objective_str"], row["current_medication_infusions_str"])
    prior_review = review_prior_external_notes_csm(
        row["lab_str"], row["assessment_str"], row["hpi_str"])
    lab_orders = lab_order_csm(row["assessment_str"])
    lab_review_result = lab_review_csm(row["lab_str"])   # original code didn't use DOS, but we keep signature flexible
    historian = independent_historian_csm(
        row["assessment_str"], row["hospital_course_str"],
        row["subjective_str"], row["hpi_str"])

    # --- Run MDM2 logic (uses utils.Process_MDM2) ---
    from utils import Process_MDM2, flatten_list_of_dicts, simplify_list_of_dicts
    mdm2_level, label, reasons = Process_MDM2(
        discussion, interpretation, prior_review,
        lab_orders, lab_review_result, historian
    )

    # --- Flatten results for the REASONS column ---
    prior_review_vals = flatten_list_of_dicts(prior_review, "Prior Review")
    lab_orders_simple = simplify_list_of_dicts(lab_orders, "Lab Order")
    lab_review_simple = simplify_list_of_dicts(lab_review_result, "Lab Review")
    discussion_vals = flatten_list_of_dicts(discussion, "Discussed Management")
    interpretation_vals = flatten_list_of_dicts(interpretation, "Independent Interpretation")
    historian_vals = flatten_list_of_dicts(historian, "Independent Historian")

    details_parts = [
        f"Review Prior Notes> {prior_review_vals or ['No Evidence Found']}",
        f"Lab Order> {lab_orders_simple or ['No Evidence Found']}",
        f"Lab Review> {lab_review_simple or ['No Evidence Found']}",
        f"Discussion Management/Test> {discussion_vals or ['No Evidence Found']}",
        f"Independent Interpretation> {interpretation_vals or ['No Evidence Found']}",
        f"Independent Historian> {historian_vals or ['No Evidence Found']}"
    ]
    details = "~".join(details_parts)

    # --- Build reference text (selected sections) ---
    def safe_text(value):
        return str(value).replace(";", ",").strip()

    sections = []
    if row.get("assessment_str"):
        sections.append(f"[Assessment]: {safe_text(row['assessment_str'])}")
    if row.get("hpi_str"):
        sections.append(f"[HPI]: {safe_text(row['hpi_str'])}")
    if row.get("lab_str"):
        sections.append(f"[Lab]: {safe_text(row['lab_str'])}")
    if row.get("hospital_course_str"):
        sections.append(f"[Hospital Course]: {safe_text(row['hospital_course_str'])}")
    if row.get("subjective_str"):
        sections.append(f"[Subjective]: {safe_text(row['subjective_str'])}")
    if row.get("objective_str"):
        sections.append(f"[Objective]: {safe_text(row['objective_str'])}")
    if row.get("current_medication_infusions_str"):
        sections.append(f"[Current Medication Infusions]: {safe_text(row['current_medication_infusions_str'])}")
    if row.get("signed_str"):
        sections.append(f"[Signed]: {safe_text(row['signed_str'])}")
    combined_text = " ~ ".join(sections).replace("\n", " ").strip()

    # --- Extract Chart ID (remove prefix and extension) ---
    chart = row["Filename"].replace("CSM_", "").replace(".TIF", "")

    # --- Return Series with expected column names ---
    # Note: CSM uses "Visit_time" and "Page_No" in config
    return pd.Series({
        "Filename": row["Filename"],
        "Chart": chart,
        "DOS": row["DOS"],
        "Visit": row["Visit"],
        "Visit Time": row["Visit_time"],
        "MDM2_Level": label.upper(),
        "REASONS FOR MDM2": details,
        "REFERENCE TEXT MDM2": combined_text,
        "Page_No": row["Page_No"]
    })


