def review_prior_external_notes_mce(lab_str, assessment_str, hpi_str):
    # --- Step 1: Combine inputs safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str]))
    lab_text = input_str.upper().strip()
    

    # --- Step 2: Keywords indicating external notes review ---
    keywords = [
        "PRIOR EXTERNAL NOTES", "EXTERNAL PROVIDER NOTES", "OUTSIDE RECORDS",
        "OUTSIDE NOTES", "REVIEWED PRIOR NOTES", "REVIEWED OUTSIDE NOTES",
        "REVIEWED PCP NOTES", "REVIEWED CONSULT NOTES", "REVIEWED SPECIALIST NOTES",
        "PREVIOUS RECORDS REVIEWED", "EXTERNAL RECORDS REVIEWED",
        "EXTERNAL DOCUMENTS REVIEWED", "ED REVIEWED", "RADIOLOGICAL IMAGING REVIEWED",
        "RADIOLOGICAL STUDIES REVIEWED", "RADIOLOGICAL STUDIES REVIEWED BY ME",
        "RADIOLOGICAL IMAGING REVIEWED BY ME AND I AGREE WITH RADIOLOGIST READING",
        "RADIOLOGICAL IMAGING REVIEWED BY ME", "ALL RADIOLOGICAL STUDIES HAVE BEEN REVIEWED BY ME",
        "ALL RADIOLOGICAL STUDIES HAVE BEEN REVIEWED BY ME AND I AGREE WITH THE SUMMARY OF THE RADIOLOGICAL INTERPRETATIONS LISTED BELOW", 
        "ALL RADIOLOGICAL STUDIES HAVE BEEN REVIEWED"
    ]
    

    # --- Step 3: Regex patterns for flexible matching ---
    patterns = [
        r"REVIEW(?:ED|ING)?\s+(?:PRIOR|EXTERNAL|OUTSIDE)\s+(?:NOTES|RECORDS)",
        r"NOTES\s+FROM\s+(?:PCP|CARDIOLOGY|RADIOLOGY|ONCOLOGY|NEUROLOGY)",
        r"CONSULT\s+NOTES\s+REVIEW(?:ED|ING)?",
        r"OUTSIDE\s+HOSPITAL\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"PREVIOUS\s+VISIT\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"RADIOLOGICAL\s+(?:IMAGING|STUDIES)\s+REVIEWED\s+BY\s+ME",
        r"ALL\s+RADIOLOGICAL\s+STUDIES\s+HAVE\s+BEEN\s+REVIEWED(?:\s+BY\s+ME)?",
        r"REVIEWED\s+BY\s+ME\s+AND\s+I\s+AGREE\s+WITH\s+RADIOLOG(?:IST|ICAL)\s+READING",
        r"I\s+AGREE\s+WITH\s+THE\s+SUMMARY\s+OF\s+THE\s+RADIOLOGICAL\s+INTERPRETATIONS(?:\s+LISTED\s+BELOW)?"
    ]

    results = []

    # --- Step 4: Exact keyword search ---
    for kw in keywords:
        if kw in lab_text:
            results.append({"Prior Review": kw})

    # --- Step 5: Regex search ---
    for pattern in patterns:
        match = re.search(pattern, lab_text)
        if match:
            results.append({"Prior Review": match.group(0)})

    # --- Step 6: Clean and return results ---
    if results:
        # extract the string part from dicts
        vals = [item["Prior Review"] for item in results]

        # deduplicate while preserving order
        # also keep longest version if multiple similar matches exist
        unique_vals = list(dict.fromkeys(vals))

        # choose the longest match (most complete phrase)
        best_match = max(unique_vals, key=len)

        return [{"Prior Review": best_match}]
    else:
        return [{"Prior Review": "No Evidence Found"}]

def lab_order_mce(assessment_str):
    # --- Step 1: Load databases ---
    lab_df = LAB_DF
    group_test_df = PANEL_DF

    # --- Step 2: Normalize input text ---
    input_str = (assessment_str or "").upper()
    # NORMALIZE HYPHENS TO SPACES AND FIX COMMON TYPOS
    input_str_normalized = re.sub(r'[-\s]+', ' ', input_str)
    # Fix common typos in medical terms
    input_str_normalized = re.sub(r'\bAXIALT\b', 'AXIAL', input_str_normalized)
    input_str_normalized = re.sub(r'\bCOMPUTERIZED\b', 'COMPUTED', input_str_normalized)
    input_str_normalized = re.sub(r'\bTOMOGRAPHY:\b', 'TOMOGRAPHY', input_str_normalized)
    
    results = []
    matched_labs = set()

    # --- Step 3: IMPROVED medication filtering ---
    # Only filter out lines that are PURELY about medications
    strong_medication_patterns = [
        r'^\s*\b(?:CONTINUE|HOLD|START)\b.*\b(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
        r'^\s*.*\b\d+\s*(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
    ]
    
    # Process line by line with GENTLE filtering
    lines = input_str_normalized.split('\n')
    filtered_lines = []
    
    for line in lines:
        line = line.strip()
        if not line:
            continue
        
        # Only exclude lines that are STRONGLY medication-only
        is_pure_medication = any(re.search(med_pat, line, re.IGNORECASE) for med_pat in strong_medication_patterns)
        
        if not is_pure_medication:
            filtered_lines.append(line)
    
    # Recombine filtered text
    filtered_text = ' '.join(filtered_lines)

    # --- Step 4: Enhanced individual lab matching with EXCLUSIONS ---
    # Exclude common medication terms from being detected as labs
    exclusion_terms = ['MG', 'MCG', 'TABLET', 'CAPSULE', 'TAB', 'PO', 'IV', 'BID', 'TID', 'QDAY']
    
    # NEW ADDITION — Exclude sodium/glucose mentions in context
    diet_context_patterns = [
        r'\bLOW\s+SODIUM\s+DIET\b',
        r'\bLOW\s*:\s*(?:SODIUM\s*/\s*DIABETIC|DIABETIC\s*/\s*SODIUM)\s+DIET\b',
        r'\bLOW\s*:\s*(?:SODIUM|DIABETIC)\s+DIET\b'
        r'\bRESTRICTED\s+SODIUM\s+DIET\b',
        r'\bSODIUM\s+RESTRICTION\b',
        r'\bSODIUM\s+INTAKE\b',
        r'\bREPLACE\s+POTASSIUM(?:\s+\w+){0,3}\b',
        r'\bSODIUM\s*/\s*DIABETIC\s+DIET\b',
        r'\bDIABETIC\s*/\s*SODIUM\s+DIET\b'
    ]
    glucose_monitor_patterns = [
        r'\bMONITOR\s+BLOOD\s+GLUCOSE\b',
        r'\bMONITOR\s+GLUCOSE\s+LEVELS?\b',
        r'\bCHECK\s+BLOOD\s+GLUCOSE\b',
        r'\bCHECK\s+GLUCOSE\s+LEVELS?\b',
        r'\bCHECK\s+BLOOD\s+GLUCOSE\s+(?:\d+\s*(?:TIMES\s*)?|\bTWICE\b|\bONCE\b|\bTHRICE\b)?\s*(?:DAILY|A\s*DAY)\b'
    ]

    sodium_diet_context = any(re.search(pat, filtered_text) for pat in diet_context_patterns)
    glucose_monitor_context = any(re.search(pat, filtered_text) for pat in glucose_monitor_patterns)
    
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_normalized = re.sub(r'[-\s]+', ' ', lab_name.upper())
        
        # Skip if this lab name is in our exclusion list
        if lab_name_normalized in exclusion_terms:
            continue

        # Skip sodium if in diet context
        if sodium_diet_context and lab_name_normalized == "SODIUM" or lab_name_normalized == "NA":
            continue
        
                          
        # Use word boundaries with normalized strings
        if re.search(r'\b' + re.escape(lab_name_normalized) + r'\b', filtered_text):
            matched_labs.add(lab_name)

    # --- Step 5: Enhanced pattern matching for common tests ---
    enhanced_order_patterns = [
        # Imaging studies - BROADER PATTERNS
        (r'\b(?:COMPUTED\s+)?(?:AXIAL\s+)?TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bCT\s+(?:SCAN)?\b', 'CT SCAN'),  # This will match "CT" and "CT SCAN"
        (r'\bCAT\s+SCAN\b', 'CT SCAN'),
        (r'\bAXIAL\s+TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bMRI\b', 'MRI'),
        (r'\bX-?RAY\b', 'X-RAY'),
        (r'\bULTRASOUND\b', 'ULTRASOUND'),
        (r'\bECHOCARDIOGRAM\b', 'ECHOCARDIOGRAM'),
        (r'\bEKG\b', 'EKG'),
        (r'\bECG\b', 'ECG'),
        
        # Culture types - include plural forms
        (r'\bBLOOD\s+CULTURES?\b', 'BLOOD CULTURE'),
        (r'\bURINE\s+CULTURES?\b', 'URINE CULTURE'),
        (r'\bSPUTUM\s+CULTURES?\b', 'SPUTUM CULTURE'),
        (r'\bWOUND\s+CULTURES?\b', 'WOUND CULTURE'),
        
        # Action-oriented patterns for cultures
        (r'\b(?:REPEAT|REPEATED)\s+BLOOD\s+CULTURES?\b', 'BLOOD CULTURE'),
        (r'\b(?:OBTAIN|GET|ORDER|SEND)\s+(?:BLOOD|URINE)\s+CULTURES?\b', 'CULTURE'),
        (r'\bCULTURES?\s+(?:DRAWN|OBTAINED|SENT)\b', 'CULTURE'),
        (r'\bCULTURES?\s+(?:NEGATIVE|POSITIVE)\b', 'CULTURE'),  
        
        # Action-oriented patterns for lab orders
        (r'\bOBTAIN\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bGET\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bORDER\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bNEED\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
    ]
    
    for pattern, test_name in enhanced_order_patterns:
        if re.search(pattern, filtered_text, re.IGNORECASE):
            matched_labs.add(test_name)

    # --- Step 6: DEDUPLICATION AND PRIORITIZATION ---
    # Remove generic terms when specific ones are found
    deduplication_rules = {
        'CT SCAN': ['CT', 'COMPUTED TOMOGRAPHY'],  # If CT SCAN found, remove CT and COMPUTED TOMOGRAPHY
        'COMPUTED TOMOGRAPHY': ['CT'],  # If COMPUTED TOMOGRAPHY found, remove CT
        'ECHOCARDIOGRAM': ['ECHO'],  # If ECHOCARDIOGRAM found, remove ECHO
    }
    
    # Apply deduplication rules
    for primary_term, terms_to_remove in deduplication_rules.items():
        if primary_term in matched_labs:
            for term in terms_to_remove:
                if term in matched_labs:
                    matched_labs.remove(term)
    
    # Remove "IMAGING STUDY" if specific imaging found
    specific_imaging_terms = ['MRI', 'CT SCAN', 'COMPUTED TOMOGRAPHY', 'X-RAY', 'ULTRASOUND', 'ECHOCARDIOGRAM', 'EKG', 'ECG']
    if any(term in matched_labs for term in specific_imaging_terms) and 'IMAGING STUDY' in matched_labs:
        matched_labs.remove('IMAGING STUDY')

    # --- Step 7: Check panels (only if ALL labs are present) ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]
        
        panel_labs_normalized = [re.sub(r'[-\s]+', ' ', lab.upper()) for lab in panel_labs]

        if panel_labs and all(re.search(r'\b' + re.escape(lab_norm) + r'\b', filtered_text) for lab_norm in panel_labs_normalized):
            results.append({"Lab Order": panel_name})
            # Remove labs that are part of this full panel
            matched_labs = matched_labs - set(panel_labs)

    # --- Step 8: Add remaining unmatched individual labs ---
    for lab in matched_labs:
        results.append({"Lab Order": lab})

    # --- Step 9: FINAL DEDUPLICATION of results ---
    unique_results = []
    seen_labs = set()
    
    for result in results:
        lab_name = result["Lab Order"]
        if lab_name not in seen_labs:
            seen_labs.add(lab_name)
            unique_results.append(result)

    # --- Step 10: If nothing found ---
    if not unique_results:
        return [{"Lab Order": "No Evidence Found"}]

    return unique_results

# Helper function to abbreviate lab names
def abbreviate_lab_name(lab_name):
    """Convert full lab names to standardized abbreviations"""
    abbreviation_map = {
        # Common panels
        'COMPLETE BLOOD COUNT': 'CBC',
        'COMPREHENSIVE METABOLIC PANEL': 'CMP',
        'BASIC METABOLIC PANEL': 'BMP',
        'LIVER FUNCTION TESTS': 'LFT',
        'RENAL FUNCTION TESTS': 'RFT',
        'BLOOD UREA NITROGEN': 'BUN',
        
        # Individual tests
        'HEMOGLOBIN': 'HGB',
        'HEMATOCRIT': 'HCT',
        'WHITE BLOOD CELL COUNT': 'WBC',
        'RED BLOOD CELL COUNT': 'RBC', 
        'PLATELET COUNT': 'PLT',
        'SODIUM': 'NA',
        'POTASSIUM': 'K',
        'CHLORIDE': 'CL',
        'CALCIUM': 'CA',
        'MAGNESIUM': 'MG',
        'CREATININE': 'CREAT',
        'GLUCOSE': 'GLUC',
        'ALBUMIN': 'ALB',
        'TOTAL PROTEIN': 'TP',
        'ALKALINE PHOSPHATASE': 'ALP',
        'ASPARTATE AMINOTRANSFERASE': 'AST',
        'ALANINE AMINOTRANSFERASE': 'ALT',
        'LIPASE': 'LIPS',
        'AMYLASE': 'AMYL',
        'BILIRUBIN TOTAL': 'TBIL',
        'INTERNATIONAL NORMALIZED RATIO': 'INR',
        'PROTHROMBIN TIME': 'PT',
        'PARTIAL THROMBOPLASTIN TIME': 'PTT',
        
        # Imaging - keep as is or abbreviate further
        'X-RAY': 'XR',
        'CT SCAN': 'CT',
        'ULTRASOUND': 'US',
        'MRI': 'MRI',
        'ECHOCARDIOGRAM': 'ECHO',
        
        # Blood gas
        'PH': 'PH',
        'PCO2': 'PCO2',
        'PO2': 'PO2',
        'O2 SATURATION': 'O2SAT',
        
        # Keep unknown names as is
    }
    
    return abbreviation_map.get(lab_name.upper(), lab_name)

# Also add this helper function to process lists
def abbreviate_lab_list(lab_list):
    """Apply abbreviations to a list of lab names"""
    if isinstance(lab_list, list):
        return [abbreviate_lab_name(lab) for lab in lab_list]
    elif isinstance(lab_list, str):
        return abbreviate_lab_name(lab_list)
    else:
        return lab_list


def lab_review_mce(lab_str, dos=None):
    """Modified to handle both dated and non-dated lab content with generalized short name detection"""
    
    # --- Step 1: Load databases ---
    lab_df = LAB_DF
    group_test_df = PANEL_DF

    # --- Step 2: Check if lab content has dates ---
    def has_dates(text):
        """Check if text contains date patterns"""
        date_pattern = r'(\d{1,2}/\d{1,2}/\d{2,4}|[A-Za-z]{3}-\d{1,2}-\d{4})'
        return bool(re.search(date_pattern, text))
    
    # --- Step 3: Filter lab content based on date presence ---
    if dos and has_dates(lab_str):
        # If DOS is provided AND content has dates, filter by DOS
        filtered_lab_str = get_lab_content_by_dos(lab_str, dos)
        #print(f"DEBUG: Using DOS-filtered content (dates present)")
    else:
        # If no DOS OR no dates in content, use entire lab content
        filtered_lab_str = lab_str
        #print(f"DEBUG: Using full lab content (no dates found)")
    
    # --- Step 4: Normalize input text ---
    input_str = (filtered_lab_str or "").upper()
    #print(f"DEBUG: Processing text: {input_str[:200]}...")

    results = []
    matched_labs = set()

    # --- Step 5: Define short lab names and their full forms ---
    short_lab_mapping = {
        'CA': 'CALCIUM',
        'K': 'POTASSIUM', 
        'NA': 'SODIUM',
        'MG': 'MAGNESIUM',
        'CL': 'CHLORIDE',
        'P': 'PHOSPHORUS',
        'FE': 'IRON',
        'HGB': 'HEMOGLOBIN',
        'HCT': 'HEMATOCRIT',
        'WBC': 'WHITE BLOOD CELL COUNT',
        'RBC': 'RED BLOOD CELL COUNT',
        'PLT': 'PLATELET COUNT',
        'PT': 'PROTHROMBIN TIME',
        'INR': 'INTERNATIONAL NORMALIZED RATIO',
        'BUN': 'BLOOD UREA NITROGEN',
        'CR': 'CREATININE',
        'AST': 'ASPARTATE AMINOTRANSFERASE',
        'ALT': 'ALANINE AMINOTRANSFERASE',
        'ALP': 'ALKALINE PHOSPHATASE',
        'TBIL': 'TOTAL BILIRUBIN',
        'ALB': 'ALBUMIN',
        'TP': 'TOTAL PROTEIN',
        'CREA': 'CREATININE'
        
    }

    # --- Step 6: Generalized lab value pattern detection ---
    def detect_lab_values(text):
        """Detect lab values using generalized patterns for all lab types"""
        detected_labs = set()
        
        # Pattern 1: Short name with separator and value (CA: 9.5, K=4.2, NA 140)
        pattern1 = r'\b([A-Z]{1,4})\s*[:=]\s*([<>]?[\d\.]+)'
        matches1 = re.finditer(pattern1, text, re.IGNORECASE)
        for match in matches1:
            short_name, value = match.groups()
            short_name = short_name.upper()
            if short_name in short_lab_mapping:
                detected_labs.add(short_lab_mapping[short_name])
                #print(f"DEBUG: Pattern1 - {short_name}: {value} -> {short_lab_mapping[short_name]}")
        
        # Pattern 2: Short name followed by value with space (CA 9.5, K 4.2)
        pattern2 = r'\b([A-Z]{1,4})\s+([<>]?[\d\.]+)'
        matches2 = re.finditer(pattern2, text, re.IGNORECASE)
        for match in matches2:
            short_name, value = match.groups()
            short_name = short_name.upper()
            # Additional validation: make sure it's not part of a date or other context
            if (short_name in short_lab_mapping and 
                not re.search(r'\d{1,2}[:=]\d{2}', match.group(0))):  # Exclude time patterns
                detected_labs.add(short_lab_mapping[short_name])
                #print(f"DEBUG: Pattern2 - {short_name} {value} -> {short_lab_mapping[short_name]}")
        
        # Pattern 3: Short name immediately followed by value (CA9.5, K4.2)
        pattern3 = r'\b([A-Z]{1,4})([<>]?[\d\.]+)'
        matches3 = re.finditer(pattern3, text, re.IGNORECASE)
        for match in matches3:
            short_name, value = match.groups()
            short_name = short_name.upper()
            if short_name in short_lab_mapping:
                detected_labs.add(short_lab_mapping[short_name])
                #print(f"DEBUG: Pattern3 - {short_name}{value} -> {short_lab_mapping[short_name]}")
        
        # Pattern 4: Full lab name with various separators
        full_lab_patterns = [
            (r'(CALCIUM)\s*[:=]\s*([<>]?[\d\.]+)', 'CALCIUM'),
            (r'(POTASSIUM)\s*[:=]\s*([<>]?[\d\.]+)', 'POTASSIUM'),
            (r'(SODIUM)\s*[:=]\s*([<>]?[\d\.]+)', 'SODIUM'),
            (r'(MAGNESIUM)\s*[:=]\s*([<>]?[\d\.]+)', 'MAGNESIUM'),
            (r'(CHLORIDE)\s*[:=]\s*([<>]?[\d\.]+)', 'CHLORIDE'),
            (r'(PHOSPHORUS)\s*[:=]\s*([<>]?[\d\.]+)', 'PHOSPHORUS'),
            (r'(IRON)\s*[:=]\s*([<>]?[\d\.]+)', 'IRON'),
        ]
        
        for pattern, lab_name in full_lab_patterns:
            matches = re.finditer(pattern, text, re.IGNORECASE)
            for match in matches:
                detected_labs.add(lab_name)
                #print(f"DEBUG: Pattern4 - {lab_name}: {match.groups()[1]}")
        
        # Pattern 5: Value then parameter (value of CA is 9.5, parameter Calcium 8.7)
        pattern5 = r'(?:VALUE|LEVEL|RESULT)\s+(?:OF|FOR)\s+([A-Z]{1,4})\s+(?:IS|WAS)\s+([<>]?[\d\.]+)'
        matches5 = re.finditer(pattern5, text, re.IGNORECASE)
        for match in matches5:
            short_name, value = match.groups()
            short_name = short_name.upper()
            if short_name in short_lab_mapping:
                detected_labs.add(short_lab_mapping[short_name])
                #print(f"DEBUG: Pattern5 - value of {short_name} is {value} -> {short_lab_mapping[short_name]}")
        
        # Pattern 6: Parameter then value (Calcium value is 9.5, Potassium level 4.2)
        pattern6 = r'([A-Z][A-Za-z]+)\s+(?:VALUE|LEVEL|RESULT)\s+(?:IS|WAS)?\s*[:=]?\s*([<>]?[\d\.]+)'
        matches6 = re.finditer(pattern6, text, re.IGNORECASE)
        for match in matches6:
            full_name, value = match.groups()
            full_name_upper = full_name.upper()
            # Check if this matches any full lab name in our mapping
            for short, full in short_lab_mapping.items():
                if full in full_name_upper:
                    detected_labs.add(full)
                    #print(f"DEBUG: Pattern6 - {full_name} value {value} -> {full}")
                    break
        
        return detected_labs

    # --- Step 7: Apply generalized lab value detection ---
    detected_short_labs = detect_lab_values(input_str)
    matched_labs.update(detected_short_labs)

    # --- Step 8: Enhanced individual lab matching for longer names ---
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_clean = lab_name.upper().strip()
        
        # Skip if already detected as short lab
        if lab_name_clean in [v.upper() for v in short_lab_mapping.values()]:
            continue
            
        # For longer lab names, use standard matching
        if len(lab_name_clean) > 3:
            if (lab_name_clean in input_str or 
                re.search(r'\b' + re.escape(lab_name_clean) + r'\b', input_str, re.IGNORECASE)):
                #print(f"DEBUG: Matched lab: {lab_name_clean}")
                matched_labs.add(lab_name)

    # --- Step 9: Enhanced common lab pattern matching for other tests ---
    #print("DEBUG: Trying enhanced pattern matching...")
    
    # Common lab patterns that might not be in the formal database
    enhanced_patterns = [
        # POC tests
        (r'(POCGLU\s*[:=]?\s*[\d\.]+)', 'GLUCOSE'),
        (r'(GLUCOSE\s*[:=]?\s*[\d\.]+)', 'GLUCOSE'),
        (r'(BLOOD\s+GLUCOSE\s*[:=]?\s*[\d\.]+)', 'BLOOD GLUCOSE'),
        
        # Medication levels
        (r'(VANCOMYCIN\s+(?:TROUGH|LEVEL)\s*[:=]?\s*[\d\.]+)', 'VANCOMYCIN LEVEL'),
        (r'(GENTAMICIN\s+(?:TROUGH|LEVEL|PEAK)\s*[:=]?\s*[\d\.]+)', 'GENTAMICIN LEVEL'),
        (r'(TOBRAMYCIN\s+(?:TROUGH|LEVEL|PEAK)\s*[:=]?\s*[\d\.]+)', 'TOBRAMYCIN LEVEL'),
        (r'(DIGOXIN\s+LEVEL\s*[:=]?\s*[\d\.]+)', 'DIGOXIN LEVEL'),
        
        # Culture types
        (r'(AEROBIC\s+CULTURE)', 'AEROBIC CULTURE'),
        (r'(ANAEROBIC\s+CULTURE)', 'ANAEROBIC CULTURE'),
        (r'(BLOOD\s+CULTURE)', 'BLOOD CULTURE'),
        (r'(URINE\s+CULTURE)', 'URINE CULTURE'),
        (r'(CULTURE\s+POSITIVE\s+FOR)', 'CULTURE'),
        
        # Blood gas and related
        (r'(PH\s*[:=]?\s*[\d\.]+)', 'PH'),
        (r'(PCO2\s*[:=]?\s*[\d\.]+)', 'PCO2'),
        (r'(PO2\s*[:=]?\s*[\d\.]+)', 'PO2'),
        (r'(O2\s+SAT\w*\s*[:=]?\s*[\d\.]+)', 'O2 SATURATION'),
            
    ]
    
    for pattern, lab_type in enhanced_patterns:
        if re.search(pattern, input_str, re.IGNORECASE):
            #print(f"DEBUG: Found via enhanced pattern: {lab_type}")
            matched_labs.add(lab_type)

    # --- Step 9.5: Imaging study detection ---
    #print("DEBUG: Checking for imaging studies...")
    
    imaging_patterns = [
        # Imaging studies (no value required)
        (r'\b(CT\s+SCAN|CT|CAT\s+SCAN)\b', 'CT SCAN'),
        (r'\b(X-?RAY|X\s+RAY)\b', 'X-RAY'), 
        (r'\b(MRI\s+SCAN|MRI)\b', 'MRI'),
        (r'\b(ULTRASOUND|US)\b', 'ULTRASOUND'),
        (r'\b(?:ECHOCARDIOGRAM|ECHO)\b', 'ECHOCARDIOGRAM'),
        (r'\b(MAMMOGRAM)\b', 'MAMMOGRAM'),
        (r'\b(DOPPLER)\b', 'DOPPLER'),
        (r'\b(FLUOROSCOPY)\b', 'FLUOROSCOPY'),
        (r'\b(ANGIOGRAM)\b', 'ANGIOGRAM'),
    ]
    
    for pattern, imaging_type in imaging_patterns:
        if re.search(pattern, input_str, re.IGNORECASE):
            #print(f"DEBUG: Found imaging study: {imaging_type}")
            matched_labs.add(imaging_type)

    # --- Step 10: Check panels (only if ALL labs are present) ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]

        if panel_labs and all(re.search(r'\b' + re.escape(lab) + r'\b', input_str, re.IGNORECASE) for lab in panel_labs):
            results.append({"Lab Review": panel_name})
            # Remove labs that are part of this full panel
            matched_labs = matched_labs - set(panel_labs)

    # --- Step 11: Add remaining unmatched individual labs ---
    for lab in matched_labs:
        results.append({"Lab Review": lab})

    # --- Step 12: Deduplicate equivalent tests ---
    equivalence_map = {
        "CMP": "COMPREHENSIVE METABOLIC PANEL",
        "BMP": "BASIC METABOLIC PANEL", 
        "CBC": "COMPLETE BLOOD COUNT",
        "LFT": "LIVER FUNCTION TESTS",
        "RFT": "RENAL FUNCTION TESTS",
        "HEPATIC FUNCTION PANEL": "LIVER FUNCTION TESTS",
        "VANCOMYCIN TROUGH": "VANCOMYCIN LEVEL",
        "PT": "PROTHROMBIN TIME",
        "POCGLU": "GLUCOSE",
        "POC GLUCOSE": "GLUCOSE"
    }

    # Add short lab mappings to equivalence map
    equivalence_map.update(short_lab_mapping)

    # Normalize results to avoid duplicates
    normalized = []
    seen = set()

    for entry in results:
        test = entry["Lab Review"].upper().strip()
        # Convert equivalent short forms to full name
        normalized_name = equivalence_map.get(test, test)

        # Avoid adding duplicates
        if normalized_name not in seen:
            seen.add(normalized_name)
            normalized.append({"Lab Review": normalized_name})

    # --- Step 13: Final context validation for false positives ---
    final_results = []
    false_positive_contexts = [
        r'POINT\s+OF\s+CARE',
        r'\bCARE\b',
        r'MEDICAL\s+CARE',
        r'HEALTH\s+CARE',
        r'PATIENT\s+CARE',
        r'TAKE\s+CARE',
    ]
    
    has_false_context = any(re.search(pattern, input_str, re.IGNORECASE) for pattern in false_positive_contexts)
    
    for entry in normalized:
        lab_name = entry["Lab Review"].upper()
        
        # Special handling for short names in false positive contexts
        if has_false_context and len(lab_name) <= 3:
            # Check if we have actual value patterns for this lab
            value_patterns = [
                rf'\b{lab_name}\s*[:=]\s*[\d\.]',
                rf'\b{lab_name}\s+[\d\.]',
                rf'{lab_name}\s*[\d\.]',
            ]
            if not any(re.search(pattern, input_str, re.IGNORECASE) for pattern in value_patterns):
                #print(f"DEBUG: Filtering {lab_name} - appears to be false positive")
                continue
        
        final_results.append(entry)

    # --- Step 14: If nothing found ---
    if not final_results:
        #print("DEBUG: No labs detected in content")
        return [{"Lab Review": "No Evidence Found"}]

    #print(f"DEBUG: Final lab review results: {[r['Lab Review'] for r in final_results]}")
    return final_results

def discussion_management_mce(assessment_str, lab_str, consultation_str):
    """
    Extracts consultation/discussion information from consultation_str (discharge to)
    and fallback to assessment/lab text.
    """
    medical_specialties = [
            'CARDIOLOGY', 'NEPHROLOGY', 'NEUROLOGY', 'UROLOGY', 'PULMONOLOGY',
            'CRITICAL CARE', 'INTENSIVE CARE', 'ORTHOPEDIC', 'ORTHOPEDICS',
            'VASCULAR SURGERY', 'VASCULARS SURGERY', 'GENERAL SURGERY', 'CARDIAC SURGERY',
            'CARDIOVASCULAR SURGERY', 'PODIATRY', 'PHYSICAL THERAPY', 'OCCUPATIONAL THERAPY',
            'CASE MANAGEMENT', 'PULMONARY', 'TELE NEUROLOGY', 'GI', 'GASTROENTEROLOGY',
            'ONCOLOGY', 'HEMATOLOGY', 'NEUROSURGERY', 'PT/OT',
        ]
    
    final_results = []

    # --- Step 1: Process consultation_str (if present and not empty) ---
    # print(f"\n[DEBUG] consultation_str = '{consultation_str}'")
    if consultation_str and str(consultation_str).strip() and str(consultation_str).upper() != 'NAN':
        raw_consultation_terms = [str(consultation_str)]
        clean_consultation_terms = []
        seen_terms = set()

        for term in raw_consultation_terms:
            cleaned_term = term.strip().upper()
            if not cleaned_term:
                continue

            if re.search(r'\b\d+of\d+\b', cleaned_term) or 'PAGE' in cleaned_term:
                continue
            if any(noise in cleaned_term for noise in ['HOSPITALIST', 'DISCHARGE SUMMARY', 'WESTERN ARIZONA', 'REGIONAL MEDICAL', 'ONECONTENT']):
                continue
            if re.search(r'\bDR\.?\s+[A-Z]', cleaned_term) or re.search(r'[A-Z]+\s+PHY\b', cleaned_term):
                continue

            cleaned_term = re.sub(r'["\']', '', cleaned_term)

            noisy_patterns = [
                r'PATIENT IN THE PROCESS OF TRANSFERRING.*',
                r'EMERGENCY ROOM.*',
                r'SEE .*',
                r'GENERATED BY.*',
                r'GENERATED ON.*',
                r'ATTENDING.*',
                r'ADMITTED.*',
                r'ENCOUNTER.*',
                r'NAME.*',
            ]
            for pattern in noisy_patterns:
                cleaned_term = re.sub(pattern, '', cleaned_term).strip()

            if len(cleaned_term) < 3 or cleaned_term in ['NONE', '2OF3', '3OF4']:
                continue

            found_specialties = []
            for specialty in medical_specialties:
                if specialty in cleaned_term:
                    found_specialties.append(specialty)
            specialties = found_specialties if len(found_specialties) > 1 else [cleaned_term]

            for specialty in specialties:
                specialty = specialty.strip()
                if specialty and specialty not in seen_terms:
                    clean_consultation_terms.append(specialty)
                    seen_terms.add(specialty)

        for consult_term in clean_consultation_terms:
            final_results.append(consult_term.title() + " Consulted")
        # print(f"[DEBUG] consultation_str branch results: {final_results}")

    # --- Step 2: Fallback to parsing assessment_str and lab_str if consultation_str gave nothing ---
    if not final_results:
        input_str = " ".join(filter(None, [assessment_str, lab_str]))
        input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)
        # print(f"[DEBUG] Fallback input_str (first 500 chars): {input_str[:500]}")

        # REMOVED the huge exclusion regex block – only keep future consultation patterns
        future_consultation_patterns = [
            r'WARRANTS\s+.*\s+CONSULTATION',
            r'NEEDS?\s+.*\s+CONSULT',
            r'RECOMMEND\s+.*\s+CONSULT',
            r'CONSIDER\s+.*\s+CONSULT',
            r'PLAN\s+FOR\s+.*\s+CONSULT',
            r'FUTURE\s+.*\s+CONSULT',
            r'OUTPATIENT\s+.*\s+CONSULT',
            r'AS\s+AN\s+OUTPATIENT',
            r'IN\s+THE\s+FUTURE',
            r'TO\s+BE\s+CONSULTED',
        ]
        for pattern in future_consultation_patterns:
            input_str = re.sub(pattern, '', input_str, flags=re.IGNORECASE)

        input_upper = input_str.upper()

        discard_phrases = [
        'to history', 'refer to history', 'please refer to history',
        'history physical exam', 'refer to physical exam', 'to daily',
        'warrants', 'needs', 'recommend', 'consider', 'future', 'outpatient', "GI ppx",
        "GI prophylaxis", "PT/OT AND PAIN MANAGEMENT PRN", "GI: SOFT, BOWEL SOUNDS PRESENT",
        "SHE WORKED WITH! PHYSICAL THERAPY", "PT UTI", "PT\n UTI",
        "Encourage participation with PT and I/S usage", "Encourage participation with PT,I/S usage",
        "General surgery", "GI NP", "PT and I/S usage", "general surgery's",
        "Patient will need to follow up with Orthopedic surgery", "Orthopedic surgery",
        "Tele neurology evaluated", "Will consult PT", "neurosurgical evaluation",
        "evaluated by Orthopedic surgery"
    ]

        discussed_keywords = [
            "DISCUSSED CASE WITH", "DISCUSSED WITH DR", "DISCUSSED WITH DOCTOR",
            "D/W DR.", "DISCUSSED WITH CARDIOLOGY", "CONSULTED WITH", "CASE DISCUSSED WITH",
            "CARDIOLOGY CONSULT", "NEUROLOGY ON BOARD", "RESPIRATORY THERAPY CONSULTED",
            "GI CONSULTED", "IR CONSULTED", "PULMONARY CONSULT", "CONSULT PULMONOLOGY",
            "CRITICAL CARE CONSULTED", "SURGERY CONSULT", "CRITICAL CARE CONSULT", "SURGERY CONSULT PLACED"
        ]

        discussed_patterns = [
            # --- Doctor discussion ---
            r"DISCUSSED\s+(CASE\s+)?WITH\s+DR\.?\s+\w+",
            r"DISCUSSED\s+(WITH\s+)?DOCTOR\s+\w+",
            r"CONSULTED\s+WITH\s+DR\.?\s+\w+",

            # --- Generic discussion ---
            r"(?i)(?:Case discussed|Discussed|Spoke with|Consulted(?: with)?|Contacted)\s+(?:Dr\. [A-Z][a-z]+(?: \([A-Za-z\s]+\))?|[A-Za-z\s]+ (?:physician|nurse|caregiver|team|consultant))",

            # --- Tele / recommendation ---
            r"(?i)SEE\s+(?:TELE\s+)?(NEUROLOGY|CARDIOLOGY)\s+RECOMMENDATIONS",
            r"(?i)TELE\s+(NEUROLOGY|CARDIOLOGY)\s+(?:CONSULT|RECOMMENDATIONS)",
            r"(?i)RECOMMENDATIONS\s+FROM\s+(?:TELE\s+)?(NEUROLOGY|CARDIOLOGY)",

            # --- PT / OT ---
            r"(?i)\bPT\s+(?:AND\s+)?OT\s+EVALUATIONS",
            r"(?i)\bPHYSICAL\s+THERAPY\s+(?:AND\s+)?OCCUPATIONAL\s+THERAPY",
            r"(?i)\b(?:PT|OT)\s+EVAL",
            r"(?i)\bCONTINUE\s+(?:PHYSICAL\s+THERAPY|PT)\b",
            r"(?i)\bCONTINUE\s+(?:OCCUPATIONAL\s+THERAPY|OT)\b",
            r"(?i)\b(?:PHYSICAL\s+THERAPY|PT)\s+(?:IS\s+)?CONTINUED\b",
            r"(?i)\b(OCCUPATIONAL\s+THERAPY|OT)\s+(?:IS\s+)?CONTINUED\b",
            r"(?i)\b(?:CONTINUE|CONTINUING)\s+BOTH\s+(?:PT\s+AND\s+OT|PHYSICAL\s+AND\s+OCCUPATIONAL)\b",

            # --- Specialty consult detection (expanded) ---
            r"(?i)\b(?:CARDIOLOGY|NEUROLOGY|GI|IR|PULMONARY|RESPIRATORY\s+THERAPY|CRITICAL CARE|SURGERY)\s+(?:CONSULT|CONSULTED|EVALUATION)\b",

            # --- Strong structured consult ---
            r"(?i)\b(CRITICAL CARE|CARDIOLOGY|NEPHROLOGY|NEUROLOGY|PULMONOLOGY|GASTROENTEROLOGY|HEMATOLOGY|INFECTIOUS DISEASE|UROLOGY|ORTHOPEDICS|SURGERY|VASCULAR SURGERY|GENERAL SURGERY)\s+(?:hasb?\s+)?been\s+consulted\b",

            # --- Recommendation-based consult ---
            r"(?i)\bper\s+(?:rec(?:ommendation)?\s+of\s+)?(CARDIOLOGY|NEPHROLOGY|CRITICAL CARE|NEUROLOGY|PULMONOLOGY|GASTROENTEROLOGY|HEMATOLOGY|INFECTIOUS DISEASE|UROLOGY|ORTHOPEDICS|SURGERY|VASCULAR SURGERY|GENERAL SURGERY)\b",
            r"(?i)\bas\s+per\s+(CARDIOLOGY|NEPHROLOGY|CRITICAL CARE|NEUROLOGY|PULMONOLOGY|GASTROENTEROLOGY|HEMATOLOGY|INFECTIOUS DISEASE|UROLOGY|ORTHOPEDICS|SURGERY|VASCULAR SURGERY|GENERAL SURGERY)\b",
            r"(?i)\bper\s+([A-Z]+(?:\s+[A-Z]+)*)(?:\s*[:\-]?\s*)(SURGERY|CARE|TEAM|SERVICE)\b",
            # --- Status ---
            r"\bON\s+BOARD\b",
            # --- per short forms ---
            r"(?i)\bper\s+(ortho|cardio|neuro|gi|pulm|renal)\b",

            # --- per full specialty ---
            r"(?i)\bper\s+(cardiology|neurology|orthopedic(?:\s+surgeon)?|general\s+surgery)\b",

            # --- consulted ---
            r"(?i)\bconsulted\s+(cardiology|neurology|orthopedic(?:\s+surgery)?)\b",
            r"(?i)\b(cardiologist|neurologist|orthopedic(?:\s+surgeon)?)\s+has\s+been\s+consulted\b",

            # --- evaluation ---
            r"(?i)\b(cardiology|neurology|orthopedic(?:\s+surgery)?)\s+evaluated\b",

            # --- following ---
            r"(?i)\b(general\s+surgery|cardiology|neurology|orthopedic(?:\s+surgery)?)\s+following\b",

            # --- agreement ---
            r"(?i)\b(general\s+surgeon|cardiologist|orthopedic(?:\s+surgeon)?)\b.*?\b(agree|agrees|agreed)\b",
        ]

        results_temp = []
        for item in discussed_keywords:
            if item in input_upper:
                results_temp.append(item)
        for pattern in discussed_patterns:
            matches = re.findall(pattern, input_str, flags=re.IGNORECASE)
            for m in matches:
                if isinstance(m, str):
                    # Check if this capture is a specialty name (all caps, short)
                    if m.upper() in [s.upper() for s in medical_specialties]:
                        results_temp.append(f"{m.title()} Consulted")
                    else:
                        results_temp.append(m.strip())
                elif isinstance(m, tuple):
                    combined = " ".join([x for x in m if x and isinstance(x, str)]).strip()
                    if combined:
                        # If combined is a single specialty (e.g., "CARDIOLOGY")
                        if combined.upper() in [s.upper() for s in medical_specialties]:
                            results_temp.append(f"{combined.title()} Consulted")
                        else:
                            results_temp.append(combined)

        # print(f"[DEBUG] results_temp before normalization: {results_temp}")
        # Convert any raw specialty name to "Specialty Consulted"
        converted = []
        for item in results_temp:
            item_upper = item.upper().strip()
            if item_upper in [s.upper() for s in medical_specialties]:
                converted.append(f"{item.title()} Consulted")
            else:
                converted.append(item)
        results_temp = converted
        def normalize_consultation(consult_text):
            consult_upper = consult_text.upper()
            # If the text is exactly a known specialty (e.g., "CARDIOLOGY")
            if consult_upper in [s.upper() for s in medical_specialties]:
                return f"{consult_text.title()} Consulted"
            if "PT/OT" in consult_upper or ("PT" in consult_upper and "OT" in consult_upper):
                return "Physical Therapy, Occupational Therapy Consulted"
            elif "PHYSICAL THERAPY" in consult_upper and "OCCUPATIONAL THERAPY" in consult_upper:
                return "Physical Therapy, Occupational Therapy Consulted"
            elif "CONTINUE PHYSICAL THERAPY" in consult_upper and "CONTINUE OCCUPATIONAL THERAPY" in consult_upper:
                return "Physical Therapy, Occupational Therapy Consulted"
            elif "CONTINUE PT" in consult_upper and "CONTINUE OT" in consult_upper:
                return "Physical Therapy, Occupational Therapy Consulted"
            elif "TELENEUROLOGY" in consult_upper or "TELE NEUROLOGY" in consult_upper:
                return "Tele Neurology Consulted"
            elif "ORTHOPEDIC" in consult_upper and "PT" in consult_upper:
                return "Orthopedic Surgery, Physical Therapy Consulted"
            elif "ORTHOPEDIC SURGEON" in consult_upper or "ORTHOPEDICS" in consult_upper:
                return "Orthopedic Surgery Consulted"
            elif "GENERAL SURGEON" in consult_upper or "GS" in consult_upper:
                return "General Surgery Consulted"
            elif "ENT" == consult_upper.strip():
                return "ENT Consulted"
            elif "OBGYN" == consult_upper.strip():
                return "OBGYN Consulted"
            elif "PHYSICAL THERAPY" in consult_upper:
                return "Physical Therapy Consulted"
            elif "OCCUPATIONAL THERAPY" in consult_upper:
                return "Occupational Therapy Consulted"
            elif "PT" in consult_upper and "EVAL" in consult_upper:
                return "Physical Therapy Consulted"
            elif "OT" in consult_upper and "EVAL" in consult_upper:
                return "Occupational Therapy Consulted"
            elif "PT" == consult_upper.strip():
                return "Physical Therapy Consulted"
            elif "OT" == consult_upper.strip():
                return "Occupational Therapy Consulted"
            elif "CONSULT" == consult_upper.strip() or "NEUROLOGY" == consult_upper.strip():
                return None
            else:
                return consult_text

        normalized_results = []
        for result in results_temp:
            normalized = normalize_consultation(result)
            if normalized:
                normalized_results.append(normalized)

        filtered_results = []
        for result in normalized_results:
            result_lower = result.lower()
            if not any(discard in result_lower for discard in discard_phrases):
                filtered_results.append(result)

        unique_results = []
        seen = set()
        filtered_results_sorted = sorted(filtered_results, key=len, reverse=True)
        for res in filtered_results_sorted:
            if not any(res.lower() in existing.lower() for existing in seen):
                seen.add(res)
                unique_results.append(res)

        final_results = [r for r in unique_results if r and str(r).strip()]
        # print(f"[DEBUG] final_results after processing: {final_results}")

    return [{"Discussed Management": final_results if final_results else ["No Evidence Found"]}]

def independent_interpretation_mce(lab_str, assessment_str, hpi_str):
    # --- Step 1: Combine safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)

    # --- Step 2: Keywords (generic only, no variants) ---
    interpretation_keywords = [
            "INDEPENDENTLY INTERPRETED", "INDEPENDENT INTERPRETATION",
            "PERSONALLY REVIEWED AND INTERPRETED", "REVIEWED AND INTERPRETED BY ME",
            "INTERPRETED BY ME", "MY INTERPRETATION", "MY EKG INTERPRETATION",
            "I INTERPRETED THE EKG", "EKG INTERPRETED", "I INTERPRETED THE ECHO",
            "ECHO INTERPRETED", "MY ECHO INTERPRETATION", "I INTERPRETED THE XRAY",
            "I INTERPRETED THE CT", "I INTERPRETED THE MRI", "XRAY INTERPRETED",
            "CT INTERPRETED", "MRI INTERPRETED", "I INTERPRETED THE PFT",
            "PFT INTERPRETED", "I INTERPRETED THE HOLTER", "HOLTER INTERPRETED",
            "PACEMAKER INTERROGATION INTERPRETED", "MY EKG INTERPRETATION IS NSR",
            "MY CT INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
            "MY X-RAY INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
            "INTERPRETATION BY ME", "I PERSONALLY VIEWED AND INTERPRETED", 
    ]

    # --- Step 3: Regex patterns (handles variants) ---
    interpretation_patterns = [
            r"I\s+(PERSONALLY\s+)?INTERPRETED\s+(THE\s+)?(EKG|ECHO|XRAY|X-RAY|CT|MRI|PFT|HOLTER|PACEMAKER)",
            r"MY\s+(EKG|ECHO|XRAY|CT|MRI|INTERPRETATION)",
            r"(EKG|ECHO|XRAY|CT|MRI|HOLTER|PACEMaker|PFT)\s+INTERPRETED",
            r"INDEPENDENTLY\s+INTERPRETED",
            r"REVIEWED\s+AND\s+INTERPRETED\s+BY\s+ME",
            r"(?:^|\W)MY\s+(CT|X-?RAY|EKG)\s+INTERPRETATION(?::| IS)\s+.*"
    ]
    results = []

    # --- Step 4: Keyword matches ---
    for phrase in interpretation_keywords:
        if phrase in input_str.upper():
            results.append(phrase)

    # --- Step 5: Regex matches ---
    for pattern in interpretation_patterns:
        matches = re.findall(pattern, input_str, flags=re.IGNORECASE)
        results.extend([m.strip() for m in matches])

    # --- Step 6: Unique + ordered ---
    seen = set()
    unique_results = [x for x in results if not (x in seen or seen.add(x))]

    return [{"Independent Interpretation": unique_results or ["No Evidence Found"]}]


def independent_historian_mce(assessment_str, hpi_str):
    # --- Step 1: Combine safely with spacing ---
    input_str = " ".join(filter(None, [assessment_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str).upper()

    # --- Step 3: Relation keywords ---
    relation_keywords = ["PARENT", "GUARDIAN", "SPOUSE", "HUSBAND", "WIFE", "SON", "DAUGHTER", "FAMILY",
                            "FAMILY MEMBER", "RELATIVE", "BROTHER", "SISTER", "UNCLE", "AUNT",
                            "GRANDMOTHER", "GRANDFATHER", "FRIEND", "NEIGHBOR", "CAREGIVER",
                            "CASE MANAGER", "NURSE", "PHYSICIAN ASSISTANT", "CLINICAL STAFF",
                            "EMS PERSONNEL", "EMT", "PARAMEDIC", "EMPLOYER", "WITNESS", "LEGAL GUARDIAN",
                            "SURROGATE DECISION-MAKER"]

    # --- Step 3: Action keywords ---
    action_keywords = ["REPORTED", "STATED", "TOLD", "MENTIONED", "INFORMED", "SAID",
                        "PROVIDED BY", "GIVEN BY", "OBTAINED FROM", "HISTORY TAKEN FROM",
                        "HISTORY PROVIDED BY", "OBSERVED BY", "DOCUMENTED BY", "COLLECTED FROM"]
    previous_next_relation = ["DISCUSSED", "TOLD", "THEM", "REPORTED" "REPORTED", "STATED", "TOLD", "MENTIONED", "INFORMED", "SAID",
                        "PROVIDED BY", "GIVEN BY", "OBTAINED FROM", "HISTORY TAKEN FROM",
                        "HISTORY PROVIDED BY", "OBSERVED BY", "DOCUMENTED BY", "COLLECTED FROM", "MENTION"]

    # --- Step 4: Phrase patterns ---
    phrase_patterns = [
        r"(?i)\bINDEPENDENT HISTORIAN\b",
        r"(?i)\bHISTORY PROVIDED BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bHISTORY TAKEN FROM\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bOBTAINED FROM\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bINFORMATION GIVEN BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bVERIFIED BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bDISCUSS(?:ED|ION)\s+(?:ADVANCE|ADVANCED)\s+DIRECTIVE(?:S)?\s+WITH\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bDISCUSS(?:ED|ION)\s+(?:CODE\s+STATUS|GOALS\s+OF\s+CARE|END\s+OF\s+LIFE)\s+WITH\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bCONSIDERING\s+DNR\b",
        r"(?i)\bFAMILY\s+(?:DECIDED|CONSIDERING|INFORMED|REQUESTED)\s+(?:DNR|LIMITED\s+CARE|COMFORT\s+MEASURES)\b",
        r"(?i)\bADVANCE(?:D)?\s+DIRECTIVE(?:S)?\s+DISCUSS(?:ED|ION)\b",
        r"(?i)\bCODE\s+STATUS\s+DISCUSS(?:ED|ION)\b",
        ]

    # --- Step 6: Split into sentences ---
    # sentences = [s.strip() for s in re.split(r'[.;!]', input_str) if s.strip()]

    '''First split based on \n, but only break if the chunk before \n is short enough (like ≤ 90 chars).
    Then, for each chunk, further split it on . ; ! into sentences.'''

    threshold = 90  # max length to allow splitting at \n
    temp_chunks = []
    buffer = ""

    # --- Step 1: Smart split on \n ---
    for part in input_str.split("\n"):
        if buffer and len(buffer.strip()) <= threshold:
            # If last chunk is short → treat as sentence break
            temp_chunks.append(buffer.strip())
            buffer = part
        else:
            # Otherwise merge with previous text
            if buffer:
                buffer += " " + part
            else:
                buffer = part
    # Add final buffer
    if buffer.strip():
        temp_chunks.append(buffer.strip())

    # --- Step 2: Further split on punctuation (. ; !) ---
    sentences = []
    for chunk in temp_chunks:
        pieces = [s.strip() for s in re.split(r'[.;!]', chunk) if s.strip()]
        sentences.extend(pieces)

    results = []

    # --- Step 7: Check each sentence ---
    for i, sentence in enumerate(sentences):
        words = sentence.split()

        found_relation = any(word in relation_keywords for word in words)
        found_action = any(word in sentence for word in action_keywords)
        found_phrase = any(re.search(pattern, sentence) for pattern in phrase_patterns)

        if (found_relation and found_action) or found_phrase:
            results.append(sentence.strip())
        if i > 0:  # check against previous
            prev = sentences[i-1].upper()
            curr = sentence.upper()

            ## All the keywords that matched are strored as list 
            matched_prev = [word for word in relation_keywords if word in prev]
            matched_curr = [word for word in previous_next_relation if word in curr]

            if matched_prev and matched_curr:
                results.append(" ".join(matched_prev) + " " + " ".join(matched_curr))
                # results.append(sentence)

    # --- Step 8: Return results ---
    if results:
        # Unique + preserve order
        
        unique_results = ", ".join([x for x in results])
        return [{"Independent Historian": unique_results}]
    else:
        return [{"Independent Historian": "No Evidence Found"}]

def process_row_mce(row, config):
    """
    Process a single row for facility MCE.
    Expects the following helper functions to be defined:
        review_prior_external_notes_mce(lab_str, assessment_str, hpi_str)
        independent_interpretation_mce(lab_str, assessment_str, hpi_str)
        discussion_management_mce(assessment_str, lab_str, consultation_str)   # note: order: assessment_str, lab_str, consultation_str
        lab_order_mce(assessment_str)
        lab_review_mce(lab_str, dos=None)
        independent_historian_mce(assessment_str, hpi_str)
    """
    # --- Run helper functions ---
    discussion = discussion_management_mce(row["assessment_str"], row["lab_str"], row.get("consultation_str", ""))
    interpretation = independent_interpretation_mce(
        row["lab_str"], row["assessment_str"], row["hpi_str"]
    )
    prior_review = review_prior_external_notes_mce(
        row["lab_str"], row["assessment_str"], row["hpi_str"]
    )
    lab_orders = lab_order_mce(row["assessment_str"])
    lab_review_result = lab_review_mce(row["lab_str"], row["DOS"])
    historian = independent_historian_mce(row["assessment_str"], row["hpi_str"])

    # --- Run MDM2 logic (uses utils.Process_MDM2) ---
    from utils import Process_MDM2, flatten_list_of_dicts, simplify_list_of_dicts
    mdm2_level, label, reasons = Process_MDM2(
        discussion, interpretation, prior_review,
        lab_orders, lab_review_result, historian
    )

    # --- Flatten results for the REASONS column ---
    prior_review_vals = flatten_list_of_dicts(prior_review, "Prior Review")
    lab_orders_simple = simplify_list_of_dicts(lab_orders, "Lab Order")
    lab_review_simple = simplify_list_of_dicts(lab_review_result, "Lab Review")
    discussion_vals = flatten_list_of_dicts(discussion, "Discussed Management")
    interpretation_vals = flatten_list_of_dicts(interpretation, "Independent Interpretation")
    historian_vals = flatten_list_of_dicts(historian, "Independent Historian")

    details_parts = [
        f"Review Prior Notes> {prior_review_vals or ['No Evidence Found']}",
        f"Lab Order> {lab_orders_simple or ['No Evidence Found']}",
        f"Lab Review> {lab_review_simple or ['No Evidence Found']}",
        f"Discussion Management/Test> {discussion_vals or ['No Evidence Found']}",
        f"Independent Interpretation> {interpretation_vals or ['No Evidence Found']}",
        f"Independent Historian> {historian_vals or ['No Evidence Found']}"
    ]
    details = "~".join(details_parts)

    # --- Build reference text (selected sections) ---
    def safe_text(value):
        return str(value).replace(";", ",").strip()

    sections = []
    if row.get("assessment_str"):
        sections.append(f"[Assessment]: {safe_text(row['assessment_str'])}")
    if row.get("hpi_str"):
        sections.append(f"[HPI]: {safe_text(row['hpi_str'])}")
    if row.get("lab_str"):
        sections.append(f"[Lab]: {safe_text(row['lab_str'])}")
    if row.get("objective_str"):
        sections.append(f"[Objective]: {safe_text(row['objective_str'])}")
    combined_text = " ~ ".join(sections).replace("\n", " ").strip()

    # --- Extract Chart ID (remove prefix and extension) ---
    # Note: MCE filenames may not have a standard prefix; adjust if needed.
    chart = row["Filename"].replace("MCE_", "").replace(".TIF", "")

    # --- Return Series with expected column names ---
    return pd.Series({
        "Filename": row["Filename"],
        "Chart": chart,
        "DOS": row["DOS"],
        "Visit": row["Visit"],
        "Visit Time": row["Visit_time"],
        "MDM2_Level": label.upper(),
        "REASONS FOR MDM2": details,
        "REFERENCE TEXT MDM2": combined_text,
        "Page No": row["Page_No"]
    })

