# MSMC
# =============================================================================
def review_prior_external_notes_msmc(lab_str, assessment_str, hpi_str):
    # --- Step 1: Combine inputs safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str]))
    lab_text = input_str.upper().strip()
    
    # --- ADD THIS NEW FUNCTION HERE ---
    def fix_incomplete_words(text):
        """Fix incomplete medical terms before processing"""
        fixes = {
            # EKG/ECG related
            r'\bKG\s+REVIEW\b': 'EKG REVIEW',
            r'\bG\s+REVIEWE\b': 'EKG REVIEW', 
            r'\bG\s+REVIEWED\b': 'EKG REVIEW',
            r'\bEKG\s+REVIE\b': 'EKG REVIEW',
            r'\bEKG\s+READ\s+BY\s+ME\b': 'EKG REVIEWED BY ME',
            r'\bREVIEWED\s+BOTH\s+EKGS\b': 'REVIEWED BOTH EKGS',
            
            # Radiology related
            r'\bOLOGY:\s+REVIEWED\b': 'RADIOLOGY REVIEWED',
            r'\bI\s+HAVE\s+REVIEWED\s+IMAGING\b': 'IMAGING REVIEWED',
            r'\bI\s+HAVE\s+REVIEWED\s+LABS\b': 'LABS REVIEWED',
            
            # ECG related (alternative to EKG)
            r'\bECG:\s+REVIEWED\b': 'ECG REVIEWED',
            r'\bCG:\s+REVIEWED\b': 'ECG REVIEWED',
            
            # General fixes
            r'\bMAGING\b': 'IMAGING',  # Fix typo
            r'\bRELEVANT\s+LABS,\s+MAGING\b': 'RELEVANT LABS, IMAGING',
        }
        
        fixed_text = text
        for pattern, replacement in fixes.items():
            fixed_text = re.sub(pattern, replacement, fixed_text)
        
        return fixed_text
    
    # Apply the fixes to the text BEFORE processing
    lab_text = fix_incomplete_words(lab_text)
    
    # --- Step 2: Keywords indicating external notes review ---
    keywords = [
        "PRIOR EXTERNAL NOTES", "EXTERNAL PROVIDER NOTES", "OUTSIDE RECORDS",
        "OUTSIDE NOTES", "REVIEWED PRIOR NOTES", "REVIEWED OUTSIDE NOTES",
        "REVIEWED PCP NOTES", "REVIEWED CONSULT NOTES", "REVIEWED SPECIALIST NOTES",
        "PREVIOUS RECORDS REVIEWED", "EXTERNAL RECORDS REVIEWED", 
        "EXTERNAL DOCUMENTS REVIEWED", "ED REVIEWED", "I HAVE REVIEWED IMAGING", "ECG REVIEWED BY",
        "I REVIEWED RELEVANT LABS, IMAGING AND PRIOR RECORDS", "REVIEWED AND AGREE WITH THE ABOVE FINDINGS", "REVIEWED BY NEUROLOGY", 
        "REVIEWED BY ME", "ECG: REVIEWED", "CG: REVIEWED", "LABS AND THE IMAGES REVIEWED AND CONSIDERED IN THE EVALUATION OF PATIENT" , 
        "LABS AND IMAGES REVIEWED AND CONSIDERED IN THE EVALUATION OF PATIENT",
        "I REVIEWED RELEVANT LABS, MAGING AND PRIOR RECORDS AND UPDATED HOME MEDICATION RECONCILIATION", "KG REVIEW", "EKG READ BY ME", 
        "G REVIEWE", "REVIEWED BOTH EKGS", "G REVIEWED", "MRI REVIEWED", "EKG REVIE", "OLOGY: REVIEWED",
        "EKG REVIEW", "RADIOLOGY REVIEWED", "IMAGING REVIEWED", "ECG REVIEWED",
        "I HAVE PERSONALLY REVIEWED THIS STUDY AND AGREE WITH THE FINAL REPORT AS PRESENTED ABOVE",
        "IHAVE PERSONALLY. REVIEWED THIS STUDY AND AGREE WITH THE FINAL REPORT AS PRESENTED ABOV",
        "I HAVE PERSONALLY REVIEWED THIS STUDY AND AGREE WITH THE FINAL REPORT AS PRESENTED ABOV",
        "I HAVE PERSONALLY REVIEWED THIS STUDY AND AGREE WITH THE FINAL REPORT AS PRESENTED AB",
        "I HAVE PERSONALLY REVIEWED THIS STUDY AND AGREE WITH THE FINAL REPORT AS PRESENTED A",
        "I HAVE PERSONALLY REVIEWED THIS STUDY AND AGREE WITH THE FINAL REPORT AS PRESENTED"
        "I HAVE PERSONALLY REVIEWED THIS STUDY AS INTERPRETED BY THE RADIOLOGIST UNDER ARRANGEMENT AND AGREE WITH THE FINAL REPORT AS PRESENTED ABOVE"
    ]

    # --- Step 3: Regex patterns for flexible matching ---
    patterns = [
        r"REVIEW(?:ED|ING)?\s+(?:PRIOR|EXTERNAL|OUTSIDE)\s+(?:NOTES|RECORDS)",
        r"NOTES\s+FROM\s+(?:PCP|CARDIOLOGY|RADIOLOGY|ONCOLOGY|NEUROLOGY)",
        r"CONSULT\s+NOTES\s+REVIEW(?:ED|ING)?",
        r"OUTSIDE\s+HOSPITAL\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"PREVIOUS\s+VISIT\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"RADIOLOGICAL\s+(?:IMAGING|STUDIES)\s+REVIEWED\s+BY\s+ME",
        r"ALL\s+RADIOLOGICAL\s+STUDIES\s+HAVE\s+BEEN\s+REVIEWED(?:\s+BY\s+ME)?",
        r"REVIEWED\s+BY\s+ME\s+AND\s+I\s+AGREE\s+WITH\s+RADIOLOG(?:IST|ICAL)\s+READING",
        r"I\s+AGREE\s+WITH\s+THE\s+SUMMARY\s+OF\s+THE\s+RADIOLOGICAL\s+INTERPRETATIONS(?:\s+LISTED\s+BELOW)?"
    ]

    results = []

    # --- Step 4: Exact keyword search ---
    for kw in keywords:
        if kw in lab_text:
            results.append({"Prior Review": kw})

    # --- Step 5: Regex search ---
    for pattern in patterns:
        match = re.search(pattern, lab_text)
        if match:
            results.append({"Prior Review": match.group(0)})

    # --- Step 6: Clean and return results ---
    if results:
        # extract the string part from dicts
        vals = [item["Prior Review"] for item in results]

        # deduplicate while preserving order
        # also keep longest version if multiple similar matches exist
        unique_vals = list(dict.fromkeys(vals))

        # choose the longest match (most complete phrase)
        best_match = max(unique_vals, key=len)

        return [{"Prior Review": best_match}]
    else:
        return [{"Prior Review": "No Evidence Found"}]


def lab_order_msmc(assessment_str):
    # --- Step 1: Load databases ---
    lab_df = LAB_DF
    group_test_df = PANEL_DF

    # --- Step 2: Normalize input text ---
    input_str = (assessment_str or "").upper()
    # NORMALIZE HYPHENS TO SPACES AND FIX COMMON TYPOS
    input_str_normalized = re.sub(r'[-\s]+', ' ', input_str)
    # Fix common typos in medical terms
    input_str_normalized = re.sub(r'\bAXIALT\b', 'AXIAL', input_str_normalized)
    input_str_normalized = re.sub(r'\bCOMPUTERIZED\b', 'COMPUTED', input_str_normalized)
    input_str_normalized = re.sub(r'\bTOMOGRAPHY:\b', 'TOMOGRAPHY', input_str_normalized)
    
    results = []
    matched_labs = set()

    # --- Step 3: IMPROVED medication filtering ---
    # Only filter out lines that are PURELY about medications
    strong_medication_patterns = [
        r'^\s*\b(?:CONTINUE|HOLD|START)\b.*\b(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
        r'^\s*.*\b\d+\s*(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
    ]
    
    # Process line by line with GENTLE filtering
    lines = input_str_normalized.split('\n')
    filtered_lines = []
    
    for line in lines:
        line = line.strip()
        if not line:
            continue
        
        # Only exclude lines that are STRONGLY medication-only
        is_pure_medication = any(re.search(med_pat, line, re.IGNORECASE) for med_pat in strong_medication_patterns)
        
        if not is_pure_medication:
            filtered_lines.append(line)
    
    # Recombine filtered text
    filtered_text = ' '.join(filtered_lines)

    # --- Step 4: Enhanced individual lab matching with EXCLUSIONS ---
    # Exclude common medication terms from being detected as labs
    exclusion_terms = ['MG', 'MCG', 'TABLET', 'CAPSULE', 'TAB', 'PO', 'IV', 'BID', 'TID', 'QDAY']
    
    # NEW ADDITION — Exclude sodium/glucose mentions in context
    diet_context_patterns = [
        r'\bLOW\s+SODIUM\s+DIET\b',
        r'\bLOW\s*:\s*(?:SODIUM\s*/\s*DIABETIC|DIABETIC\s*/\s*SODIUM)\s+DIET\b',
        r'\bLOW\s*:\s*(?:SODIUM|DIABETIC)\s+DIET\b'
        r'\bRESTRICTED\s+SODIUM\s+DIET\b',
        r'\bSODIUM\s+RESTRICTION\b',
        r'\bSODIUM\s+INTAKE\b',
        r'\bREPLACE\s+POTASSIUM(?:\s+\w+){0,3}\b',
        r'\bSODIUM\s*/\s*DIABETIC\s+DIET\b',
        r'\bDIABETIC\s*/\s*SODIUM\s+DIET\b'
    ]
    glucose_monitor_patterns = [
        r'\bMONITOR\s+BLOOD\s+GLUCOSE\b',
        r'\bMONITOR\s+GLUCOSE\s+LEVELS?\b',
        r'\bCHECK\s+BLOOD\s+GLUCOSE\b',
        r'\bCHECK\s+GLUCOSE\s+LEVELS?\b',
        r'\bCHECK\s+BLOOD\s+GLUCOSE\s+(?:\d+\s*(?:TIMES\s*)?|\bTWICE\b|\bONCE\b|\bTHRICE\b)?\s*(?:DAILY|A\s*DAY)\b'
    ]

    sodium_diet_context = any(re.search(pat, filtered_text) for pat in diet_context_patterns)
    glucose_monitor_context = any(re.search(pat, filtered_text) for pat in glucose_monitor_patterns)
    
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_normalized = re.sub(r'[-\s]+', ' ', lab_name.upper())
        
        # Skip if this lab name is in our exclusion list
        if lab_name_normalized in exclusion_terms:
            continue

        # Skip sodium if in diet context
        if sodium_diet_context and lab_name_normalized == "SODIUM" or lab_name_normalized == "NA":
            continue
        
                          
        # Use word boundaries with normalized strings
        if re.search(r'\b' + re.escape(lab_name_normalized) + r'\b', filtered_text):
            matched_labs.add(lab_name)

    # --- Step 5: Enhanced pattern matching for common tests ---
    enhanced_order_patterns = [
        # Imaging studies - BROADER PATTERNS
        (r'\b(?:COMPUTED\s+)?(?:AXIAL\s+)?TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bCT\s+(?:SCAN)?\b', 'CT SCAN'),  # This will match "CT" and "CT SCAN"
        (r'\bCAT\s+SCAN\b', 'CT SCAN'),
        (r'\bAXIAL\s+TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bMRI\b', 'MRI'),
        (r'\bX-?RAY\b', 'X-RAY'),
        (r'\bULTRASOUND\b', 'ULTRASOUND'),
        (r'\bBLADDER\s+SCAN\b', 'BLADDER SCAN'),
        (r'\bEKG\b', 'EKG'),
        (r'\bECG\b', 'ECG'),

        # Echocardiogram patterns  
        (r'\bECHOCARDIOGRAM\b', 'ECHOCARDIOGRAM'),
        (r'\bECHOCARDIOGRAPHY\b', 'ECHOCARDIOGRAM'),
        (r'\bCARDIAC\s+ECHO\b', 'ECHOCARDIOGRAM'),
        (r'\bHEART\s+ULTRASOUND\b', 'ECHOCARDIOGRAM'),
        
        # Urinalysis patterns
        (r'\bURINALYSIS\b', 'URINALYSIS'),
        (r'\bUA\b', 'URINALYSIS'),
        (r'\bURINE\s+ANALYSIS\b', 'URINALYSIS'),
        (r'\bURINE\s+TEST\b', 'URINALYSIS'),
        
        # Culture types - include plural forms
        (r'\bBLOOD\s+CULTURES?\b', 'BLOOD CULTURE'),
        (r'\bURINE\s+CULTURES?\b', 'URINE CULTURE'),
        (r'\bSPUTUM\s+CULTURES?\b', 'SPUTUM CULTURE'),
        (r'\bWOUND\s+CULTURES?\b', 'WOUND CULTURE'),
        
        # Action-oriented patterns for cultures
        (r'\b(?:REPEAT|REPEATED)\s+BLOOD\s+CULTURES?\b', 'BLOOD CULTURE'),
        (r'\b(?:OBTAIN|GET|ORDER|SEND)\s+(?:BLOOD|URINE)\s+CULTURES?\b', 'CULTURE'),
        (r'\bCULTURES?\s+(?:DRAWN|OBTAINED|SENT)\b', 'CULTURE'),
        (r'\bCULTURES?\s+(?:NEGATIVE|POSITIVE)\b', 'CULTURE'),  
        
        # Action-oriented patterns for lab orders
        (r'\bOBTAIN\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bGET\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bORDER\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bNEED\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
    ]
    
    for pattern, test_name in enhanced_order_patterns:
        if re.search(pattern, filtered_text, re.IGNORECASE):
            matched_labs.add(test_name)

    # --- Step 6: DEDUPLICATION AND PRIORITIZATION ---
    # Remove generic terms when specific ones are found
    deduplication_rules = {
        'CT': ['CT SCAN', 'COMPUTED TOMOGRAPHY'],  # If CT found, remove CT SCAN and COMPUTED TOMOGRAPHY
        'CT': ['COMPUTED TOMOGRAPHY'],  # If CT found, remove COMPUTED TOMOGRAPHY
        'ECHOCARDIOGRAM': ['ECHO'],  # If ECHOCARDIOGRAM found, remove ECHO
        'CAROTID DOPPLER': ['DOPPLER'], # If CAROTID DOPPLER found, remove DOPPLER
        'URINE CULTURE': ['URINE'], # If URINE CULTURE found, remove URINE
    }
    
    # Apply deduplication rules
    for primary_term, terms_to_remove in deduplication_rules.items():
        if primary_term in matched_labs:
            for term in terms_to_remove:
                if term in matched_labs:
                    matched_labs.remove(term)
    
    # Remove "IMAGING STUDY" if specific imaging found
    specific_imaging_terms = ['MRI', 'CT SCAN', 'COMPUTED TOMOGRAPHY', 'X-RAY', 'ULTRASOUND', 'ECHOCARDIOGRAM', 'EKG', 'ECG']
    if any(term in matched_labs for term in specific_imaging_terms) and 'IMAGING STUDY' in matched_labs:
        matched_labs.remove('IMAGING STUDY')

    # --- NEW: Comprehensive deduplication for lab orders ---
    comprehensive_deduplication = {
        # Panel vs components
        'COMPLETE BLOOD COUNT': ['WBC', 'RBC', 'HGB', 'HCT', 'PLT', 'PLATELET COUNT'],
        'COMPREHENSIVE METABOLIC PANEL': ['GLUCOSE', 'BUN', 'CREATININE', 'CALCIUM', 'SODIUM', 
                                        'POTASSIUM', 'CHLORIDE', 'CO2', 'ALBUMIN', 'TOTAL PROTEIN'],
        'BASIC METABOLIC PANEL': ['GLUCOSE', 'BUN', 'CREATININE', 'CALCIUM', 'SODIUM', 
                                'POTASSIUM', 'CHLORIDE', 'CO2'],
        'RENAL FUNCTION PANEL': ['RENAL FUNCTION', 'GFR', 'BUN', 'CREATININE', 'SODIUM', 
                            'POTASSIUM', 'CHLORIDE', 'CO2', 'CALCIUM', 'ALBUMIN'],
        'URINALYSIS': ['URINE', 'URINE COLOR', 'URINE APPEARANCE', 'URINE GLUCOSE'],
        
        # Same test different names
        'CALCIUM': ['CA'],
        'ELECTROCARDIOGRAM': ['EKG', 'ECG'],
        'ECHOCARDIOGRAM': ['ECHO'],
        'CHEST X-RAY': ['CXR', 'X-RAY CHEST'],
        'X-RAY': ['XR'],
        'MAGNESIUM': ['MG'],
        'POTASSIUM': ['K'],
        'SODIUM': ['NA'],
        
        # Specific vs general
        'BLOOD CULTURE': ['CULTURE'],
        'URINE CULTURE': ['CULTURE'],
    }

    # Apply comprehensive deduplication - PREFER PRIMARY TERMS
    filtered_matched_labs = set()
    for lab in matched_labs:
        # Check if this lab should be replaced by a primary term
        replaced = False
        for primary_term, terms_to_remove in comprehensive_deduplication.items():
            if lab in terms_to_remove:
                # Replace with primary term
                filtered_matched_labs.add(primary_term)
                replaced = True
                #print(f"🔍 REPLACED: {lab} → {primary_term}")
                break
        
        if not replaced:
            filtered_matched_labs.add(lab)

    # Remove any primary terms that have components (clean up)
    final_matched_labs = set()
    for lab in filtered_matched_labs:
        if lab in comprehensive_deduplication:
            # This is a primary term - check if we have any of its components
            terms_to_remove = comprehensive_deduplication[lab]
            has_components = any(term in filtered_matched_labs for term in terms_to_remove if term != lab)
            if not has_components:
                final_matched_labs.add(lab)
        else:
            final_matched_labs.add(lab)

    matched_labs = final_matched_labs
    
    
    # --- Step 7: Check panels (only if ALL labs are present) ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]
        
        panel_labs_normalized = [re.sub(r'[-\s]+', ' ', lab.upper()) for lab in panel_labs]

        if panel_labs and all(re.search(r'\b' + re.escape(lab_norm) + r'\b', filtered_text) for lab_norm in panel_labs_normalized):
            results.append({"Lab Order": panel_name})
            # Remove labs that are part of this full panel (more aggressively)
            for lab in panel_labs:
                if lab in matched_labs:
                    matched_labs.remove(lab)
                    print(f"🔍 REMOVED FROM PANEL: {lab} (part of {panel_name})")

    # --- Step 8: Add remaining unmatched individual labs ---
    for lab in matched_labs:
        results.append({"Lab Order": lab})

    # --- Step 9: FINAL DEDUPLICATION of results ---
    unique_results = []
    seen_labs = set()
    
    for result in results:
        lab_name = result["Lab Order"]
        if lab_name not in seen_labs:
            seen_labs.add(lab_name)
            unique_results.append(result)

    # --- Step 10: If nothing found ---
    if not unique_results:
        return [{"Lab Order": "No Evidence Found"}]

    return unique_results


def lab_review_msmc(lab_str, dos=None):
    
    # --- Step 1: Load databases ---
    lab_df = LAB_DF
    group_test_df = PANEL_DF

    # --- Step 2: Check if lab content has dates ---
    def has_dates(text):
        """Check if text contains date patterns"""
        date_pattern = r'(\d{1,2}/\d{1,2}/\d{2,4}|[A-Za-z]{3}-\d{1,2}-\d{4})'
        return bool(re.search(date_pattern, text))
    
    # --- Step 3: Filter lab content based on date presence ---
    if dos and has_dates(lab_str):
        # If DOS is provided AND content has dates, filter by DOS
        filtered_lab_str = get_lab_content_by_dos(lab_str, dos)
        
    else:
        # If no DOS OR no dates in content, use entire lab content
        filtered_lab_str = lab_str
        
    
    # --- Step 4: Normalize input text ---
    input_str = (filtered_lab_str or "").upper()
    
    results = []
    matched_labs = set()

    # --- Step 5: Enhanced short lab mapping ---
    short_lab_mapping = {
        'CA': 'CALCIUM', 'K': 'POTASSIUM', 'NA': 'SODIUM', 'MG': 'MAGNESIUM',
        'CL': 'CHLORIDE', 'P': 'PHOSPHORUS', 'FE': 'IRON', 'HGB': 'HEMOGLOBIN',
        'HCT': 'HEMATOCRIT', 'WBC': 'WHITE BLOOD CELL COUNT', 'RBC': 'RED BLOOD CELL COUNT',
        'PLT': 'PLATELET COUNT', 'PLATELETS': 'PLATELET COUNT', 'PT': 'PROTHROMBIN TIME',
        'INR': 'INTERNATIONAL NORMALIZED RATIO', 'BUN': 'BLOOD UREA NITROGEN', 
        'CR': 'CREATININE', 'CREAT': 'CREATININE', 'AST': 'ASPARTATE AMINOTRANSFERASE',
        'ALT': 'ALANINE AMINOTRANSFERASE', 'ALP': 'ALKALINE PHOSPHATASE', 
        'TBIL': 'BILIRUBIN TOTAL', 'BILIRUBIN': 'BILIRUBIN TOTAL', 'TOTAL BILIRUBIN': 'BILIRUBIN TOTAL',
        'ALB': 'ALBUMIN', 'TP': 'TOTAL PROTEIN', 'CO2': 'CARBON DIOXIDE', 'BICARB': 'CARBON DIOXIDE',
        'SGPT': 'ALANINE AMINOTRANSFERASE', 'SGOT': 'ASPARTATE AMINOTRANSFERASE', 'POC BEDSIDE GLUCOSE': 'GLUCOSE',
        'PT': 'PROTHROMBIN TIME', 'INR': 'INTERNATIONAL NORMALIZED RATIO', 'APTT': 'PARTIAL THROMBOPLASTIN TIME',
        'PTT': 'PARTIAL THROMBOPLASTIN TIME', 'WBC': 'WBC COUNT', 'RBC': 'RBC COUNT', 'URINE': 'URINALYSIS', 
        'BILIRUBIN': 'BILIRUBIN TOTAL',  'SGPT': 'ALT',  'SGOT': 'AST', 'ECG': 'ELECTROCARDIOGRAM', 'EKG': 'ELECTROCARDIOGRAM',
        'GLOBULIN': 'TOTAL PROTEIN', 'ALB/GLOB': 'ALBUMIN/GLOBULIN RATIO',  'BUN/CR': 'BUN/CREATININE RATIO',
        'POCT GLUCOSE': 'GLUCOSE',
    }

    # --- Step 6: Enhanced function to check lab presence ---
    def is_lab_present(lab_name, text):
        """Check if a lab component is present, handling abbreviations and word order variations"""
        lab_upper = lab_name.upper()
        
        # Check exact match first
        if re.search(r'\b' + re.escape(lab_upper) + r'\b', text, re.IGNORECASE):
            return True
        
        # Check abbreviations
        for abbr, full_name in short_lab_mapping.items():
            if full_name == lab_upper:
                if re.search(r'\b' + re.escape(abbr) + r'\b', text, re.IGNORECASE):
                    return True
        
        # Handle word order variations for specific terms
        word_order_variations = {
            'BILIRUBIN TOTAL': [r'TOTAL\s+BILIRUBIN', r'BILIRUBIN,\s*TOTAL'],
        }
        
        if lab_upper in word_order_variations:
            for pattern in word_order_variations[lab_upper]:
                if re.search(pattern, text, re.IGNORECASE):
                    return True
        
        return False

    # --- Step 7: Extract and CLEAN panel definitions from Excel ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    panel_definitions = {}
    
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = []
        
        for col in lab_columns:
            if pd.notna(row[col]):
                # CLEAN the lab name - remove extra spaces
                lab_name = str(row[col]).upper().strip()
                # Fix specific known issues
                if lab_name == 'RED BLOOD CELL COUNT  ':
                    lab_name = 'RED BLOOD CELL COUNT'
                if lab_name:
                    panel_labs.append(lab_name)
        
        if panel_labs:
            panel_definitions[panel_name] = panel_labs

    # --- FIX 1: Enhanced Panel Detection ---
    detected_panels = []
    panel_components_found = set()

    for panel_name, required_labs in panel_definitions.items():
        all_components_found = True
        found_count = 0
        
        for lab in required_labs:
            if is_lab_present(lab, input_str):
                found_count += 1
            else:
                # For panels, we need ALL components to be present
                all_components_found = False
                break
        
        # Only detect panel if ALL required components are found
        if all_components_found and found_count >= 2:  # At least 2 components to be considered a panel
            detected_panels.append(panel_name)
            # Track all components of this panel to avoid individual detection
            for lab in required_labs:
                panel_components_found.add(lab)
                # Also add abbreviations
                for abbr, full_name in short_lab_mapping.items():
                    if full_name == lab:
                        panel_components_found.add(abbr)

    # --- Step 9: Add detected panels to results ---
    for panel in detected_panels:
        results.append({"Lab Review": panel})

    # --- Step 10: Individual lab detection (ONLY if not part of detected panels) ---
        
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_clean = lab_name.upper().strip()
        
        # Skip if this lab is part of a detected panel
        if lab_name_clean in panel_components_found:
            continue
            
        # Check if lab is present in text
        if re.search(r'\b' + re.escape(lab_name_clean) + r'\b', input_str, re.IGNORECASE):
            
            matched_labs.add(lab_name)

    # --- Step 11: Add remaining individual labs (EXCLUDE panel components) ---
    
    for lab in matched_labs:
        # Double-check it's not a panel component
        if lab.upper() not in panel_components_found:
            results.append({"Lab Review": lab})
            
    
    # --- Step 12: Enhanced Imaging and Culture Study Detection ---
    
    imaging_patterns = [
        # Imaging studies (no value required)
        (r'\b(CT\s+SCAN|CT|CAT\s+SCAN)\b', 'CT SCAN'),
        (r'\b(X-?RAY|X\s+RAY|XR\s+CHEST|XR)\b', 'X-RAY'), 
        (r'\b(MRI\s+SCAN|MRI)\b', 'MRI'),
        (r'\b(ULTRASOUND|US)\b', 'ULTRASOUND'),
        (r'\b(?:ECHOCARDIOGRAM|ECHO)\b', 'ECHOCARDIOGRAM'),
        (r'\b(MAMMOGRAM)\b', 'MAMMOGRAM'),
        (r'\b(DOPPLER)\b', 'DOPPLER'),
        (r'\b(FLUOROSCOPY)\b', 'FLUOROSCOPY'),
        (r'\b(ANGIOGRAM)\b', 'ANGIOGRAM'),
        (r'\bBLADDER\s+SCAN\b', 'BLADDER SCAN')
    ]
    
    # Culture types (no value required)
    culture_patterns = [
        (r'\b(BLOOD\s+CULTURE)\b', 'BLOOD CULTURE'),
        (r'\b(URINE\s+CULTURE)\b', 'URINE CULTURE'),
        (r'\b(SPUTUM\s+CULTURE)\b', 'SPUTUM CULTURE'),
        (r'\b(WOUND\s+CULTURE)\b', 'WOUND CULTURE'),
        (r'\b(AEROBIC\s+CULTURE)\b', 'AEROBIC CULTURE'),
        (r'\b(ANAEROBIC\s+CULTURE)\b', 'ANAEROBIC CULTURE'),
    ]
    
    # Add imaging and culture tests (they don't need values)
    for pattern, test_name in imaging_patterns + culture_patterns:
        if re.search(pattern, input_str, re.IGNORECASE):
            results.append({"Lab Review": test_name})
    

    # --- Step 13: Final cleanup and deduplication ---
    
    # --- FIX 2: Comprehensive panel components definition ---
    always_panel_components = {
        'COMPLETE BLOOD COUNT': [
            'WBC', 'RBC', 'HGB', 'HCT', 'PLT', 'PLATELET COUNT', 
            'WHITE BLOOD CELL COUNT', 'RED BLOOD CELL COUNT', 'HEMOGLOBIN', 
            'HEMATOCRIT', 'MCV', 'MCH', 'MCHC', 'RDW', 'MPV', 'RDW-SD', 'RDW-CV',
            'NEUTROPHILS RELATIVE', 'LYMPHOCYTES', 'MONOCYTES', 'EOSINOPHILS', 
            'BASOPHILS', 'NRBC', 'IMMATURE GRANULOCYTES', 'NEUTROPHILS ABSOLUTE',
            'LYMPHOCYTES ABSOLUTE', 'MONOCYTES ABSOLUTE', 'EOSINOPHILS ABSOLUTE',
            'BASOPHILS ABSOLUTE', 'NRBC ABSOLUTE', 'ABSOLUTE IMMATURE GRANULOCYTES',
            'WBC COUNT', 'RBC COUNT', 'PLATELETS' 
                        
        ],
        
        'COMPREHENSIVE METABOLIC PANEL': [
            'NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
            'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
            'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM', 'ALBUMIN', 
            'TOTAL PROTEIN', 'ALKALINE PHOSPHATASE', 'ALANINE AMINOTRANSFERASE', 
            'ASPARTATE AMINOTRANSFERASE', 'BILIRUBIN TOTAL', 'ALT', 'AST', 'SGPT',
            'ALKALINE', 'PHOSPHATASE', 'TBIL', 'BILIRUBIN', 'GLOBULIN',
            'ALBUMIN/GLOBULIN RATIO', 'ANION GAP', 'BUN/CREATININE RATIO',
            'CALCULATED OSMOLALITY', 'EGFR', 'OSMOLALITY', 'ALB', 'TP'
        ],
        
        'BASIC METABOLIC PANEL': [
            'NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
            'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
            'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM'
        ],
        
        'ELECTROLYTE PANEL': [
            'NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
            'CO2', 'CARBON DIOXIDE', 'BICARB'
        ],
        
        'RENAL FUNCTION PANEL': [
            'NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
            'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
            'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM', 'ALBUMIN', 'PHOSPHORUS',
            'EGFR', 'BUN/CREATININE RATIO', 'CALCULATED OSMOLALITY', 'P'
        ],
        
        'CARDIAC PANEL': [
            'VENTRICULAR RATE', 'ATRIAL RATE', 'P-R INTERVAL', 'QRS DURATION', 
            'Q-T INTERVAL', 'QTC CALCULATION', 'CALCULATED P AXIS', 'CALCULATED R AXIS', 
            'CALCULATED T AXIS', 'ECG', 'EKG'
        ],
        
        'MUSCLE ENZYME PANEL': [
            'CPK', 'LACTIC ACID', 'AST', 'ALT', 'LACTATE'
        ],
        
        'TOXICOLOGY SCREEN': [
            'SALICYLATE LEVEL', 'ACETAMINOPHEN LEVEL', 'ETHANOL LEVEL',
            'OPIATE SCREEN URINE', 'COCAINE URINE', 'BENZODIAZEPINE SCREEN URINE',
            'PHENCYCLIDINE URINE QUAL', 'CANNABINOIDS URINE QUAL', 
            'AMPHETAMINE/METHAMPHETAMINE URINE', 'BARBITURATE SCREEN URINE',
            'FENTANYL URINE QUAL', 'TRICYCLICS URINE'
        ],
        
        'URINALYSIS': [
            'URINE COLOR', 'URINE APPEARANCE', 'URINE GLUCOSE', 'URINE BILIRUBIN', 
            'URINE BLOOD', 'URINE PROTEIN', 'URINE NITRITE', 'URINE LEUKOCYTES', 
            'URINE SPECIFIC GRAVITY', 'URINE PH', 'UROBILINOGEN', 'URINE', 'PH',
            'KETONES-UA', 'HYALINE CASTS', 'MUCUS THREADS', 'BACTERIA', 'NITRITE',
            'POCT GLUCOSE', 'LEUKOCYTE ESTERACES', 'GLUCOSE RANDOM', 'BLOOD UA',
            'BILIRUBIN URINE', 'RBC UA', 'WBC UA'
        ],
        
        'HEPATIC FUNCTION PANEL': [
            'ALBUMIN', 'TOTAL PROTEIN', 'BILIRUBIN TOTAL', 
            'ALKALINE PHOSPHATASE', 'ALANINE AMINOTRANSFERASE', 
            'ASPARTATE AMINOTRANSFERASE', 'ALT', 'AST', 'SGPT',
            'ALKALINE', 'PHOSPHATASE', 'TBIL', 'BILIRUBIN', 'GLOBULIN'
        ]
    }
    
    # Define equivalence mapping to avoid duplicates
    equivalence_map = {
        "CBC": "COMPLETE BLOOD COUNT",
        "BMP": "BASIC METABOLIC PANEL", 
        "CMP": "COMPREHENSIVE METABOLIC PANEL",
        "LFT": "LIVER FUNCTION TESTS",
        "RFT": "RENAL FUNCTION TESTS",
        "LIVER FUNCTION TESTS": "HEPATIC FUNCTION PANEL",
        "XR CHEST": "X-RAY", 
        "X-RAY CHEST": "CHEST X-RAY",
        "XR": "X-RAY",
        "PT INR": "INTERNATIONAL NORMALIZED RATIO",
        "PROTIME": "PROTHROMBIN TIME",
        "PTT": "PARTIAL THROMBOPLASTIN TIME",
        "APTT": "PARTIAL THROMBOPLASTIN TIME",
        "ALKALINE": "ALKALINE PHOSPHATASE",
        "PHOSPHATASE": "ALKALINE PHOSPHATASE",
        "SGPT": "ALANINE AMINOTRANSFERASE",
        "SGOT": "ASPARTATE AMINOTRANSFERASE",
        "ANTIBODY": "ANTIBODY SCREEN", 
        "CT SCAN": "CT", 
        "CAT SCAN": "CT",
        "COMPUTED TOMOGRAPHY": "CT",
    }
    
    # Add short lab mappings to equivalence map
    equivalence_map.update(short_lab_mapping)
    
    # Clean up the results
    cleaned_results = []
    seen_items = set()
    
    for entry in results:
        item = entry["Lab Review"].upper().strip()
        
        # Convert equivalents to standard names
        normalized_item = equivalence_map.get(item, item)
        
        # Skip if we've already seen this (or its equivalent)
        if normalized_item not in seen_items:
            seen_items.add(normalized_item)
            cleaned_results.append({"Lab Review": normalized_item})
    
    
    # --- FIX 3: Track used lab components to prevent double-counting ---
    # Define what should always be kept (individual tests, not panels)
    always_keep_individual_tests = [
        'TROPONIN', 'HCG', 'MAGNESIUM', 'LIPASE', 'PROCALCITONIN',
        'BNP', 'NT PROBNP', 'D-DIMER', 'CRP', 'ESR', 'TSH'
    ]

    used_lab_components = set()
    final_cleaned_results = []

    # Process panels in priority order (highest first)
    priority_order = [
        'COMPREHENSIVE METABOLIC PANEL',
        'COMPLETE BLOOD COUNT', 
        'HEPATIC FUNCTION PANEL',
        'URINALYSIS',
        'CARDIAC PANEL',
        'MUSCLE ENZYME PANEL',
        'TOXICOLOGY SCREEN',
        'BASIC METABOLIC PANEL',
        'ELECTROLYTE PANEL',
        'RENAL FUNCTION PANEL'
    ]

    #print("=== COMPONENT TRACKING DEBUG ===")

    # First pass: Add panels in priority order, tracking their components
    for panel_name in priority_order:
        panel_found = False
        # Check if this panel exists in our results
        for entry in cleaned_results:
            if entry["Lab Review"] == panel_name:
                panel_found = True
                break
        
        if panel_found:
            # Get all components for this panel
            panel_components = panel_definitions.get(panel_name, [])
            
            # Check if any components are already used by higher priority panels
            overlapping_components = used_lab_components.intersection(set(panel_components))
            
            if not overlapping_components:
                # No overlap - safe to add this panel
                final_cleaned_results.append({"Lab Review": panel_name})
                # Mark all its components as used
                used_lab_components.update(panel_components)
                #print(f"✅ ADDED PANEL: {panel_name} (no component overlap)")
                #print(f"✅ ADDED PANEL: {panel_name} (no component overlap)")
            else:
                # Panels with overlapping components are handled here - no print needed
                # They will be naturally skipped in the second pass
                pass

    # Second pass: Add individual tests that aren't part of any COMPLETE panels
    for entry in cleaned_results:
        lab_name = entry["Lab Review"]
        
        # Skip if it's already been added as part of a panel
        if any(lab_name == item["Lab Review"] for item in final_cleaned_results):
            continue
            
        # Check if this is an individual test (not a panel)
        is_panel = lab_name in panel_definitions
        
        if not is_panel:
            # Check if this individual test could be part of any panel
            potential_panels = []
            for panel_name, panel_components in panel_definitions.items():
                if lab_name in panel_components:
                    potential_panels.append(panel_name)
            
            # If this test could be part of panels, check if those panels are COMPLETE
            if potential_panels:
                should_add_individual = True
                for potential_panel in potential_panels:
                    # Check if this panel is COMPLETE (all components present)
                    panel_complete = potential_panel in [item["Lab Review"] for item in final_cleaned_results]
                    if panel_complete:
                        should_add_individual = False
                        #print(f"❌ FILTERED: {lab_name} (part of complete {potential_panel})")
                        break
                
                if should_add_individual:
                    final_cleaned_results.append({"Lab Review": lab_name})
                    #print(f"✅ ADDED INDIVIDUAL: {lab_name} (incomplete panel components)")
            else:
                # This test doesn't belong to any panel - always add it
                final_cleaned_results.append({"Lab Review": lab_name})
                #print(f"✅ ADDED INDIVIDUAL: {lab_name} (not part of any panel)")
        else:
            # This is a panel that was skipped due to overlap
            #print(f"ℹ️  SKIPPED PANEL: {lab_name}")
            pass

    # Replace cleaned_results with our final filtered list
    cleaned_results = final_cleaned_results
    
    if not final_cleaned_results:
        return [{"Lab Review": "No Evidence Found"}]

    return final_cleaned_results
  
def discussion_management_msmc(assessment_str, lab_str, consultation_str):
    """
    consultation_str: The combined consultation data for the current row only
    """
    results = []

    # --- Step 1: Load and clean consultation terms from CURRENT ROW ---
    try:
        #print(f"Debug: Processing consultation data for current row")
        
        # Get consultation data from current row only (from consultation_str)
        raw_consultation_terms = []
        if consultation_str and pd.notna(consultation_str) and str(consultation_str).strip():
            raw_consultation_terms = [str(consultation_str)]
        
        #print(f"DEBUG: Found {len(raw_consultation_terms)} raw consultation terms for this row")
        
        # Clean the consultation terms (your existing logic)
        clean_consultation_terms = []
        seen_terms = set()
        
        for term in raw_consultation_terms:
            #print(f"DEBUG: Processing term: '{term}'")
            
            # Split multi-line text into individual lines
            lines = term.split('\n')
            #print(f"DEBUG: Split into {len(lines)} lines")
            
            for line_num, line in enumerate(lines):
                #print(f"DEBUG: Processing line {line_num}: '{line}'")
                
                # Clean each line separately
                cleaned_term = line.strip().upper()

                # Skip empty terms
                if not cleaned_term:
                    continue
                    
                # Remove common noise patterns
                if re.search(r'\b\d+of\d+\b', cleaned_term) or 'PAGE' in cleaned_term:
                    continue
                    
                # Remove hospital/discharge summary text
                if any(noise in cleaned_term for noise in ['HOSPITALIST', 'DISCHARGE SUMMARY', 'WESTERN ARIZONA', 'REGIONAL MEDICAL', 'ONECONTENT']):
                    continue
                    
                # Remove doctor names
                if re.search(r'\bDR\.?\s+[A-Z]', cleaned_term) or re.search(r'[A-Z]+\s+PHY\b', cleaned_term):
                    continue
                    
                # Remove quotes and special characters
                cleaned_term = re.sub(r'["\']', '', cleaned_term)
                
                # Remove specific noisy patterns
                noisy_patterns = [
                    r'PATIENT IN THE PROCESS OF TRANSFERRING.*',
                    r'EMERGENCY ROOM.*',
                    r'SEE .*',
                    r'GENERATED BY.*',
                    r'GENERATED ON.*',
                    r'ATTENDING.*',
                    r'ADMITTED.*',
                    r'ENCOUNTER.*',
                    r'NAME.*',
                ]
            
                for pattern in noisy_patterns:
                    cleaned_term = re.sub(pattern, '', cleaned_term).strip()
                
                # Skip if term is too short or just noise
                if len(cleaned_term) < 3 or cleaned_term in ['NONE', '2OF3', '3OF4', 'NA', 'N/A', '']:
                    continue
                
                #print(f"DEBUG: After cleaning: '{cleaned_term}'")
                
                # Check if it matches medical departments (your existing logic)
                medical_departments = {
                    'CARDIOLOGY': ['CARDIOLOGY', 'CARDIAC', 'CARDIO', 'CV', 'CARDIOLOGIST'],
                    'NEUROLOGY': ['NEUROLOGY', 'NEURO', 'NEUROLOGICAL', 'NEUROLOGIST'],
                    'ONCOLOGY': ['ONCOLOGY', 'ONCO', 'CANCER', 'ONCOLOGIST', 'HEMATOLOGY/ONCOLOGY'],
                    'PULMONOLOGY': ['PULMONOLOGY', 'PULMONARY', 'PULM', 'RESPIRATORY', 'CHEST', 'PULMONOLOGIST'],
                    'GASTROENTEROLOGY': ['GASTROENTEROLOGY', 'GASTRO', 'GI', 'GASTROINTESTINAL', 'GASTROENTEROLOGIST'],
                    'NEPHROLOGY': ['NEPHROLOGY', 'NEPHRO', 'RENAL', 'NEPHROLOGIST'],
                    'INFECTIOUS_DISEASE': ['INFECTIOUS DISEASE', 'INFECTIOUS', 'ID', 'INFECTIOUS DISEASE SPECIALIST'],
                    'UROLOGY': ['UROLOGY', 'URO', 'UROLOGICAL', 'UROLOGIST'],
                    'HEMATOLOGY': ['HEMATOLOGY', 'HEME', 'BLOOD', 'HEMATOLOGIST'],
                    'ENDOCRINOLOGY': ['ENDOCRINOLOGY', 'ENDO', 'ENDOCRINE', 'ENDOCRINOLOGIST'],
                    'RHEUMATOLOGY': ['RHEUMATOLOGY', 'RHEUM', 'RHEUMATOLOGICAL', 'RHEUMATOLOGIST'],
                    'DERMATOLOGY': ['DERMATOLOGY', 'DERM', 'DERMATOLOGIST'],
                    
                    'ORTHOPEDICS': ['ORTHOPEDICS', 'ORTHO', 'ORTHOPEDIC', 'ORTHOPEDIST'],
                    'PHYSICAL_THERAPY': ['PHYSICAL THERAPY', 'PT', 'PHYSICAL THERAPIST'],
                    'OCCUPATIONAL_THERAPY': ['OCCUPATIONAL THERAPY', 'OT', 'OCCUPATIONAL THERAPIST'],
                    'SPEECH_THERAPY': ['SPEECH THERAPY', 'SPEECH', 'ST', 'SPEECH LANGUAGE PATHOLOGY', 'SLP', 'SPEECH PATHOLOGIST'],
                    'RESPIRATORY_THERAPY': ['RESPIRATORY THERAPY', 'RT', 'RESPIRATORY THERAPIST'],
                    'PSYCHIATRY': ['PSYCHIATRY', 'PSYCH', 'PSYCHIATRIC', 'PSYCHIATRIST'],
                    'SOCIAL_WORK': ['SOCIAL WORK', 'SOCIAL WORKER', 'SOCIAL SERVICES'],
                    'CASE_MANAGEMENT': ['CASE MANAGEMENT', 'CASE MANAGER'],
                    'CARE_MANAGEMENT': ['CARE MANAGEMENT', 'CONSULT TO CARE'],
                    'PALLIATIVE_CARE': ['PALLIATIVE CARE', 'PALLIATIVE', 'PALLIATIVE MEDICINE'],
                }
            
                # Check if the cleaned term matches any medical department
                matched_department = None
                for main_dept, variations in medical_departments.items():
                    for variation in variations:
                        if re.search(r'\b' + re.escape(variation) + r'\b', cleaned_term):
                            matched_department = main_dept.replace('_', ' ')
                            break
                    if matched_department:
                        break
                
                if matched_department and matched_department not in seen_terms:
                    clean_consultation_terms.append(matched_department)
                    seen_terms.add(matched_department)
                    #print(f"DEBUG: ADDED: {matched_department} CONSULTED")
        
        # Add consultation terms to results
        for term in clean_consultation_terms:
            results.append(f"{term} CONSULTED")
            
        #print(f"DEBUG: Consultation results for this row: {results}")
            
    except Exception as e:
        #print(f"DEBUG: Error processing consultation data: {e}")
        import traceback
        traceback.print_exc()

    # --- Step 2: If no consultations found in consultation_str, apply discussion management logic ---
    if not results:
        #print("DEBUG: No consultations found in consultation_str, applying discussion management logic")
        # Combine input strings
        input_str = " ".join(filter(None, [assessment_str, lab_str]))
        input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)
        
        # --- Step 2: Combined Exclusion Patterns ---
        input_str = re.sub(
            r'(?ix)'
            r'(?:'
            r'CONSULTANTS?\s*[:-]?\s*(?:\n|\r|\r\n)?\s*NOT(?:\s+ON\s+FILE)?'
            r'|CONSULTANTS?\s*[:-]?\s*(?:\n|\r|\r\n|\s)*NOT\s+ON\s+FILE'
            r'|\bONCOLOGY\s+FOLLOW(?:\s*UP)?\b'
            r'|\bFOLLOWS?\s+(?:UP\s+WITH|WITH)\s+[A-Z][A-Z\s]+\b'
            r'|\bCONSIDER\s+(?:A\s+)?CONSULTS?(?:ATION)?\b'
            r'|\b(MIGHT|MAY)\s+NEED\s+[A-Z\s]*(CONSULTS?|CONSULTATION)\b'
            r'|\bMEDICINE\s+WAS\s+CONSULTED\b'
            r'|\b(FOLLOW(?:\s*[\n\r]\s*|\s*[-\s]*)UP|FLUP)\s+[A-Z\s]*(CULTURES?|CONSULTS?|CONSULTATION)\b'
            r'|\b(?:TELE\s+)?[A-Z\s]*CONSULT(?:S|ATION)?\s+(?:ORDER\s+PLACED|ORDERED|REQUEST(?:ED|ING)?)\b'
            r'|\bREFER\s+(?:TO\s+)?THE?\s*DISCHARGE\s+SUMMARY\b'
            r'|\b[A-Z][A-Z\s]+CONSULT\S*\s+WILL\s+(?:BE\s+)?GREATLY\s+APPRECIATE(?:D)?\b'
            r'|\b(?:GENERAL\s+)?SURGER(Y|ICAL)\s+CONSULTS?(?:ATION)?\b'
            r'|\b(?:PENDING\s+[A-Z\s]*(CONSULTS?|CONSULTATION)|[A-Z\s]*(CONSULTS?|CONSULTATION)\s+(IS\s+)?PENDING)\b'
            r'|\bMANAGEMENT\s+CONSULT(?:ED|S?|ATION)?\b'
            r'|\bHOSPICE\s+CONSULT(?:ED|S?|ATION)?\b'
            r'|\bCONSULT(?:ED|S?|ATION)?\s+FOR\s+(?:FURTHER\s+)?(RECOMMENDATIONS?|MANAGEMENT|ADVICE|INPUT)\b'
            r'|\bAPPRECIATE\s+[A-Z\s]*CONSULTATION\b'
            r'|\b[A-Z\s]*EVALUATION\s+REQUESTED\b'
            r'|\bTHANKS?(?:\s*YOU)?(?:\s+VERY\s+MUCH)?\s+FOR\s+THE\s+CONSULTATION\b'
            r'|DISCUSSED\s+(?:PLAN|CASE|CARE|TREATMENT)?\s*(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY|RELATIVES?|HIS\s+WIFE|HER\s+HUSBAND|SPOUSE|SON|DAUGHTER|CHILD|CHILDREN|CAREGIVER)\b'
            r'|SPOKE\s+(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY|RELATIVES?|HIS\s+WIFE|HER\s+HUSBAND|SPOUSE|SON|DAUGHTER|CHILD|CHILDREN|CAREGIVER)\b'
            r'|TALKED\s+(?:TO|WITH)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY|RELATIVES?|HIS\s+WIFE|HER\s+HUSBAND|SPOUSE)\b'
            r'|CASE\s+DISCUSSED\s+(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?|FAMILY)\b'
            r'|FOLLOW\s+UP\s+(?:WITH|W/)\s*:?(\s+THE\s+)?(?:PATIENTS?|PTS?)\b'
            r'|\b[A-Z][A-Za-z\s]*\s+FOLLOWING\s+[A-Z][A-Za-z\s]*\b'
            r'|\bFOLLOWING\s+BY\s+[A-Z][A-Za-z\s]+\b'
            r'|\bFOLLOWED\s+BY\s+[A-Z][A-Za-z\s]+\b'
            r'|\bPER\s+[A-Z][A-Za-z\s]+\s+RECOMMENDATION\b'
            r'|\bAS\s+PER\s+[A-Z][A-Za-z\s]+\s+RECOMMENDATION\b'
            r'|\bACCORDING\s+TO\s+[A-Z][A-Za-z\s]+\s+RECOMMENDATION\b'
            r'|\bRECOMMENDATION\s+FROM\s+[A-Z][A-Za-z\s]+\b'
            r'|\bCONSULT\s+TO\s+TELE\s+PULMONOLOGY\b'
            r'|\bCONSULT\s+TO\s+(TELE\s+)?[A-Z][A-Za-z]+\b'
            r'|\bWILL\s+NEED\s+[A-Z][A-Za-z]+\s+CONSULT\b'
            r'|\bTELE\s+[A-Z][A-Za-z]+\s+CONSULTED\b'
            r'|\bDISCUSS\s+WITH\s+[A-Z][A-Za-z]+\s+TOMORROW\b'
            r')',
            '',
            input_str
        )
        
        # Pattern 1: "consult/consulted" + department
        consult_patterns = [
            r'(?:CONSULT|CONSULTED|CONSULTATION)\s+(?:WITH\s+)?(?:THE\s+)?([A-Z][A-Za-z\s\/]+?(?=\s|\.|,|$|;))',
            r'([A-Z][A-Za-z\s\/]+)\s+(?:CONSULT|CONSULTED|CONSULTATION)',
            r'CONSULT\s+(?:FOR\s+)?([A-Z][A-Za-z\s\/]+)',
            r'\bCONSULTANTS?\s*[:\-]\s*([A-Z][A-Za-z\/\s]+)\b',
            r'\bCONSULTANTS?\s*(?:IS|ARE)?\s*([A-Z][A-Za-z\/\s]+)\b',

        ]
        
        # Pattern 2: "discuss/discussed" + department  
        discuss_patterns = [
            r'(?:DISCUSS|DISCUSSED|DISCUSSION)\s+(?:WITH\s+)?(?:THE\s+)?([A-Z][A-Za-z\s\/]+?(?=\s|\.|,|$|;))',
            r'([A-Z][A-Za-z\s\/]+)\s+(?:DISCUSS|DISCUSSED|DISCUSSION)',
            r'DISCUSSED\s+(?:CASE\s+)?WITH\s+([A-Z][A-Za-z\s\/]+)',
            r'SPOKE\s+WITH\s+([A-Z][A-Za-z\s\/]+)',
            r'TALKED\s+WITH\s+([A-Z][A-Za-z\s\/]+)',
            r'\b[A-Z][A-Za-z]+\s+Dr\.\s*[A-Z][A-Za-z]+\s+consulted\b',
            r'\b[A-Z][A-Za-z]+\s+Dr\.\s*[A-Z][A-Za-z\.]+\s+[A-Za-z]+\s+consulted\b',
            r'\b[A-Z][A-Za-z\s]+?\s+Dr\.\s*[A-Z][A-Za-z\.]+\s*[A-Za-z]*\s+consulted\b',
            r'\bNEPHROLOGY\s+DR\.\s*SLOAN\s+CONSULTED\b',
            r'\b[A-Z][A-Za-z]+\s+Dr\.\s*[A-Z][A-Za-z]+\s+consulted\b',
            

        ]
        
        def find_medical_department(text):
            """Check if text contains any medical department"""
            text_upper = text.upper().strip()
            
            # Special handling for PT/OT combinations
            pt_ot_combinations = [
                'PT/OT', 'OT/PT', 'PT/OT/ST', 'PT OT', 'OT PT', 'PT OT ST',
                'PHYSICAL THERAPY/OCCUPATIONAL THERAPY', 'OCCUPATIONAL THERAPY/PHYSICAL THERAPY'
            ]
            
            for combo in pt_ot_combinations:
                if combo in text_upper:
                    return "PT/OT"
            
            for main_dept, variations in medical_departments.items():
                for variation in variations:
                    # Exact word matching to avoid partial matches
                    if re.search(r'\b' + re.escape(variation) + r'\b', text_upper):
                        return main_dept.replace('_', ' ')
            return None
        
        # Search for consult patterns
        for pattern in consult_patterns:
            matches = re.finditer(pattern, input_str, re.IGNORECASE)
            for match in matches:
                if match.lastindex:
                    department_text = match.group(1).strip()
                    department = find_medical_department(department_text)
                    if department:
                        result = f"CONSULTED {department}"
                        if result not in results:
                            results.append(result)
        
        # Search for discuss patterns
        for pattern in discuss_patterns:
            matches = re.finditer(pattern, input_str, re.IGNORECASE)
            for match in matches:
                if match.lastindex:
                    department_text = match.group(1).strip()
                    department = find_medical_department(department_text)
                    if department:
                        result = f"DISCUSSED WITH {department}"
                        if result not in results:
                            results.append(result)
    else:
        print("DEBUG: Using consultation_str data")
        

    # Remove duplicates and return
    results = list(set(results))
    return [{"Discussed Management": results if results else ["No Evidence Found"]}]


def independent_interpretation_msmc(lab_str, assessment_str, hpi_str):
    # --- Step 1: Combine safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)

    # --- Step 2: Keywords (generic only, no variants) ---
    interpretation_keywords = [
            "INDEPENDENTLY INTERPRETED", "INDEPENDENT INTERPRETATION",
            "PERSONALLY REVIEWED AND INTERPRETED", "REVIEWED AND INTERPRETED BY ME",
            "INTERPRETED BY ME", "MY INTERPRETATION", "MY EKG INTERPRETATION",
            "I INTERPRETED THE EKG", "EKG INTERPRETED", "I INTERPRETED THE ECHO",
            "ECHO INTERPRETED", "MY ECHO INTERPRETATION", "I INTERPRETED THE XRAY",
            "I INTERPRETED THE CT", "I INTERPRETED THE MRI", "XRAY INTERPRETED",
            "CT INTERPRETED", "MRI INTERPRETED", "I INTERPRETED THE PFT",
            "PFT INTERPRETED", "I INTERPRETED THE HOLTER", "HOLTER INTERPRETED",
            "PACEMAKER INTERROGATION INTERPRETED", "MY EKG INTERPRETATION IS NSR",
            "MY CT INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
            "MY X-RAY INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
            "INTERPRETATION BY ME", "I PERSONALLY VIEWED AND INTERPRETED",
            "ALL LAB RESULTS AND MAGING STUDIES DESCRIBED ABOVE WERE INDEPENDENTLY REVIEWED AND INTERPRETED BY ME",
            "ALL LAB RESULTS AND IMAGING STUDIES DESCRIBED ABOVE WERE INDEPENDENTLY REVIEWED AND INTERPRETED BY ME"
    ]

    # --- Step 3: Regex patterns (handles variants) ---
    interpretation_patterns = [
            r"I\s+(PERSONALLY\s+)?INTERPRETED\s+(THE\s+)?(EKG|ECHO|XRAY|X-RAY|CT|MRI|PFT|HOLTER|PACEMAKER)",
            r"MY\s+(EKG|ECHO|XRAY|CT|MRI|INTERPRETATION)",
            r"(EKG|ECHO|XRAY|CT|MRI|HOLTER|PACEMaker|PFT)\s+INTERPRETED",
            r"INDEPENDENTLY\s+INTERPRETED",
            r"REVIEWED\s+AND\s+INTERPRETED\s+BY\s+ME",
            r"(?:^|\W)MY\s+(CT|X-?RAY|EKG)\s+INTERPRETATION(?::| IS)\s+.*"
    ]

    results = []

    # --- Step 4: Keyword matches ---
    for phrase in interpretation_keywords:
        if phrase in input_str.upper():
            results.append(phrase)

    # --- Step 5: Regex matches ---
    for pattern in interpretation_patterns:
        matches = re.findall(pattern, input_str, flags=re.IGNORECASE)
        results.extend([m.strip() for m in matches])

    # --- Step 6: Unique + ordered ---
    seen = set()
    unique_results = [x for x in results if not (x in seen or seen.add(x))]

    return [{"Independent Interpretation": unique_results or ["No Evidence Found"]}]


def independent_historian_msmc(assessment_str, hpi_str):
    # --- Step 1: Combine safely ---
    input_str = " ".join(filter(None, [assessment_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str).upper()

    # --- Step 2: Define key lists ---
    relation_keywords = [
        "PARENT","GUARDIAN","SPOUSE","HUSBAND","WIFE","SON","DAUGHTER","FAMILY MEMBER",
        "RELATIVE","BROTHER","SISTER","UNCLE","AUNT","GRANDMOTHER","GRANDFATHER",
        "FRIEND","NEIGHBOR","CAREGIVER","CASE MANAGER","NURSE","PHYSICIAN ASSISTANT",
        "CLINICAL STAFF","EMS","EMT","PARAMEDIC","EMPLOYER","WITNESS","LEGAL GUARDIAN",
        "SURROGATE","TEAM","STAFF"
    ]

    action_keywords = [
        "REPORTED","STATED","TOLD","MENTIONED","INFORMED","SAID","PROVIDED","GIVEN",
        "OBTAINED","HISTORY TAKEN","HISTORY PROVIDED","OBSERVED","DOCUMENTED","COLLECTED",
        "PRESENTED","ARRIVED","BROUGHT","CAME","ACCOMPANIED"
    ]

    phrase_patterns = [
        r"(?i)\bINDEPENDENT HISTORIAN\b",
        r"(?i)\bHISTORY (?:PROVIDED|TAKEN|OBTAINED)\s+FROM\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bINFORMATION\s+(?:GIVEN|PROVIDED)\s+BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bPRESENTED\s+(?:WITH|BY)\s+(?:HIS|HER|THE)?\s*(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bACCOMPANIED\s+BY\s+(?:HIS|HER|THE)?\s*(?:{})\b".format("|".join(relation_keywords))
    ]

    # --- Step 3: Split text roughly into sentences ---
    sentences = [s.strip() for s in re.split(r'[.;!\n]', input_str) if s.strip()]

    results = []

    # --- Step 4: Main logic ---
    for sentence in sentences:
        # Check if any key phrase matches
        if any(re.search(p, sentence, re.IGNORECASE) for p in phrase_patterns):
            results.append(sentence)
            continue

        # Find combination of relation + action keywords
        if any(r in sentence for r in relation_keywords) and any(a in sentence for a in action_keywords):
            results.append(sentence)

    # --- Step 5: Context limiter (keep relevant ~15 words around the match)
    trimmed_results = []
    for s in results:
        words = s.split()
        joined = " ".join(words)

        # find first occurrence of any keyword
        match = re.search(
            r"(" + "|".join(relation_keywords + action_keywords) + r")",
            joined
        )
        if match:
            idx = joined[:match.start()].count(" ")
            start = max(0, idx - 8)
            end = min(len(words), idx + 8)
            trimmed_results.append(" ".join(words[start:end]))
        else:
            trimmed_results.append(s[:120])  # fallback limit

    # --- Step 6: Return clean output ---
    if trimmed_results:
        return [{"Independent Historian": list(dict.fromkeys(trimmed_results))}]
    else:
        return [{"Independent Historian": ["No Evidence Found"]}]

def process_row_msmc(row, config):
    """
    Process a single row for facility MSMC.
    Expects the following helper functions to be defined:
        review_prior_external_notes_msmc(lab_str, assessment_str, hpi_str)
        independent_interpretation_msmc(lab_str, assessment_str, hpi_str)
        discussion_management_msmc(lab_str, assessment_str, consultation_str)   # note: order: lab_str, assessment_str, consultation_str
        lab_order_msmc(assessment_str)
        lab_review_msmc(lab_str, dos=None)
        independent_historian_msmc(assessment_str, hpi_str)
    """
    # --- Run helper functions (order matches notebook's compute_mdm2_details) ---
    discussion = discussion_management_msmc(
        row["lab_str"], row["assessment_str"], row["consultation_str"]
    )
    interpretation = independent_interpretation_msmc(
        row["lab_str"], row["assessment_str"], row["hpi_str"]
    )
    prior_review = review_prior_external_notes_msmc(
        row["lab_str"], row["assessment_str"], row["hpi_str"]
    )
    lab_orders = lab_order_msmc(row["assessment_str"])
    lab_review_result = lab_review_msmc(row["lab_str"], row["DOS"])
    historian = independent_historian_msmc(row["assessment_str"], row["hpi_str"])

    # --- Abbreviation mapping (from notebook) ---
    def abbreviate_lab_name(lab_name):
        """Convert full lab names to standardized abbreviations"""
        abbreviation_map = {
            # Common panels
            'COMPLETE BLOOD COUNT': 'CBC',
            'COMPREHENSIVE METABOLIC PANEL': 'CMP',
            'BASIC METABOLIC PANEL': 'BMP',
            'LIVER FUNCTION TESTS': 'LFT',
            'RENAL FUNCTION TESTS': 'RFT',
            'BLOOD UREA NITROGEN': 'BUN',
            # Individual tests
            'HEMOGLOBIN': 'HGB',
            'HEMATOCRIT': 'HCT',
            'WHITE BLOOD CELL COUNT': 'WBC',
            'RED BLOOD CELL COUNT': 'RBC', 
            'PLATELET COUNT': 'PLT',
            'SODIUM': 'NA',
            'POTASSIUM': 'K',
            'CHLORIDE': 'CL',
            'CALCIUM': 'CA',
            'MAGNESIUM': 'MG',
            'CREATININE': 'CREAT',
            'GLUCOSE': 'GLUC',
            'ALBUMIN': 'ALB',
            'TOTAL PROTEIN': 'TP',
            'ALKALINE PHOSPHATASE': 'ALP',
            'ASPARTATE AMINOTRANSFERASE': 'AST',
            'ALANINE AMINOTRANSFERASE': 'ALT',
            'LIPASE': 'LIPS',
            'AMYLASE': 'AMYL',
            'BILIRUBIN TOTAL': 'TBIL',
            'INTERNATIONAL NORMALIZED RATIO': 'INR',
            'PROTHROMBIN TIME': 'PT',
            'PARTIAL THROMBOPLASTIN TIME': 'PTT',
            # Imaging
            'X-RAY': 'XR',
            'CT SCAN': 'CT',
            'ULTRASOUND': 'US',
            'MRI': 'MRI',
            'ECHOCARDIOGRAM': 'ECHO',
            # Blood gas
            'PH': 'PH',
            'PCO2': 'PCO2',
            'PO2': 'PO2',
            'O2 SATURATION': 'O2SAT',
        }
        return abbreviation_map.get(lab_name.upper(), lab_name)

    def abbreviate_lab_list(lab_list):
        if isinstance(lab_list, list):
            return [abbreviate_lab_name(lab) for lab in lab_list]
        return lab_list

    # --- Run MDM2 logic (uses utils.Process_MDM2) ---
    from utils import Process_MDM2, flatten_list_of_dicts, simplify_list_of_dicts
    mdm2_level, label, reasons = Process_MDM2(
        discussion, interpretation, prior_review,
        lab_orders, lab_review_result, historian
    )

    # --- Flatten results for the REASONS column ---
    prior_review_vals = flatten_list_of_dicts(prior_review, "Prior Review")
    lab_orders_simple = simplify_list_of_dicts(lab_orders, "Lab Order")
    lab_review_simple = simplify_list_of_dicts(lab_review_result, "Lab Review")
    discussion_vals = flatten_list_of_dicts(discussion, "Discussed Management")
    interpretation_vals = flatten_list_of_dicts(interpretation, "Independent Interpretation")
    historian_vals = flatten_list_of_dicts(historian, "Independent Historian")

    # Apply abbreviations (as in notebook)
    lab_orders_simple = abbreviate_lab_list(lab_orders_simple)
    lab_review_simple = abbreviate_lab_list(lab_review_simple)

    details_parts = [
        f"Review Prior Notes> {prior_review_vals or ['No Evidence Found']}",
        f"Lab Order> {lab_orders_simple or ['No Evidence Found']}",
        f"Lab Review> {lab_review_simple or ['No Evidence Found']}",
        f"Discussion Management/Test> {discussion_vals or ['No Evidence Found']}",
        f"Independent Interpretation> {interpretation_vals or ['No Evidence Found']}",
        f"Independent Historian> {historian_vals or ['No Evidence Found']}"
    ]
    details = "~".join(details_parts)

    # --- Build reference text (selected sections) ---
    def safe_text(value):
        return str(value).replace(";", ",").strip()

    sections = []
    if row.get("assessment_str"):
        sections.append(f"[Assessment]: {safe_text(row['assessment_str'])}")
    if row.get("hpi_str"):
        sections.append(f"[HPI]: {safe_text(row['hpi_str'])}")
    if row.get("lab_str"):
        sections.append(f"[Lab]: {safe_text(row['lab_str'])}")
    if row.get("objective_str"):
        sections.append(f"[Objective]: {safe_text(row['objective_str'])}")
    combined_text = " ~ ".join(sections).replace("\n", " ").strip()

    # --- Extract Chart ID (remove prefix and extension) ---
    chart = row["Filename"].replace("MSMC_", "").replace(".TIF", "")

    # --- Return Series with expected column names ---
    return pd.Series({
        "Filename": row["Filename"],
        "Chart": chart,
        "DOS": row["DOS"],
        "Visit": row["Visit"],
        "Visit Time": row["Visit_time"],
        "MDM2_Level": label.upper(),
        "REASONS FOR MDM2": details,
        "REFERENCE TEXT MDM2": combined_text,
        "Page No": row["Page_No"]
    })

