def review_prior_external_notes_nl(lab_str, assessment_str, hpi_str, Critical_care_time_str, Code_status_str):
    # --- Step 1: Combine inputs safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str, Critical_care_time_str, Code_status_str]))
    lab_text = input_str.upper().strip()
    
    # --- ADD THIS NEW FUNCTION HERE ---
    def fix_incomplete_words(text):
        """Fix incomplete medical terms before processing"""
        fixes = {
            # EKG/ECG related
            r'\bKG\s+REVIEW\b': 'EKG REVIEW',
            r'\bG\s+REVIEWE\b': 'EKG REVIEW', 
            r'\bG\s+REVIEWED\b': 'EKG REVIEW',
            r'\bEKG\s+REVIE\b': 'EKG REVIEW',
            r'\bEKG\s+READ\s+BY\s+ME\b': 'EKG REVIEWED BY ME',
            r'\bREVIEWED\s+BOTH\s+EKGS\b': 'REVIEWED BOTH EKGS',
            
            # Radiology related
            r'\bOLOGY:\s+REVIEWED\b': 'RADIOLOGY REVIEWED',
            r'\bI\s+HAVE\s+REVIEWED\s+IMAGING\b': 'IMAGING REVIEWED',
            r'\bI\s+HAVE\s+REVIEWED\s+LABS\b': 'LABS REVIEWED',
            
            # ECG related (alternative to EKG)
            r'\bECG:\s+REVIEWED\b': 'ECG REVIEWED',
            r'\bCG:\s+REVIEWED\b': 'ECG REVIEWED',
            
            # General fixes
            r'\bMAGING\b': 'IMAGING',  # Fix typo
            r'\bRELEVANT\s+LABS,\s+MAGING\b': 'RELEVANT LABS, IMAGING',
        }
        
        fixed_text = text
        for pattern, replacement in fixes.items():
            fixed_text = re.sub(pattern, replacement, fixed_text)
        
        return fixed_text
    
    # Apply the fixes to the text BEFORE processing
    lab_text = fix_incomplete_words(lab_text)
    
    # --- Step 2: Keywords indicating external notes review ---
    keywords = [
        "PRIOR EXTERNAL NOTES", "EXTERNAL PROVIDER NOTES", "OUTSIDE RECORDS",
        "OUTSIDE NOTES", "REVIEWED PRIOR NOTES", "REVIEWED OUTSIDE NOTES",
        "REVIEWED PCP NOTES", "REVIEWED CONSULT NOTES", "REVIEWED SPECIALIST NOTES",
        "PREVIOUS RECORDS REVIEWED", "EXTERNAL RECORDS REVIEWED", 
        "EXTERNAL DOCUMENTS REVIEWED", "ED REVIEWED", "I HAVE REVIEWED IMAGING", "I HAVE REVIEWED LABS", "ECG REVIEWED BY"
        "I REVIEWED RELEVANT LABS, IMAGING AND PRIOR RECORDS", "REVIEWED AND AGREE WITH THE ABOVE FINDINGS", "REVIEWED BY NEUROLOGY", "REVIEWED BY ME",
        "ECG: REVIEWED", "CG: REVIEWED", "LABS AND THE IMAGES REVIEWED AND CONSIDERED IN THE EVALUATION OF PATIENT" , 
        "LABS AND IMAGES REVIEWED AND CONSIDERED IN THE EVALUATION OF PATIENT",
        "I REVIEWED RELEVANT LABS, MAGING AND PRIOR RECORDS AND UPDATED HOME MEDICATION RECONCILIATION", "KG REVIEW", "EKG READ BY ME", "G REVIEWE",
        "REVIEWED BOTH EKGS", "G REVIEWED", "MRI REVIEWED", "EKG REVIE", "OLOGY: REVIEWED",
        "EKG REVIEW", "RADIOLOGY REVIEWED", "IMAGING REVIEWED", "LABS REVIEWED", "ECG REVIEWED", 
        "HAVE PERSONALLY REVIEWED THE LABS AND TEST RESULTS THAT ARE PRESENTLY AVAILABLE",
        "I HAVE PERSONALLY REVIEWED THE LABS AND TEST RESULTS THAT ARE PRESENTLY AVAILABLE",
        "I HAVE PERSONALLY REVIEWED THE IMAGES AND AGREE WITH RADIOLOGIST REPORT",
        "I HAVE PERSONALLY REVIEWED THE FOLLOWING IMAGING AND AGREE WITH RADIOLOGIST",
        "I HAVE PERSONALLY REVIEWED THE FOLLOWING IMAGING AND AGREE WITH THE RADIOLOGIST",
        "IH HAVE PERSONALLY REVIEWED THE FOLLOWING IMAGING AND AGREE WITH THE RADIOLOGIST",
        "I HAVE PERSONALLY REVIEWED THET FOLLOWING IMAGING AND AGREE WITH THE RADIOLOGIST",
        "I PERSONALLY REVIEWED THE RADIOLOGY IMAGING", "[X] I PERSONALLY REVIEWED THE RADIOLOGY IMAGING", 
        "[X] I PERSONALLY REVIEWED THE RADLOLOGY IMAGING", "I PERSONALLY REVIEWED ALL X RAYS"  
    ]
    

    # --- Step 3: Regex patterns for flexible matching ---
    patterns = [
        r"REVIEW(?:ED|ING)?\s+(?:PRIOR|EXTERNAL|OUTSIDE)\s+(?:NOTES|RECORDS)",
        r"NOTES\s+FROM\s+(?:PCP|CARDIOLOGY|RADIOLOGY|ONCOLOGY|NEUROLOGY)",
        r"CONSULT\s+NOTES\s+REVIEW(?:ED|ING)?",
        r"OUTSIDE\s+HOSPITAL\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"PREVIOUS\s+VISIT\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"RADIOLOGICAL\s+(?:IMAGING|STUDIES)\s+REVIEWED\s+BY\s+ME",
        r"ALL\s+RADIOLOGICAL\s+STUDIES\s+HAVE\s+BEEN\s+REVIEWED(?:\s+BY\s+ME)?",
        r"REVIEWED\s+BY\s+ME\s+AND\s+I\s+AGREE\s+WITH\s+RADIOLOG(?:IST|ICAL)\s+READING",
        r"I\s+AGREE\s+WITH\s+THE\s+SUMMARY\s+OF\s+THE\s+RADIOLOGICAL\s+INTERPRETATIONS(?:\s+LISTED\s+BELOW)?"
    ]

    results = []

    # --- Step 4: Exact keyword search ---
    for kw in keywords:
        if kw in lab_text:
            results.append({"Prior Review": kw})

    # --- Step 5: Regex search ---
    for pattern in patterns:
        match = re.search(pattern, lab_text)
        if match:
            results.append({"Prior Review": match.group(0)})

    # --- Step 6: Clean and return results ---
    if results:
        # extract the string part from dicts
        vals = [item["Prior Review"] for item in results]

        # deduplicate while preserving order
        # also keep longest version if multiple similar matches exist
        unique_vals = list(dict.fromkeys(vals))

        # choose the longest match (most complete phrase)
        best_match = max(unique_vals, key=len)

        return [{"Prior Review": best_match}]
    else:
        return [{"Prior Review": "No Evidence Found"}]


def independent_interpretation_nl(lab_str, assessment_str, hpi_str, hospitalcourse_str, Code_status_str):
    # --- Step 1: Combine safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str, hospitalcourse_str, Code_status_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)

    # --- Step 2: Keywords (generic only, no variants) ---
    interpretation_keywords = [
            "INDEPENDENTLY INTERPRETED", "INDEPENDENT INTERPRETATION",
            "PERSONALLY REVIEWED AND INTERPRETED", "REVIEWED AND INTERPRETED BY ME",
            "INTERPRETED BY ME", "MY INTERPRETATION", "MY EKG INTERPRETATION",
            "I INTERPRETED THE EKG", "EKG INTERPRETED", "I INTERPRETED THE ECHO",
            "ECHO INTERPRETED", "MY ECHO INTERPRETATION", "I INTERPRETED THE XRAY",
            "I INTERPRETED THE CT", "I INTERPRETED THE MRI", "XRAY INTERPRETED",
            "CT INTERPRETED", "MRI INTERPRETED", "I INTERPRETED THE PFT",
            "PFT INTERPRETED", "I INTERPRETED THE HOLTER", "HOLTER INTERPRETED",
            "PACEMAKER INTERROGATION INTERPRETED", "MY EKG INTERPRETATION IS NSR",
            "MY CT INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
            "MY X-RAY INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
            "INTERPRETATION BY ME", "INDEPENDENT REVIEW OF", "REVIEW AND INTERPRETATION OF",
            "PERSONALLY REVIEWED AND INTERPRETED", "REVIEWED AND INTERPRETED", "I PERSONALLY VIEWED AND INTERPRETED THIS EKG",
            "I PERSONALLY VIEWED AND INTERPRETED"  
    ]

    # --- Step 3: Regex patterns (handles variants) ---
    interpretation_patterns = [
            r"I\s+(PERSONALLY\s+)?INTERPRETED\s+(THE\s+)?(EKG|ECHO|XRAY|X-RAY|CT|MRI|PFT|HOLTER|PACEMAKER)",
            r"MY\s+(EKG|ECHO|XRAY|CT|MRI|INTERPRETATION)",
            r"(EKG|ECHO|XRAY|CT|MRI|HOLTER|PACEMaker|PFT)\s+INTERPRETED",
            r"INDEPENDENTLY\s+INTERPRETED",
            r"REVIEWED\s+AND\s+INTERPRETED\s+BY\s+ME",
            r"(?:^|\W)MY\s+(CT|X-?RAY|EKG)\s+INTERPRETATION(?::| IS)\s+.*",
            r"INDEPENDENT\s+REVIEW\s+OF\s+(?:THE\s+)?(CHEST\s+X-?RAY|CT|MRI|X-?RAY|IMAGING)",
            r"REVIEW\s+AND\s+INTERPRETATION\s+OF\s+(?:THE\s+)?(CXR|CHEST\s+X-?RAY|CT|MRI|X-?RAY|IMAGING)",
            r"(?:PERSONALLY\s+)?REVIEWED?\s+AND\s+INTERPRETED?\s+(?:THE\s+)?(?:IMAGING|STUDIES|CXR|X-?RAY|CT|MRI)",
            r"I\s+(?:PERSONALLY\s+)?(?:REVIEWED|INTERPRETED)\s+(?:THE\s+)?(?:IMAGING|CHEST\s+X-?RAY|CXR|CT|MRI)"
    ]

    results = []

    # --- Step 4: Keyword matches ---
    for phrase in interpretation_keywords:
        if phrase in input_str.upper():
            results.append(phrase)

    # --- Step 5: Regex matches ---
    for pattern in interpretation_patterns:
        matches = re.findall(pattern, input_str, flags=re.IGNORECASE)
        results.extend([m.strip() for m in matches])

    # --- Step 6: Unique + ordered ---
    seen = set()
    unique_results = [x for x in results if not (x in seen or seen.add(x))]

    return [{"Independent Interpretation": unique_results or ["No Evidence Found"]}]


def lab_order_nl(assessment_str):
    # --- Step 1: Load databases ---
    lab_df = LAB_DF
    group_test_df = PANEL_DF

    # --- Step 2: Normalize input text ---
    input_str = (assessment_str or "").upper()
    # NORMALIZE HYPHENS TO SPACES AND FIX COMMON TYPOS
    input_str_normalized = re.sub(r'[-\s]+', ' ', input_str)
    # Fix common typos in medical terms
    input_str_normalized = re.sub(r'\bAXIALT\b', 'AXIAL', input_str_normalized)
    input_str_normalized = re.sub(r'\bCOMPUTERIZED\b', 'COMPUTED', input_str_normalized)
    input_str_normalized = re.sub(r'\bTOMOGRAPHY:\b', 'TOMOGRAPHY', input_str_normalized)
    
    results = []
    matched_labs = set()

    # --- Step 3: IMPROVED medication filtering ---
    # Only filter out lines that are PURELY about medications
    strong_medication_patterns = [
        r'^\s*\b(?:CONTINUE|HOLD|START)\b.*\b(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
        r'^\s*.*\b\d+\s*(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
    ]
    
    # Process line by line with GENTLE filtering
    lines = input_str_normalized.split('\n')
    filtered_lines = []
    
    for line in lines:
        line = line.strip()
        if not line:
            continue
        
        # Only exclude lines that are STRONGLY medication-only
        is_pure_medication = any(re.search(med_pat, line, re.IGNORECASE) for med_pat in strong_medication_patterns)
        
        if not is_pure_medication:
            filtered_lines.append(line)
    
    # Recombine filtered text
    filtered_text = ' '.join(filtered_lines)

    # --- Step 4: Enhanced individual lab matching with EXCLUSIONS ---
    # Exclude common medication terms from being detected as labs
    exclusion_terms = ['MG', 'MCG', 'TABLET', 'CAPSULE', 'TAB', 'PO', 'IV', 'BID', 'TID', 'QDAY']
    
    # NEW ADDITION — Exclude sodium/glucose mentions in context
    diet_context_patterns = [
        r'\bLOW\s+SODIUM\s+DIET\b',
        r'\bLOW\s*:\s*(?:SODIUM\s*/\s*DIABETIC|DIABETIC\s*/\s*SODIUM)\s+DIET\b',
        r'\bLOW\s*:\s*(?:SODIUM|DIABETIC)\s+DIET\b'
        r'\bRESTRICTED\s+SODIUM\s+DIET\b',
        r'\bSODIUM\s+RESTRICTION\b',
        r'\bSODIUM\s+INTAKE\b',
        r'\bREPLACE\s+POTASSIUM(?:\s+\w+){0,3}\b',
        r'\bSODIUM\s*/\s*DIABETIC\s+DIET\b',
        r'\bDIABETIC\s*/\s*SODIUM\s+DIET\b'
    ]
    glucose_monitor_patterns = [
        r'\bMONITOR\s+BLOOD\s+GLUCOSE\b',
        r'\bMONITOR\s+GLUCOSE\s+LEVELS?\b',
        r'\bCHECK\s+BLOOD\s+GLUCOSE\b',
        r'\bCHECK\s+GLUCOSE\s+LEVELS?\b',
        r'\bCHECK\s+BLOOD\s+GLUCOSE\s+(?:\d+\s*(?:TIMES\s*)?|\bTWICE\b|\bONCE\b|\bTHRICE\b)?\s*(?:DAILY|A\s*DAY)\b'
    ]

    sodium_diet_context = any(re.search(pat, filtered_text) for pat in diet_context_patterns)
    glucose_monitor_context = any(re.search(pat, filtered_text) for pat in glucose_monitor_patterns)
    
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_normalized = re.sub(r'[-\s]+', ' ', lab_name.upper())
        
        # Skip if this lab name is in our exclusion list
        if lab_name_normalized in exclusion_terms:
            continue

        # Skip sodium if in diet context
        if sodium_diet_context and lab_name_normalized == "SODIUM" or lab_name_normalized == "NA":
            continue
                          
        # Use word boundaries with normalized strings
        if re.search(r'\b' + re.escape(lab_name_normalized) + r'\b', filtered_text):
            matched_labs.add(lab_name)

    
    # --- Step 5: Enhanced pattern matching for common tests ---
    enhanced_order_patterns = [
        # Imaging studies - BROADER PATTERNS
        (r'\b(?:COMPUTED\s+)?(?:AXIAL\s+)?TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bCT\s+(?:SCAN)?\b', 'CT SCAN'),  # This will match "CT" and "CT SCAN"
        (r'\bCAT\s+SCAN\b', 'CT SCAN'),
        (r'\bAXIAL\s+TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bMRI\b', 'MRI'),
        (r'\b(?:CHEST\s+)?X-?RAY\b', 'CHEST X-RAY'),
        (r'\bULTRASOUND\b', 'ULTRASOUND'),
        (r'\bBLADDER\s+SCAN\b', 'BLADDER SCAN'),
        (r'\bEKG\b', 'EKG'),
        (r'\bECG\b', 'ECG'),

        # Echocardiogram patterns  
        (r'\bECHOCARDIOGRAM\b', 'ECHOCARDIOGRAM'),
        (r'\bECHOCARDIOGRAPHY\b', 'ECHOCARDIOGRAM'),
        (r'\bCARDIAC\s+ECHO\b', 'ECHOCARDIOGRAM'),
        (r'\bHEART\s+ULTRASOUND\b', 'ECHOCARDIOGRAM'),
        
        # Urinalysis patterns
        (r'\bURINALYSIS\b', 'URINALYSIS'),
        (r'\bUA\b', 'URINALYSIS'),
        (r'\bURINE\s+ANALYSIS\b', 'URINALYSIS'),
        (r'\bURINE\s+TEST\b', 'URINALYSIS'),
        
        # Culture types - include plural forms
        (r'\bBLOOD\s+CULTURES?\b', 'BLOOD CULTURE'),
        (r'\bURINE\s+CULTURES?\b', 'URINE CULTURE'),
        (r'\bSPUTUM\s+CULTURES?\b', 'SPUTUM CULTURE'),
        (r'\bWOUND\s+CULTURES?\b', 'WOUND CULTURE'),
        
        # Action-oriented patterns for cultures
        (r'\b(?:REPEAT|REPEATED)\s+BLOOD\s+CULTURES?\b', 'BLOOD CULTURE'),
        (r'\b(?:OBTAIN|GET|ORDER|SEND)\s+(?:BLOOD|URINE)\s+CULTURES?\b', 'CULTURE'),
        (r'\bCULTURES?\s+(?:DRAWN|OBTAINED|SENT)\b', 'CULTURE'),
        (r'\bCULTURES?\s+(?:NEGATIVE|POSITIVE)\b', 'CULTURE'),  
        
        # Action-oriented patterns for lab orders
        (r'\bOBTAIN\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bGET\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bORDER\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bNEED\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
    ]
    
    for pattern, test_name in enhanced_order_patterns:
        if re.search(pattern, filtered_text, re.IGNORECASE):
            matched_labs.add(test_name)

    # --- Step 6: IMPROVED DEDUPLICATION AND PRIORITIZATION ---
    # Comprehensive deduplication mapping (primary term -> terms to remove)
    comprehensive_deduplication = {
        # Panel vs components
        # 'COMPLETE BLOOD COUNT': ['WBC', 'RBC', 'HGB', 'HCT', 'PLT', 'PLATELET COUNT'],
        # 'COMPREHENSIVE METABOLIC PANEL': ['GLUCOSE', 'BUN', 'CREATININE', 'CALCIUM', 'SODIUM', 
        #                                 'POTASSIUM', 'CHLORIDE', 'CO2', 'ALBUMIN', 'TOTAL PROTEIN'],
        # 'BASIC METABOLIC PANEL': ['GLUCOSE', 'BUN', 'CREATININE', 'CALCIUM', 'SODIUM', 
        #                         'POTASSIUM', 'CHLORIDE', 'CO2'],
        # 'RENAL FUNCTION PANEL': ['RENAL FUNCTION', 'GFR', 'BUN', 'CREATININE', 'SODIUM', 
        #                     'POTASSIUM', 'CHLORIDE', 'CO2', 'CALCIUM', 'ALBUMIN'],
        'URINALYSIS': ['URINE', 'URINE COLOR', 'URINE APPEARANCE', 'URINE GLUCOSE'],
        
        # Same test different names
        'CALCIUM': ['CA'],
        'ELECTROCARDIOGRAM': ['EKG', 'ECG'],
        'ECHOCARDIOGRAM': ['ECHO'],
        'CHEST X-RAY': ['CXR', 'X-RAY CHEST', 'CHEST 1 VIEW', 'CHEST 2 VIEWS'],
        'X-RAY': ['XR'],
        'MAGNESIUM': ['MG'],
        'POTASSIUM': ['K'],
        'SODIUM': ['NA'],
        'BICARBONATE': ['BICARB', 'CO2', 'CARBON DIOXIDE'],
        'CHLORIDE': ['CL'],
        
        # Specific vs general
        'BLOOD CULTURE': ['CULTURE'],
        'URINE CULTURE': ['CULTURE'],
        'CT SCAN': ['CT', 'COMPUTED TOMOGRAPHY', 'CAT SCAN'],
        'IMAGING STUDY': ['MRI', 'ULTRASOUND', 'X-RAY'],  # Remove if specific imaging found
        'CHEST X-RAY': ['CHEST XRAY', 'CXR', 'X-RAY CHEST', 'CHEST 1 VIEW'],
    }

    # Apply comprehensive deduplication - PREFER PRIMARY TERMS
    filtered_matched_labs = set()
    labs_to_remove = set()
    
    # First pass: identify what needs to be removed
    for lab in matched_labs:
        for primary_term, terms_to_remove in comprehensive_deduplication.items():
            if lab in terms_to_remove:
                labs_to_remove.add(lab)
                # Add the primary term if we're removing one of its components
                if primary_term not in labs_to_remove:
                    filtered_matched_labs.add(primary_term)
    
    # Second pass: add labs that weren't marked for removal
    for lab in matched_labs:
        if lab not in labs_to_remove:
            filtered_matched_labs.add(lab)
    
    matched_labs = filtered_matched_labs
    
    # --- Step 7: Check panels (only if ALL labs are present) ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    panels_found = set()
    
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]
        
        panel_labs_normalized = [re.sub(r'[-\s]+', ' ', lab.upper()) for lab in panel_labs]

        if panel_labs and all(re.search(r'\b' + re.escape(lab_norm) + r'\b', filtered_text) for lab_norm in panel_labs_normalized):
            panels_found.add(panel_name)
            # Remove labs that are part of this full panel
            for lab in panel_labs:
                if lab in matched_labs:
                    matched_labs.remove(lab)

    # Remove "IMAGING STUDY" if specific imaging tests are found
    specific_imaging_terms = ['MRI', 'CT SCAN', 'X-RAY', 'CHEST X-RAY', 'ULTRASOUND', 'ECHOCARDIOGRAM']
    if 'IMAGING STUDY' in matched_labs and any(term in matched_labs for term in specific_imaging_terms):
        matched_labs.remove('IMAGING STUDY')
    
    
    # --- Step 8: Add panels and remaining individual labs ---
    for panel in panels_found:
        results.append({"Lab Order": panel})
    
    for lab in matched_labs:
        # Skip if this lab is already covered by a panel
        if not any(lab in comprehensive_deduplication.get(panel, []) for panel in panels_found):
            results.append({"Lab Order": lab})

    # --- Step 9: FINAL CLEANUP - Remove any remaining duplicates ---
    unique_results = []
    seen_labs = set()
    
    for result in results:
        lab_name = result["Lab Order"]
        # Normalize the name for comparison
        normalized_name = re.sub(r'[-\s]+', ' ', lab_name.upper()).strip()
        
        if normalized_name not in seen_labs:
            seen_labs.add(normalized_name)
            unique_results.append(result)

    # --- Step 10: If nothing found ---
    if not unique_results:
        return [{"Lab Order": "No Evidence Found"}]

    return unique_results


def lab_review_nl(lab_str, dos=None):
    
    # --- Step 1: Load databases ---
    lab_df = LAB_DF
    group_test_df = PANEL_DF

    # --- Step 2: Check if lab content has dates ---
    def has_dates(text):
        """Check if text contains date patterns"""
        date_pattern = r'(\d{1,2}/\d{1,2}/\d{2,4}|[A-Za-z]{3}-\d{1,2}-\d{4})'
        return bool(re.search(date_pattern, text))
    
    # --- Step 3: Filter lab content based on date presence ---
    if dos and has_dates(lab_str):
        # If DOS is provided AND content has dates, filter by DOS
        filtered_lab_str = get_lab_content_by_dos(lab_str, dos)
        
    else:
        # If no DOS OR no dates in content, use entire lab content
        filtered_lab_str = lab_str
        
    
    # --- Step 4: Normalize input text ---
    input_str = (filtered_lab_str or "").upper()
    
    results = []
    matched_labs = set()

    # --- Step 5: Enhanced short lab mapping --- #
    short_lab_mapping = {
        'CA': 'CALCIUM', 'K': 'POTASSIUM', 'NA': 'SODIUM', 'MG': 'MAGNESIUM',
        'CL': 'CHLORIDE', 'P': 'PHOSPHORUS', 'FE': 'IRON', 'HGB': 'HEMOGLOBIN',
        'HCT': 'HEMATOCRIT', 'WBC': 'WHITE BLOOD CELL COUNT', 'RBC': 'RED BLOOD CELL COUNT',
        'PLT': 'PLATELET COUNT', 'PLATELETS': 'PLATELET COUNT', 'PT': 'PROTHROMBIN TIME',
        'INR': 'INTERNATIONAL NORMALIZED RATIO', 'BUN': 'BLOOD UREA NITROGEN', 
        'CR': 'CREATININE', 'CREAT': 'CREATININE', 'AST': 'ASPARTATE AMINOTRANSFERASE',
        'ALT': 'ALANINE AMINOTRANSFERASE', 'ALP': 'ALKALINE PHOSPHATASE', 
        'TBIL': 'BILIRUBIN TOTAL', 'BILIRUBIN': 'BILIRUBIN TOTAL', 'TOTAL BILIRUBIN': 'BILIRUBIN TOTAL',
        'ALB': 'ALBUMIN', 'TP': 'TOTAL PROTEIN', 'CO2': 'CARBON DIOXIDE', 'BICARB': 'CARBON DIOXIDE',
        'SGPT': 'ALANINE AMINOTRANSFERASE', 'SGOT': 'ASPARTATE AMINOTRANSFERASE', 'POC BEDSIDE GLUCOSE': 'GLUCOSE', 
    }

    # --- Step 6: Enhanced function to check lab presence ---
    def is_lab_present(lab_name, text):
        """Check if a lab component is present, handling abbreviations and word order variations"""
        lab_upper = lab_name.upper()
        
        # Check exact match first
        if re.search(r'\b' + re.escape(lab_upper) + r'\b', text, re.IGNORECASE):
            return True
        
        # Check abbreviations
        for abbr, full_name in short_lab_mapping.items():
            if full_name == lab_upper:
                if re.search(r'\b' + re.escape(abbr) + r'\b', text, re.IGNORECASE):
                    return True
        
        # Handle word order variations for specific terms
        word_order_variations = {
            'BILIRUBIN TOTAL': [r'TOTAL\s+BILIRUBIN', r'BILIRUBIN,\s*TOTAL'],
        }
        
        if lab_upper in word_order_variations:
            for pattern in word_order_variations[lab_upper]:
                if re.search(pattern, text, re.IGNORECASE):
                    return True
        
        return False

    # --- Step 7: Extract and CLEAN panel definitions from Excel ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    panel_definitions = {}
    
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = []
        
        for col in lab_columns:
            if pd.notna(row[col]):
                # CLEAN the lab name - remove extra spaces
                lab_name = str(row[col]).upper().strip()
                # Fix specific known issues
                if lab_name == 'RED BLOOD CELL COUNT  ':
                    lab_name = 'RED BLOOD CELL COUNT'
                if lab_name:
                    panel_labs.append(lab_name)
        
        if panel_labs:
            panel_definitions[panel_name] = panel_labs

    # --- Step 8: Enhanced Panel Detection ---
    detected_panels = []
    panel_components_found = set()
    
    for panel_name, required_labs in panel_definitions.items():
        all_components_found = True
        
        for lab in required_labs:
            if not is_lab_present(lab, input_str):
                all_components_found = False
                break
        
        if all_components_found:
            detected_panels.append(panel_name)
            # Track all components of this panel to avoid individual detection
            for lab in required_labs:
                panel_components_found.add(lab)
                # Also add abbreviations
                for abbr, full_name in short_lab_mapping.items():
                    if full_name == lab:
                        panel_components_found.add(abbr)

    # --- Step 9: Add detected panels to results ---
    for panel in detected_panels:
        results.append({"Lab Review": panel})

    # --- Step 10: Individual lab detection (ONLY if not part of detected panels) ---
    
        
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_clean = lab_name.upper().strip()
        
        # Skip if this lab is part of a detected panel
        if lab_name_clean in panel_components_found:
            continue
            
        # Check if lab is present in text
        if re.search(r'\b' + re.escape(lab_name_clean) + r'\b', input_str, re.IGNORECASE):
            
            matched_labs.add(lab_name)

    

    # --- Step 11: Add remaining individual labs (EXCLUDE panel components) ---
    
    for lab in matched_labs:
        # Double-check it's not a panel component
        if lab.upper() not in panel_components_found:
            results.append({"Lab Review": lab})
            
    # --- Step 12: Enhanced Imaging and Culture Study Detection ---
    
    imaging_patterns = [
        # Imaging studies (no value required)
        (r'\b(CT\s+SCAN|CT|CAT\s+SCAN)\b', 'CT SCAN'),
        (r'\b(X-?RAY|X\s+RAY|XR\s+CHEST|XR)\b', 'X-RAY'), 
        (r'\b(MRI\s+SCAN|MRI)\b', 'MRI'),
        (r'\b(ULTRASOUND|US)\b', 'ULTRASOUND'),
        (r'\b(?:ECHOCARDIOGRAM|ECHO)\b', 'ECHOCARDIOGRAM'),
        (r'\b(MAMMOGRAM)\b', 'MAMMOGRAM'),
        (r'\b(DOPPLER)\b', 'DOPPLER'),
        (r'\b(FLUOROSCOPY)\b', 'FLUOROSCOPY'),
        (r'\b(ANGIOGRAM)\b', 'ANGIOGRAM'),
    ]
    
    # Culture types (no value required)
    culture_patterns = [
        (r'\b(BLOOD\s+CULTURE)\b', 'BLOOD CULTURE'),
        (r'\b(URINE\s+CULTURE)\b', 'URINE CULTURE'),
        (r'\b(SPUTUM\s+CULTURE)\b', 'SPUTUM CULTURE'),
        (r'\b(WOUND\s+CULTURE)\b', 'WOUND CULTURE'),
        (r'\b(AEROBIC\s+CULTURE)\b', 'AEROBIC CULTURE'),
        (r'\b(ANAEROBIC\s+CULTURE)\b', 'ANAEROBIC CULTURE'),
    ]
    
    # Add imaging and culture tests (they don't need values)
    for pattern, test_name in imaging_patterns + culture_patterns:
        if re.search(pattern, input_str, re.IGNORECASE):
            results.append({"Lab Review": test_name})
    

    # --- Step 13: Final cleanup and deduplication ---
    
    # Define what components are part of which panels
    panel_components = {
        'COMPLETE BLOOD COUNT': ['WBC', 'RBC', 'HGB', 'HCT', 'PLT', 'PLATELET COUNT', 
                                'WHITE BLOOD CELL COUNT', 'RED BLOOD CELL COUNT', 'HEMOGLOBIN', 
                                'HEMATOCRIT', 'MCV', 'MCH', 'MCHC', 'RDW', 'MPV'],
        'BASIC METABOLIC PANEL': ['NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
                                 'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
                                 'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM'],
        'COMPREHENSIVE METABOLIC PANEL': ['NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
                                         'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
                                         'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM', 'ALBUMIN', 
                                         'TOTAL PROTEIN', 'ALKALINE PHOSPHATASE', 'ALANINE AMINOTRANSFERASE', 
                                         'ASPARTATE AMINOTRANSFERASE', 'BILIRUBIN TOTAL', 'ALT', 'AST', 'SGPT',
                                         'ALKALINE', 'PHOSPHATASE', 'TBIL', 'BILIRUBIN'],
        'ELECTROLYTE PANEL': ['NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
                             'CO2', 'CARBON DIOXIDE', 'BICARB'],
        'HEPATIC FUNCTION PANEL': ['ALBUMIN', 'TOTAL PROTEIN', 'BILIRUBIN TOTAL', 
                                  'ALKALINE PHOSPHATASE', 'ALANINE AMINOTRANSFERASE', 
                                  'ASPARTATE AMINOTRANSFERASE', 'ALT', 'AST', 'SGPT',
                                  'ALKALINE', 'PHOSPHATASE', 'TBIL', 'BILIRUBIN'],
        'RENAL FUNCTION PANEL': ['NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
                                'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
                                'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM', 'ALBUMIN', 'PHOSPHORUS'],
        'LIPID PANEL': ['CHOLESTEROL', 'TRIGLYCERIDES', 'HDL CHOLESTEROL', 'LDL CHOLESTEROL'],
        'URINALYSIS': ['URINE COLOR', 'URINE APPEARANCE', 'URINE GLUCOSE', 'URINE BILIRUBIN', 
                      'URINE BLOOD', 'URINE PROTEIN', 'URINE NITRITE', 'URINE LEUKOCYTES', 
                      'URINE SPECIFIC GRAVITY', 'URINE PH', 'UROBILINOGEN', 'URINE']
    }
    
    # Define equivalence mapping to avoid duplicates
    equivalence_map = {
        "CBC": "COMPLETE BLOOD COUNT",
        "BMP": "BASIC METABOLIC PANEL", 
        "CMP": "COMPREHENSIVE METABOLIC PANEL",
        "LFT": "LIVER FUNCTION TESTS",
        "RFT": "RENAL FUNCTION TESTS",
        "HEPATIC FUNCTION PANEL": "LIVER FUNCTION TESTS",
        "XR CHEST": "X-RAY",
        "XR": "X-RAY",
        "PT INR": "INTERNATIONAL NORMALIZED RATIO",
        "PROTIME": "PROTHROMBIN TIME",
        "PTT": "PARTIAL THROMBOPLASTIN TIME",
        "APTT": "PARTIAL THROMBOPLASTIN TIME",
        "ALKALINE": "ALKALINE PHOSPHATASE",
        "PHOSPHATASE": "ALKALINE PHOSPHATASE",
        "SGPT": "ALANINE AMINOTRANSFERASE",
        "SGOT": "ASPARTATE AMINOTRANSFERASE"
    }
    
    # Add short lab mappings to equivalence map
    equivalence_map.update(short_lab_mapping)
    
    # Clean up the results
    cleaned_results = []
    seen_items = set()
    
    for entry in results:
        item = entry["Lab Review"].upper().strip()
        
        # Convert equivalents to standard names
        normalized_item = equivalence_map.get(item, item)
        
        # Skip if we've already seen this (or its equivalent)
        if normalized_item not in seen_items:
            seen_items.add(normalized_item)
            cleaned_results.append({"Lab Review": normalized_item})
    
    
    # --- Step 14: Final comprehensive cleanup ---
    
    
    final_results = []
    
    # Define panel groups (consolidate equivalent panels)
    panel_groups = {
        'LIVER FUNCTION TESTS': ['HEPATIC FUNCTION PANEL', 'LFT'],
        'COMPREHENSIVE METABOLIC PANEL': ['CMP'],
        'COMPLETE BLOOD COUNT': ['CBC'],
        'BASIC METABOLIC PANEL': ['BMP']
    }
    
    # Define components that should NEVER appear individually (always part of panels)
    always_panel_components = {
        'URINALYSIS': ['URINE COLOR', 'URINE APPEARANCE', 'URINE GLUCOSE', 'URINE BILIRUBIN', 
                    'URINE BLOOD', 'URINE PROTEIN', 'URINE NITRITE', 'URINE LEUKOCYTES', 
                    'URINE SPECIFIC GRAVITY', 'URINE PH', 'UROBILINOGEN', 'URINE', 'PH'],
        'COMPLETE BLOOD COUNT': ['WBC', 'RBC', 'HGB', 'HCT', 'PLT', 'PLATELET COUNT', 
                                'WHITE BLOOD CELL COUNT', 'RED BLOOD CELL COUNT', 'HEMOGLOBIN', 
                                'HEMATOCRIT', 'MCV', 'MCH', 'MCHC', 'RDW', 'MPV'],
        'COMPREHENSIVE METABOLIC PANEL': ['NA', 'SODIUM', 'K', 'POTASSIUM', 'CL', 'CHLORIDE', 
                                        'CO2', 'CARBON DIOXIDE', 'BUN', 'BLOOD UREA NITROGEN', 
                                        'CREATININE', 'GLUCOSE', 'CA', 'CALCIUM', 'ALBUMIN', 
                                        'TOTAL PROTEIN', 'ALKALINE PHOSPHATASE', 'ALANINE AMINOTRANSFERASE', 
                                        'ASPARTATE AMINOTRANSFERASE', 'BILIRUBIN TOTAL', 'ALT', 'AST', 'SGPT',
                                        'ALKALINE', 'PHOSPHATASE', 'TBIL', 'BILIRUBIN'],
    }
    
    # Always keep these categories (never remove them)
    always_keep_categories = [
        # Imaging tests
        'CT SCAN', 'X-RAY', 'MRI', 'ULTRASOUND', 'ECHOCARDIOGRAM',
        # Individual tests that are never part of panels
        'TROPONIN', 'LIPASE', 'HCG', 'MAGNESIUM',
        # Coagulation tests (they're individual tests, not panels)
        'INTERNATIONAL NORMALIZED RATIO', 'PROTHROMBIN TIME', 'PARTIAL THROMBOPLASTIN TIME'
    ]
    
    # Track which panels we've actually included
    included_panels = set()
    
    for entry in cleaned_results:
        item = entry["Lab Review"].upper()
        should_include = True
        
        # Always keep specific individual tests
        if item in always_keep_categories:
            should_include = True
        else:
            # Handle panel grouping - only include one from each group
            for primary_panel, equivalent_panels in panel_groups.items():
                if item in equivalent_panels:
                    # Only include if we haven't included the primary panel yet
                    if primary_panel not in included_panels:
                        # Replace with primary panel name
                        entry["Lab Review"] = primary_panel
                        included_panels.add(primary_panel)
                    else:
                        should_include = False
                    break
                elif item == primary_panel:
                    if item not in included_panels:
                        included_panels.add(item)
                    else:
                        should_include = False
                    break
            
            # If not a panel, check if it's a component that should NEVER appear individually
            if should_include:
                for panel_name, components in always_panel_components.items():
                    if item in components:
                        should_include = False
                        break
        
        if should_include:
            final_results.append(entry)
    
    # --- Step 14: Final comprehensive cleanup ---
    #print(f"DEBUG: Before comprehensive cleanup, results: {results}")

    # Remove CT duplicate + exact duplicates + handle common equivalents
    final_cleaned_results = []
    ct_scan_found = any(entry["Lab Review"] == "CT SCAN" for entry in results)
    seen = set()

    # Quick equivalents fix(remove the "CBC", "BMP" as duplicate from result)
    equivalents = {'CBC': 'COMPLETE BLOOD COUNT', 'BMP': 'BASIC METABOLIC PANEL'}

    for entry in results:
        lab_name = entry["Lab Review"]
        
        # Skip CT if CT SCAN is present
        if lab_name == "CT" and ct_scan_found:
            continue
        
        # Handle common equivalents
        normalized_name = equivalents.get(lab_name, lab_name)
        
        # Skip duplicates
        if normalized_name not in seen:
            seen.add(normalized_name)
            final_cleaned_results.append({"Lab Review": normalized_name})

    if not final_cleaned_results:
        return [{"Lab Review": "No Evidence Found"}]

    return final_cleaned_results
  
def discussion_management_nl(assessment_str, lab_str, hospitalcourse_str, consultation_str, Code_status_str):
    """
    Handles consultation detection using consultation_str (row-specific)
    and fallback discussion-management logic using assessment/lab/hospitalcourse.
    """

    results = []

    # ---------------------------------------------------------
    #  GLOBAL MEDICAL DEPARTMENT DICTIONARY (AVAILABLE EVERYWHERE)
    # ---------------------------------------------------------
    medical_departments = {
        'CARDIOLOGY': ['CARDIOLOGY', 'CARDIAC', 'CARDIO', 'CV', 'CARDIOLOGIST'],
        'NEUROLOGY': ['NEUROLOGY', 'NEURO', 'NEUROLOGICAL', 'NEUROLOGIST'],
        'ONCOLOGY': ['ONCOLOGY', 'ONCO', 'CANCER', 'ONCOLOGIST', 'HEMATOLOGY/ONCOLOGY'],
        'PULMONOLOGY': ['PULMONOLOGY', 'PULMONARY', 'PULM', 'RESPIRATORY', 'CHEST', 'PULMONOLOGIST'],
        'GASTROENTEROLOGY': ['GASTROENTEROLOGY', 'GASTRO', 'GI', 'GASTROINTESTINAL', 'GASTROENTEROLOGIST'],
        'NEPHROLOGY': ['NEPHROLOGY', 'NEPHRO', 'RENAL', 'NEPHROLOGIST'],
        'INFECTIOUS_DISEASE': ['INFECTIOUS DISEASE', 'INFECTIOUS', 'ID', 'INFECTIOUS DISEASE SPECIALIST'],
        'UROLOGY': ['UROLOGY', 'URO', 'UROLOGICAL', 'UROLOGIST'],
        'HEMATOLOGY': ['HEMATOLOGY', 'HEME', 'BLOOD', 'HEMATOLOGIST'],
        'ENDOCRINOLOGY': ['ENDOCRINOLOGY', 'ENDO', 'ENDOCRINE', 'ENDOCRINOLOGIST'],
        'RHEUMATOLOGY': ['RHEUMATOLOGY', 'RHEUM', 'RHEUMATOLOGICAL', 'RHEUMATOLOGIST'],
        'DERMATOLOGY': ['DERMATOLOGY', 'DERM', 'DERMATOLOGIST'],
        'ORTHOPEDICS': ['ORTHOPEDICS', 'ORTHO', 'ORTHOPEDIC', 'ORTHOPEDIST'],
        'PHYSICAL_THERAPY': ['PHYSICAL THERAPY', 'PT', 'PHYSICAL THERAPIST'],
        'OCCUPATIONAL_THERAPY': ['OCCUPATIONAL THERAPY', 'OT', 'OCCUPATIONAL THERAPIST'],
        'SPEECH_THERAPY': ['SPEECH THERAPY', 'SPEECH', 'ST', 'SLP', 'SPEECH PATHOLOGIST'],
        'RESPIRATORY_THERAPY': ['RESPIRATORY THERAPY', 'RT', 'RESPIRATORY THERAPIST'],
        'PSYCHIATRY': ['PSYCHIATRY', 'PSYCH', 'PSYCHIATRIC', 'PSYCHIATRIST'],
        'SOCIAL_WORK': ['SOCIAL WORK', 'SOCIAL WORKER', 'SOCIAL SERVICES'],
        'CASE_MANAGEMENT': ['CASE MANAGEMENT', 'CASE MANAGER'],
        'CARE_MANAGEMENT': ['CARE MANAGEMENT', 'CONSULT TO CARE'],
        'CRITICAL_CARE': ['CRITICAL CARE', 'ICU', 'INTENSIVE CARE'],
        'PALLIATIVE_CARE': ['PALLIATIVE CARE', 'PALLIATIVE', 'PALLIATIVE MEDICINE'],
        'GYNAECOLOGY': ['GYNAECOLOGY', 'GYN', 'GYNECOLOGY'],
        'SURGERY': ['SURGERY', 'SURGICAL', 'GENERAL SURGERY', 'SURGEON'],
        'NEUROSURGERY': ['NEUROSURGERY', 'NEUROSURGICAL', 'NEUROSURGEON'],
        'CARDIOTHORACIC_SURGERY': ['CARDIOTHORACIC', 'CT SURGERY', 'CARDIAC SURGERY', 'THORACIC SURGERY'],
        'PLASTIC_SURGERY': ['PLASTIC SURGERY', 'PLASTIC SURGICAL', 'PLASTIC SURGEON'],
        'VASCULAR_SURGERY': ['VASCULAR SURGERY', 'VASCULAR SURGICAL', 'VASCULAR SURGEON'],
    }

    # ---------------------------------------------------------
    # Helper: Identify department
    # ---------------------------------------------------------
    def find_medical_department(text):
        text_upper = text.upper().strip()

        pt_ot_combos = ['PT/OT', 'OT/PT', 'PT OT', 'OT PT', 'PT OT ST', 'PT/OT/ST']
        for combo in pt_ot_combos:
            if combo in text_upper:
                return "PT/OT"

        for main_dept, variations in medical_departments.items():
            for var in variations:
                if re.search(r'\b' + re.escape(var) + r'\b', text_upper):
                    return main_dept.replace("_", " ")

        return None

    # ---------------------------------------------------------
    # STEP 1 — PROCESS CONSULTATION_STR ONLY
    # ---------------------------------------------------------
    try:

        raw_consultation_terms = []
        if consultation_str and pd.notna(consultation_str) and str(consultation_str).strip():
            raw_consultation_terms = [str(consultation_str)]

        clean_consultation_terms = []
        seen_terms = set()

        for term in raw_consultation_terms:
            for line in term.split("\n"):
                cleaned = line.strip().upper()

                if not cleaned:
                    continue

                # Remove numeric/page noise
                if re.search(r'\b\d+of\d+\b', cleaned) or "PAGE" in cleaned:
                    continue

                # Remove hospital system names
                noise_list = ["HOSPITALIST", "DISCHARGE SUMMARY", "WESTERN ARIZONA", "REGIONAL MEDICAL", "ONECONTENT"]
                if any(n in cleaned for n in noise_list):
                    continue

                # Remove doctor names
                if re.search(r'\bDR\.?\s+[A-Z]', cleaned):
                    continue

                # Remove quotes
                cleaned = re.sub(r'["\']', '', cleaned)

                # Remove noisy patterns
                noisy_patterns = [
                    r'PATIENT IN THE PROCESS.*',
                    r'EMERGENCY ROOM.*',
                    r'GENERATED BY.*',
                    r'GENERATED ON.*',
                    r'ADMITTED.*',
                ]
                for pat in noisy_patterns:
                    cleaned = re.sub(pat, '', cleaned).strip()

                if len(cleaned) < 3:
                    continue

                dept = find_medical_department(cleaned)
                if dept and dept not in seen_terms:
                    seen_terms.add(dept)
                    clean_consultation_terms.append(dept)

        for d in clean_consultation_terms:
            results.append(f"{d} CONSULTED")

    except Exception:
        import traceback
        traceback.print_exc()

    # ---------------------------------------------------------
    # STEP 2 – APPLY DISCUSSION MANAGEMENT LOGIC
    # ---------------------------------------------------------
    if not results:

        # Merge text
        input_str = " ".join(filter(None, [assessment_str, lab_str, hospitalcourse_str, Code_status_str]))
        input_str = re.sub(r'^[\s.]|[\s.]$', '', input_str)

        # Remove exclusion patterns
        exclusion_regex = r'''
            (?ix)
            CONSULTANTS?\s*[:-]?\s*NOT
            |CONSULT\s+TO\s+TELE\s+PULMONOLOGY
            |DISCUSS\s+WITH\s+[A-Z]+\s+TOMORROW
            |WILL\s+NEED\s+[A-Z]+\s+CONSULT
            |CONSULTATIONS?\s*[:\-]{2}\s*NO\s+(?:ADDITIONAL\s+)?CONSULTS?
        '''
        input_str = re.sub(exclusion_regex, '', input_str, flags=re.IGNORECASE | re.VERBOSE)

        # -------- CONSULT PATTERNS --------
        consult_patterns = [
            r'CONSULT(?:ED)?\s+([A-Z][A-Za-z\s\/]+)',
            r'([A-Z][A-Za-z\s\/]+)\s+CONSULTED',
            r'CONSULTATION\s+WITH\s+([A-Z][A-Za-z\s\/]+)',
        ]

        for pat in consult_patterns:
            for m in re.finditer(pat, input_str, flags=re.IGNORECASE):
                dept = find_medical_department(m.group(1))
                if dept:
                    res = f"CONSULTED {dept}"
                    if res not in results:
                        results.append(res)

        # -------- DISCUSS PATTERNS --------
        discuss_patterns = [
            r'DISCUSS(?:ED)?\s+WITH\s+([A-Z][A-Za-z\s\/]+)',
            r'SPOKE\s+WITH\s+([A-Z][A-Za-z\s\/]+)',
        ]

        for pat in discuss_patterns:
            for m in re.finditer(pat, input_str, flags=re.IGNORECASE):
                dept = find_medical_department(m.group(1))
                if dept:
                    res = f"DISCUSSED WITH {dept}"
                    if res not in results:
                        results.append(res)

    if not results:
        results = ["No Evidence Found"]

    return [{"Discussed Management": results}]


def independent_historian_nl(assessment_str, hpi_str):
    # --- Step 1: Combine safely with spacing ---
    input_str = " ".join(filter(None, [assessment_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str).upper()

    # ===== FIXED: CLEAR SEPARATION BETWEEN MEDICAL vs NON-MEDICAL SOURCES =====
    
    # --- NON-MEDICAL relation keywords (family/friends/caregivers) ---
    non_medical_relations = ["PARENT", "GUARDIAN", "SPOUSE", "HUSBAND", "WIFE", "SON", "DAUGHTER", "FAMILY",
                            "FAMILY MEMBER", "RELATIVE", "BROTHER", "SISTER", "UNCLE", "AUNT",
                            "GRANDMOTHER", "GRANDFATHER", "FRIEND", "NEIGHBOR", "CAREGIVER",
                            "EMPLOYER", "WITNESS", "LEGAL GUARDIAN", "SURROGATE DECISION-MAKER",
                            "SIGNIFICANT OTHER", "PARTNER", "BOYFRIEND", "GIRLFRIEND"]
    
    # --- MEDICAL PROFESSIONALS (EXCLUDE THESE) ---
    medical_professionals = ["NURSE", "PHYSICIAN", "DOCTOR", "DR", "MD", "DO", "NP", "PA", 
                            "PHYSICIAN ASSISTANT", "CLINICAL STAFF", "EMS PERSONNEL", "EMT", 
                            "PARAMEDIC", "CASE MANAGER", "SOCIAL WORKER", "THERAPIST",
                            "RESPIRATORY THERAPIST", "PHARMACIST", "DIETITIAN"]
    
    # --- Action keywords ---
    action_keywords = ["REPORTED", "STATED", "TOLD", "MENTIONED", "INFORMED", "SAID",
                      "PROVIDED BY", "GIVEN BY", "OBTAINED FROM", "HISTORY TAKEN FROM",
                      "HISTORY PROVIDED BY", "OBSERVED BY", "DOCUMENTED BY", "COLLECTED FROM"]

    # --- Step 4: IMPROVED Phrase patterns (NON-MEDICAL ONLY) ---
    phrase_patterns = [
        r"(?i)\bINDEPENDENT HISTORIAN\b",
        r"(?i)\bHISTORY PROVIDED BY\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bHISTORY TAKEN FROM\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bOBTAINED FROM\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bINFORMATION GIVEN BY\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bVERIFIED BY\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bALL HISTORY (?:OBTAINED|PROVIDED) FROM\s+(?:{})\b".format("|".join(non_medical_relations)),
        r"(?i)\bUNABLE TO PROVIDE HISTORY.*?(?:OBTAINED|FROM)\s+(?:{})\b".format("|".join(non_medical_relations)),
    ]

    # --- NEW: Clear exclusion patterns for medical professionals ---
    exclusion_patterns = [
        r"(?i)\b(?:HISTORY|INFORMATION).*?(?:{})\b".format("|".join(medical_professionals)),
        r"(?i)\b(?:OBTAINED|PROVIDED).*?(?:{})\b".format("|".join(medical_professionals)),
    ]

    # --- Step 6: Split into sentences ---
    threshold = 90
    temp_chunks = []
    buffer = ""

    for part in input_str.split("\n"):
        if buffer and len(buffer.strip()) <= threshold:
            temp_chunks.append(buffer.strip())
            buffer = part
        else:
            if buffer:
                buffer += " " + part
            else:
                buffer = part
    if buffer.strip():
        temp_chunks.append(buffer.strip())

    sentences = []
    for chunk in temp_chunks:
        pieces = [s.strip() for s in re.split(r'[.;!]', chunk) if s.strip()]
        sentences.extend(pieces)

    results = []

    # --- Step 7: IMPROVED sentence checking ---
    for i, sentence in enumerate(sentences):
        # FIRST: Check if this sentence contains MEDICAL professionals (EXCLUDE)
        contains_medical = any(re.search(pattern, sentence) for pattern in exclusion_patterns)
        if contains_medical:
            continue  # Skip medical professional references
        
        # SECOND: Check for clear independent historian patterns
        found_clear_pattern = any(re.search(pattern, sentence) for pattern in phrase_patterns)
        if found_clear_pattern:
            # Extract the specific relationship if mentioned
            for relation in non_medical_relations:
                if relation in sentence:
                    results.append(f"HISTORY FROM {relation}")
                    break
            else:
                results.append("INDEPENDENT HISTORIAN USED")
            continue
        
        # THIRD: Check for relation + action combination (NON-MEDICAL ONLY)
        words = sentence.split()
        found_relation = any(relation in words for relation in non_medical_relations)
        found_action = any(action in sentence for action in action_keywords)
        
        if found_relation and found_action:
            # Extract the specific non-medical relationship
            for relation in non_medical_relations:
                if relation in sentence:
                    results.append(f"HISTORY FROM {relation}")
                    break

    # --- Step 8: Return CLEAN results ---
    if results:
        # Remove duplicates and take the most specific one
        unique_results = []
        seen = set()
        for result in results:
            if result not in seen:
                seen.add(result)
                unique_results.append(result)
        
        # If multiple, prefer the most specific one
        if len(unique_results) > 1:
            # Look for the most specific relationship mentioned
            specific_results = [r for r in unique_results if any(rel in r for rel in non_medical_relations)]
            if specific_results:
                unique_results = [specific_results[0]]
        
        return [{"Independent Historian": unique_results[0]}]
    else:
        return [{"Independent Historian": "No Evidence Found"}]

def process_row_nl(row, config):
    """
    Process a single row for facility NL.
    Expects the following helper functions to be defined:
        review_prior_external_notes_nl(lab_str, assessment_str, hpi_str, Critical_care_time_str, Code_status_str)
        independent_interpretation_nl(lab_str, assessment_str, hpi_str, hospitalcourse_str, Code_status_str)
        discussion_management_nl(assessment_str, lab_str, hospitalcourse_str, consultation_str, Code_status_str)
        lab_order_nl(assessment_str)
        lab_review_nl(lab_str, dos=None)
        independent_historian_nl(assessment_str, hpi_str)
    """
    # --- Run helper functions (order matches notebook's compute_mdm2_details) ---
    discussion = discussion_management_nl(
        row["assessment_str"], row["lab_str"], row["hospitalcourse_str"],
        row["consultation_str"], row["Code_status_str"]
    )
    interpretation = independent_interpretation_nl(
        row["lab_str"], row["assessment_str"], row["hpi_str"],
        row["hospitalcourse_str"], row["Code_status_str"]
    )
    prior_review = review_prior_external_notes_nl(
        row["lab_str"], row["assessment_str"], row["hpi_str"],
        row["Critical_care_time_str"], row["Code_status_str"]
    )
    lab_orders = lab_order_nl(row["assessment_str"])
    lab_review_result = lab_review_nl(row["lab_str"], row["DOS"])
    historian = independent_historian_nl(row["assessment_str"], row["hpi_str"])

    # --- Run MDM2 logic (uses utils.Process_MDM2) ---
    from utils import Process_MDM2, flatten_list_of_dicts, simplify_list_of_dicts
    mdm2_level, label, reasons = Process_MDM2(
        discussion, interpretation, prior_review,
        lab_orders, lab_review_result, historian
    )

    # --- Flatten results for the REASONS column ---
    prior_review_vals = flatten_list_of_dicts(prior_review, "Prior Review")
    lab_orders_simple = simplify_list_of_dicts(lab_orders, "Lab Order")
    lab_review_simple = simplify_list_of_dicts(lab_review_result, "Lab Review")
    discussion_vals = flatten_list_of_dicts(discussion, "Discussed Management")
    interpretation_vals = flatten_list_of_dicts(interpretation, "Independent Interpretation")
    historian_vals = flatten_list_of_dicts(historian, "Independent Historian")

    details_parts = [
        f"Review Prior Notes> {prior_review_vals or ['No Evidence Found']}",
        f"Lab Order> {lab_orders_simple or ['No Evidence Found']}",
        f"Lab Review> {lab_review_simple or ['No Evidence Found']}",
        f"Discussion Management/Test> {discussion_vals or ['No Evidence Found']}",
        f"Independent Interpretation> {interpretation_vals or ['No Evidence Found']}",
        f"Independent Historian> {historian_vals or ['No Evidence Found']}"
    ]
    details = "~".join(details_parts)

    # --- Build reference text (selected sections) ---
    def safe_text(value):
        return str(value).replace(";", ",").strip()

    sections = []
    if row.get("assessment_str"):
        sections.append(f"[Assessment]: {safe_text(row['assessment_str'])}")
    if row.get("hpi_str"):
        sections.append(f"[HPI]: {safe_text(row['hpi_str'])}")
    if row.get("hospitalcourse_str"):
        sections.append(f"[Hospital Course]: {safe_text(row['hospitalcourse_str'])}")
    if row.get("lab_str"):
        sections.append(f"[Lab]: {safe_text(row['lab_str'])}")
    if row.get("objective_str"):
        sections.append(f"[Objective]: {safe_text(row['objective_str'])}")
    if row.get("consultation_str"):
        sections.append(f"[Consultation]: {safe_text(row['consultation_str'])}")
    combined_text = " ~ ".join(sections).replace("\n", " ").strip()

    # --- Extract Chart ID (remove prefix and extension) ---
    chart = row["Filename"].replace("NL_", "").replace(".TIF", "")

    # --- Return Series with expected column names (include Sr No) ---
    return pd.Series({
        "Sr No": row["Sr No"],
        "Filename": row["Filename"],
        "Chart": chart,
        "DOS": row["DOS"],
        "Visit": row["Visit"],
        "Visit Time": row["Visit_time"],
        "MDM2_Level": label.upper(),
        "REASONS FOR MDM2": details,
        "REFERENCE TEXT MDM2": combined_text,
        "Page No": row["Page_No"]
    })

