def review_prior_external_notes_olgmc(lab_str, assessment_str, hpi_str, MD_Addendum_str):
    # --- Step 1: Combine inputs safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str, MD_Addendum_str]))
    lab_text = input_str.upper().strip()
    
    # --- ADD THIS NEW FUNCTION HERE ---
    def fix_incomplete_words(text):
        """Fix incomplete medical terms before processing"""
        fixes = {
            # EKG/ECG related
            r'\bKG\s+REVIEW\b': 'EKG REVIEW',
            r'\bG\s+REVIEWE\b': 'EKG REVIEW', 
            r'\bG\s+REVIEWED\b': 'EKG REVIEW',
            r'\bEKG\s+REVIE\b': 'EKG REVIEW',
            r'\bEKG\s+READ\s+BY\s+ME\b': 'EKG REVIEWED BY ME',
            r'\bREVIEWED\s+BOTH\s+EKGS\b': 'REVIEWED BOTH EKGS',
            
            # Radiology related
            r'\bOLOGY:\s+REVIEWED\b': 'RADIOLOGY REVIEWED',
            r'\bI\s+HAVE\s+REVIEWED\s+IMAGING\b': 'IMAGING REVIEWED',
            r'\bI\s+HAVE\s+REVIEWED\s+LABS\b': 'LABS REVIEWED',
            
            # ECG related (alternative to EKG)
            r'\bECG:\s+REVIEWED\b': 'ECG REVIEWED',
            r'\bCG:\s+REVIEWED\b': 'ECG REVIEWED',
            
            # General fixes
            r'\bMAGING\b': 'IMAGING',  # Fix typo
            r'\bRELEVANT\s+LABS,\s+MAGING\b': 'RELEVANT LABS, IMAGING',
        }
        
        fixed_text = text
        for pattern, replacement in fixes.items():
            fixed_text = re.sub(pattern, replacement, fixed_text)
        
        return fixed_text
    
    # Apply the fixes to the text BEFORE processing
    lab_text = fix_incomplete_words(lab_text)
    
    # --- Step 2: Keywords indicating external notes review ---
    keywords = [
        "PRIOR EXTERNAL NOTES", "EXTERNAL PROVIDER NOTES", "OUTSIDE RECORDS",
        "OUTSIDE NOTES", "REVIEWED PRIOR NOTES", "REVIEWED OUTSIDE NOTES",
        "REVIEWED PCP NOTES", "REVIEWED CONSULT NOTES", "REVIEWED SPECIALIST NOTES",
        "PREVIOUS RECORDS REVIEWED", "EXTERNAL RECORDS REVIEWED", 
        "EXTERNAL DOCUMENTS REVIEWED", "ED REVIEWED", "I HAVE REVIEWED IMAGING", "ECG REVIEWED BY"
        "I REVIEWED RELEVANT LABS, IMAGING AND PRIOR RECORDS", "REVIEWED AND AGREE WITH THE ABOVE FINDINGS", "REVIEWED BY NEUROLOGY", "REVIEWED BY ME",
        "ECG: REVIEWED", "CG: REVIEWED", "LABS AND THE IMAGES REVIEWED AND CONSIDERED IN THE EVALUATION OF PATIENT" , 
        "LABS AND IMAGES REVIEWED AND CONSIDERED IN THE EVALUATION OF PATIENT",
        "I REVIEWED RELEVANT LABS, MAGING AND PRIOR RECORDS AND UPDATED HOME MEDICATION RECONCILIATION", "KG REVIEW", "EKG READ BY ME", "G REVIEWE",
        "REVIEWED BOTH EKGS", "G REVIEWED", "MRI REVIEWED", "EKG REVIE", "OLOGY: REVIEWED",
        "EKG REVIEW", "RADIOLOGY REVIEWED", "IMAGING REVIEWED", "ECG REVIEWED", 
        "I HAVE PERSONALLY REVIEWED THE LABS AND TEST RESULTS THAT ARE PRESENTLY AVAILABLE",
        "I HAVE PERSONALLY REVIEWED THE IMAGES AND AGREE WITH RADIOLOGIST REPORT",
        "I HAVE PERSONALLY REVIEWED THE FOLLOWING IMAGING AND AGREE WITH RADIOLOGIST",
        "I HAVE PERSONALLY REVIEWED THE FOLLOWING IMAGING AND AGREE WITH THE RADIOLOGIST",
        "IH HAVE PERSONALLY REVIEWED THE FOLLOWING IMAGING AND AGREE WITH THE RADIOLOGIST",
        "IH HAVE PERSONALLY REVIEWED THET FOLLOWING IMAGING AND AGREE WITH THE RADIOLOGIST",
        "I HAVE PERSONALLY REVIEWED THET FOLLOWING IMAGING AND AGREE WITH THE RADIOLOGIST",
        "IHAVE PERSONALLY REVIEWED THE FOLLOWING IMAGING AND AGREE WITH THE RADIOLOGIST",
        "HAVE PERSONALLY REVIEWED THE LABS AND TEST RESULTS THAT ARE PRESENTLY AVAILABLE",
        "SIGNIFICANT IMAGING: I HAVE REVIEWED ALL PERTINENT IMAGING RESULTS/FINDINGS WITHIN THE PAST 24 HOURS",
        "SIGNIFICANT MAGING: I HAVE REVIEWED ALL PERTINENT IMAGING RESULTS/FINDINGS WITHIN THE PAST 24 HOURS"
       
    ]
    
    # --- Step 3: Regex patterns for flexible matching ---
    patterns = [
        r"REVIEW(?:ED|ING)?\s+(?:PRIOR|EXTERNAL|OUTSIDE)\s+(?:NOTES|RECORDS)",
        r"NOTES\s+FROM\s+(?:PCP|CARDIOLOGY|RADIOLOGY|ONCOLOGY|NEUROLOGY)",
        r"CONSULT\s+NOTES\s+REVIEW(?:ED|ING)?",
        r"OUTSIDE\s+HOSPITAL\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"PREVIOUS\s+VISIT\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"RADIOLOGICAL\s+(?:IMAGING|STUDIES)\s+REVIEWED\s+BY\s+ME",
        r"ALL\s+RADIOLOGICAL\s+STUDIES\s+HAVE\s+BEEN\s+REVIEWED(?:\s+BY\s+ME)?",
        r"REVIEWED\s+BY\s+ME\s+AND\s+I\s+AGREE\s+WITH\s+RADIOLOG(?:IST|ICAL)\s+READING",
        r"I\s+AGREE\s+WITH\s+THE\s+SUMMARY\s+OF\s+THE\s+RADIOLOGICAL\s+INTERPRETATIONS(?:\s+LISTED\s+BELOW)?"
    ]

    results = []

    # --- Step 4: Exact keyword search ---
    for kw in keywords:
        if kw in lab_text:
            results.append({"Prior Review": kw})

    # --- Step 5: Regex search ---
    for pattern in patterns:
        match = re.search(pattern, lab_text)
        if match:
            results.append({"Prior Review": match.group(0)})

    # --- Step 6: Clean and return results ---
    if results:
        # extract the string part from dicts
        vals = [item["Prior Review"] for item in results]

        # deduplicate while preserving order
        # also keep longest version if multiple similar matches exist
        unique_vals = list(dict.fromkeys(vals))

        # choose the longest match (most complete phrase)
        best_match = max(unique_vals, key=len)

        return [{"Prior Review": best_match}]
    else:
        return [{"Prior Review": "No Evidence Found"}]


def lab_order_olgmc(assessment_str):
    # --- Step 1: Load databases ---
    lab_df = LAB_DF
    group_test_df = PANEL_DF

    # --- Step 2: Normalize input text ---
    input_str = (assessment_str or "").upper()
    # NORMALIZE HYPHENS TO SPACES AND FIX COMMON TYPOS
    input_str_normalized = re.sub(r'[-\s]+', ' ', input_str)
    # Fix common typos in medical terms
    input_str_normalized = re.sub(r'\bAXIALT\b', 'AXIAL', input_str_normalized)
    input_str_normalized = re.sub(r'\bCOMPUTERIZED\b', 'COMPUTED', input_str_normalized)
    input_str_normalized = re.sub(r'\bTOMOGRAPHY:\b', 'TOMOGRAPHY', input_str_normalized)
    
    results = []
    matched_labs = set()

    # --- Step 3: IMPROVED medication filtering ---
    # Only filter out lines that are PURELY about medications
    strong_medication_patterns = [
        r'^\s*\b(?:CONTINUE|HOLD|START)\b.*\b(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
        r'^\s*.*\b\d+\s*(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
    ]
    
    # Process line by line with GENTLE filtering
    lines = input_str_normalized.split('\n')
    filtered_lines = []
    
    for line in lines:
        line = line.strip()
        if not line:
            continue
        
        # Only exclude lines that are STRONGLY medication-only
        is_pure_medication = any(re.search(med_pat, line, re.IGNORECASE) for med_pat in strong_medication_patterns)
        
        if not is_pure_medication:
            filtered_lines.append(line)
    
    # Recombine filtered text
    filtered_text = ' '.join(filtered_lines)

    # --- Step 4: Enhanced individual lab matching with EXCLUSIONS ---
    # Exclude common medication terms from being detected as labs
    exclusion_terms = ['MG', 'MCG', 'TABLET', 'CAPSULE', 'TAB', 'PO', 'IV', 'BID', 'TID', 'QDAY']
    
    # NEW ADDITION — Exclude sodium/glucose mentions in context
    diet_context_patterns = [
        r'\bLOW\s+SODIUM\s+DIET\b',
        r'\bLOW\s*:\s*(?:SODIUM\s*/\s*DIABETIC|DIABETIC\s*/\s*SODIUM)\s+DIET\b',
        r'\bLOW\s*:\s*(?:SODIUM|DIABETIC)\s+DIET\b'
        r'\bRESTRICTED\s+SODIUM\s+DIET\b',
        r'\bSODIUM\s+RESTRICTION\b',
        r'\bSODIUM\s+INTAKE\b',
        r'\bREPLACE\s+POTASSIUM(?:\s+\w+){0,3}\b',
        r'\bSODIUM\s*/\s*DIABETIC\s+DIET\b',
        r'\bDIABETIC\s*/\s*SODIUM\s+DIET\b'
    ]
    glucose_monitor_patterns = [
        r'\bMONITOR\s+BLOOD\s+GLUCOSE\b',
        r'\bMONITOR\s+GLUCOSE\s+LEVELS?\b',
        r'\bCHECK\s+BLOOD\s+GLUCOSE\b',
        r'\bCHECK\s+GLUCOSE\s+LEVELS?\b',
        r'\bCHECK\s+BLOOD\s+GLUCOSE\s+(?:\d+\s*(?:TIMES\s*)?|\bTWICE\b|\bONCE\b|\bTHRICE\b)?\s*(?:DAILY|A\s*DAY)\b'
    ]

    sodium_diet_context = any(re.search(pat, filtered_text) for pat in diet_context_patterns)
    glucose_monitor_context = any(re.search(pat, filtered_text) for pat in glucose_monitor_patterns)
    
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_normalized = re.sub(r'[-\s]+', ' ', lab_name.upper())
        
        # Skip if this lab name is in our exclusion list
        if lab_name_normalized in exclusion_terms:
            continue

        # Skip sodium if in diet context
        if sodium_diet_context and lab_name_normalized == "SODIUM" or lab_name_normalized == "NA":
            continue
                          
        # Use word boundaries with normalized strings
        if re.search(r'\b' + re.escape(lab_name_normalized) + r'\b', filtered_text):
            matched_labs.add(lab_name)

    
    # --- Step 5: Enhanced pattern matching for common tests ---
    enhanced_order_patterns = [
        # Imaging studies - BROADER PATTERNS
        (r'\b(?:COMPUTED\s+)?(?:AXIAL\s+)?TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bCT\s+(?:SCAN)?\b', 'CT SCAN'),  # This will match "CT" and "CT SCAN"
        (r'\bCAT\s+SCAN\b', 'CT SCAN'),
        (r'\bAXIAL\s+TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bMRI\b', 'MRI'),
        (r'\b(?:CHEST\s+)?X-?RAY\b', 'CHEST X-RAY'),
        (r'\bULTRASOUND\b', 'ULTRASOUND'),
        (r'\bBLADDER\s+SCAN\b', 'BLADDER SCAN'),
        (r'\bEKG\b', 'EKG'),
        (r'\bECG\b', 'ECG'),

        # Echocardiogram patterns  
        (r'\bECHOCARDIOGRAM\b', 'ECHOCARDIOGRAM'),
        (r'\bECHOCARDIOGRAPHY\b', 'ECHOCARDIOGRAM'),
        (r'\bCARDIAC\s+ECHO\b', 'ECHOCARDIOGRAM'),
        (r'\bHEART\s+ULTRASOUND\b', 'ECHOCARDIOGRAM'),
        
        # Urinalysis patterns
        (r'\bURINALYSIS\b', 'URINALYSIS'),
        (r'\bUA\b', 'URINALYSIS'),
        (r'\bURINE\s+ANALYSIS\b', 'URINALYSIS'),
        (r'\bURINE\s+TEST\b', 'URINALYSIS'),
        
        # Culture types - include plural forms
        (r'\bBLOOD\s+CULTURES?\b', 'BLOOD CULTURE'),
        (r'\bURINE\s+CULTURES?\b', 'URINE CULTURE'),
        (r'\bSPUTUM\s+CULTURES?\b', 'SPUTUM CULTURE'),
        (r'\bWOUND\s+CULTURES?\b', 'WOUND CULTURE'),
        
        # Action-oriented patterns for cultures
        (r'\b(?:REPEAT|REPEATED)\s+BLOOD\s+CULTURES?\b', 'BLOOD CULTURE'),
        (r'\b(?:OBTAIN|GET|ORDER|SEND)\s+(?:BLOOD|URINE)\s+CULTURES?\b', 'CULTURE'),
        (r'\bCULTURES?\s+(?:DRAWN|OBTAINED|SENT)\b', 'CULTURE'),
        (r'\bCULTURES?\s+(?:NEGATIVE|POSITIVE)\b', 'CULTURE'),  
        
        # Action-oriented patterns for lab orders
        (r'\bOBTAIN\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bGET\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bORDER\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bNEED\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
    ]
    
    for pattern, test_name in enhanced_order_patterns:
        if re.search(pattern, filtered_text, re.IGNORECASE):
            matched_labs.add(test_name)

    # --- Step 6: IMPROVED DEDUPLICATION AND PRIORITIZATION ---
    comprehensive_deduplication = {
        
        'URINALYSIS': ['URINE', 'URINE COLOR', 'URINE APPEARANCE', 'URINE GLUCOSE'],
        
        # Same test different names
        'CALCIUM': ['CA'],
        'ELECTROCARDIOGRAM': ['EKG', 'ECG'],
        'ECHOCARDIOGRAM': ['ECHO'],
        'CHEST X-RAY': ['CXR', 'X-RAY CHEST', 'CHEST 1 VIEW', 'CHEST 2 VIEWS'],
        'X-RAY': ['XR'],
        'MAGNESIUM': ['MG'],
        'POTASSIUM': ['K'],
        'SODIUM': ['NA'],
        'BICARBONATE': ['BICARB', 'CO2', 'CARBON DIOXIDE'],
        'CHLORIDE': ['CL'],
        
        # Specific vs general
        'BLOOD CULTURE': ['CULTURE'],
        'URINE CULTURE': ['CULTURE'],
        'CT SCAN': ['CT', 'COMPUTED TOMOGRAPHY', 'CAT SCAN'],
        'IMAGING STUDY': ['MRI', 'ULTRASOUND', 'X-RAY'],  # Remove if specific imaging found
        'CHEST X-RAY': ['CHEST XRAY', 'CXR', 'X-RAY CHEST', 'CHEST 1 VIEW'],
    }

    # Apply comprehensive deduplication - PREFER PRIMARY TERMS
    filtered_matched_labs = set()
    labs_to_remove = set()
    
    # First pass: identify what needs to be removed
    for lab in matched_labs:
        for primary_term, terms_to_remove in comprehensive_deduplication.items():
            if lab in terms_to_remove:
                labs_to_remove.add(lab)
                # Add the primary term if we're removing one of its components
                if primary_term not in labs_to_remove:
                    filtered_matched_labs.add(primary_term)
    
    # Second pass: add labs that weren't marked for removal
    for lab in matched_labs:
        if lab not in labs_to_remove:
            filtered_matched_labs.add(lab)
    
    matched_labs = filtered_matched_labs
    
    # --- Step 7: Check panels (only if ALL labs are present) ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    panels_found = set()
    
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]
        
        panel_labs_normalized = [re.sub(r'[-\s]+', ' ', lab.upper()) for lab in panel_labs]

        if panel_labs and all(re.search(r'\b' + re.escape(lab_norm) + r'\b', filtered_text) for lab_norm in panel_labs_normalized):
            panels_found.add(panel_name)
            # Remove labs that are part of this full panel
            for lab in panel_labs:
                if lab in matched_labs:
                    matched_labs.remove(lab)

    # Remove "IMAGING STUDY" if specific imaging tests are found
    specific_imaging_terms = ['MRI', 'CT SCAN', 'X-RAY', 'CHEST X-RAY', 'ULTRASOUND', 'ECHOCARDIOGRAM']
    if 'IMAGING STUDY' in matched_labs and any(term in matched_labs for term in specific_imaging_terms):
        matched_labs.remove('IMAGING STUDY')
    
    
    # --- Step 8: Add panels and remaining individual labs ---
    for panel in panels_found:
        results.append({"Lab Order": panel})
    
    for lab in matched_labs:
        # Skip if this lab is already covered by a panel
        if not any(lab in comprehensive_deduplication.get(panel, []) for panel in panels_found):
            results.append({"Lab Order": lab})

    # --- Step 9: FINAL CLEANUP - Remove any remaining duplicates ---
    unique_results = []
    seen_labs = set()
    
    for result in results:
        lab_name = result["Lab Order"]
        # Normalize the name for comparison
        normalized_name = re.sub(r'[-\s]+', ' ', lab_name.upper()).strip()
        
        if normalized_name not in seen_labs:
            seen_labs.add(normalized_name)
            unique_results.append(result)

    # --- Step 10: If nothing found ---
    if not unique_results:
        return [{"Lab Order": "No Evidence Found"}]

    return unique_results


def lab_review_olgmc(lab_str, dos=None):
    
    # --- Step 1: Load databases ---
    lab_df = LAB_DF
    group_test_df = PANEL_DF

    # --- Step 2: Check if lab content has dates ---
    
    def has_dates(text):
        """Check if text contains date patterns"""
        date_pattern = r'(\d{1,2}/\d{1,2}/\d{2,4}|[A-Za-z]{3}-\d{1,2}-\d{4})'
        return bool(re.search(date_pattern, text))
    
    def has_explicit_date_header(text):
        """Check if text has explicit date headers like 'Date: 01/03/25'"""
        date_header_patterns = [
            r'Date:\s*\d{1,2}/\d{1,2}/\d{2,4}',
            r'DOS:\s*\d{1,2}/\d{1,2}/\d{2,4}',
            r'Service Date:\s*\d{1,2}/\d{1,2}/\d{2,4}'
        ]
        return any(re.search(pattern, text, re.IGNORECASE) for pattern in date_header_patterns)
    
    # --- IMPROVED FILTERING LOGIC ---
    if dos:
        # If DOS is provided, try to filter by DOS
        if has_dates(lab_str) or has_explicit_date_header(lab_str):
            # Only filter if dates are present in the content
            filtered_lab_str = get_lab_content_by_dos(lab_str, dos)
            
            # CRITICAL FIX: If filtering returns empty but original has content, use original
            if not filtered_lab_str.strip() and lab_str.strip():
                #print(f"DEBUG: Filtered content empty but original has data, using original")
                filtered_lab_str = lab_str
        else:
            # If no dates in content, use entire lab content
            filtered_lab_str = lab_str
    else:
        # If no DOS provided, use entire lab content
        filtered_lab_str = lab_str
        
    
    # --- Step 4: Normalize input text ---
    input_str = (filtered_lab_str or "").upper()
    
    results = []
