def review_prior_external_notes_wa(lab_str, assessment_str, hpi_str):
    # --- Step 1: Combine inputs safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str]))
    lab_text = input_str.upper().strip()
    
    # --- Step 2: Keywords indicating external notes review ---
    keywords = [
        "PRIOR EXTERNAL NOTES", "EXTERNAL PROVIDER NOTES", "OUTSIDE RECORDS",
        "OUTSIDE NOTES", "REVIEWED PRIOR NOTES", "REVIEWED OUTSIDE NOTES",
        "REVIEWED PCP NOTES", "REVIEWED CONSULT NOTES", "REVIEWED SPECIALIST NOTES",
        "PREVIOUS RECORDS REVIEWED", "EXTERNAL RECORDS REVIEWED", "EXTERNAL DOCUMENTS REVIEWED",
        "ED REVIEWED", "I HAVE REVIEWED IMAGING", "I HAVE REVIEWED LABS", "I REVIEWED RELEVANT LABS, IMAGING AND PRIOR RECORDS",
        "REVIEWED AND AGREE WITH THE ABOVE FINDINGS", "REVIEWED BY NEUROLOGY", "REVIEWED BY ME"
    ]

    # --- Step 3: Regex patterns for flexible matching ---
    patterns = [
        r"REVIEW(?:ED|ING)?\s+(?:PRIOR|EXTERNAL|OUTSIDE)\s+(?:NOTES|RECORDS)",
        r"REVIEW(?:ED|ING)?\s+(?:PCP|PRIMARY\s+CARE|CONSULT|SPECIALIST)\s+NOTES",
        r"EXTERNAL\s+DOCUMENTS\s+REVIEW(?:ED|ING)?",
        r"OUTSIDE\s+HOSPITAL\s+RECORDS\s+REVIEW(?:ED|ING)?",
        r"PREVIOUS\s+(?:VISIT\s+)?RECORDS\s+REVIEW(?:ED|ING)?",
        r"\bED\s+REVIEW(?:ED|ING)?",
        r"I\s+HAVE\s+REVIEW(?:ED|ING)?\s+(?:IMAGING|LABS)",
        r"I\s+REVIEW(?:ED|ING)?\s+RELEVANT\s+LABS.*PRIOR\s+RECORDS",
        r"REVIEW(?:ED|ING)?\s+AND\s+AGREE\s+WITH.*FINDINGS",
        r"REVIEW(?:ED|ING)?\s+BY\s+(?:NEUROLOGY|ME)"
    ]
    results = []

    # --- Step 4: Exact keyword search ---
    for kw in keywords:
        if kw in lab_text:
            results.append({"Prior Review": kw})

    # --- Step 5: Regex search ---
    for pattern in patterns:
        match = re.search(pattern, lab_text)
        if match:
            results.append({"Prior Review": match.group(0)})

    # --- Step 6: Return results ---
    return results if results else [{"Prior Review": "No Evidence Found"}]


def lab_order_wa(assessment_str):
    # --- Step 1: Load databases ---
    lab_df = LAB_DF
    group_test_df = PANEL_DF

    # --- Step 2: Normalize input text ---
    input_str = (assessment_str or "").upper()
    # NORMALIZE HYPHENS TO SPACES AND FIX COMMON TYPOS
    input_str_normalized = re.sub(r'[-\s]+', ' ', input_str)
    # Fix common typos in medical terms
    input_str_normalized = re.sub(r'\bAXIALT\b', 'AXIAL', input_str_normalized)
    input_str_normalized = re.sub(r'\bCOMPUTERIZED\b', 'COMPUTED', input_str_normalized)
    input_str_normalized = re.sub(r'\bTOMOGRAPHY:\b', 'TOMOGRAPHY', input_str_normalized)
    
    results = []
    matched_labs = set()

    # --- Step 3: IMPROVED medication filtering ---
    # Only filter out lines that are PURELY about medications
    strong_medication_patterns = [
        r'^\s*\b(?:CONTINUE|HOLD|START)\b.*\b(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
        r'^\s*.*\b\d+\s*(?:MG|MCG)\b.*\b(?:DAILY|BID|TID)\b$',
    ]
    
    # Process line by line with GENTLE filtering
    lines = input_str_normalized.split('\n')
    filtered_lines = []
    
    for line in lines:
        line = line.strip()
        if not line:
            continue
        
        # Only exclude lines that are STRONGLY medication-only
        is_pure_medication = any(re.search(med_pat, line, re.IGNORECASE) for med_pat in strong_medication_patterns)
        
        if not is_pure_medication:
            filtered_lines.append(line)
    
    # Recombine filtered text
    filtered_text = ' '.join(filtered_lines)

    # --- Step 4: Enhanced individual lab matching with EXCLUSIONS ---
    # Exclude common medication terms from being detected as labs
    exclusion_terms = ['MG', 'MCG', 'TABLET', 'CAPSULE', 'TAB', 'PO', 'IV', 'BID', 'TID', 'QDAY']
    
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_normalized = re.sub(r'[-\s]+', ' ', lab_name.upper())
        
        # Skip if this lab name is in our exclusion list
        if lab_name_normalized in exclusion_terms:
            continue
            
        # Use word boundaries with normalized strings
        if re.search(r'\b' + re.escape(lab_name_normalized) + r'\b', filtered_text):
            matched_labs.add(lab_name)

    # --- Step 5: Enhanced pattern matching for common tests ---
    enhanced_order_patterns = [
        # Imaging studies - BROADER PATTERNS
        (r'\b(?:COMPUTED\s+)?(?:AXIAL\s+)?TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bCT\s+(?:SCAN)?\b', 'CT SCAN'),
        (r'\bCAT\s+SCAN\b', 'CT SCAN'),
        (r'\bAXIAL\s+TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bMRI\b', 'MRI'),  # Simple MRI pattern
        (r'\bX-?RAY\b', 'X-RAY'),
        (r'\bULTRASOUND\b', 'ULTRASOUND'),
        (r'\bECHOCARDIOGRAM\b', 'ECHOCARDIOGRAM'),
        (r'\bEKG\b', 'EKG'),
        (r'\bECG\b', 'ECG'),
        
        # Culture types
        (r'\bBLOOD\s+CULTURE\b', 'BLOOD CULTURE'),
        (r'\bURINE\s+CULTURE\b', 'URINE CULTURE'),
        (r'\bSPUTUM\s+CULTURE\b', 'SPUTUM CULTURE'),
        (r'\bWOUND\s+CULTURE\b', 'WOUND CULTURE'),
        
        # Action-oriented patterns for lab orders
        (r'\bOBTAIN\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bGET\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bORDER\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
        (r'\bNEED\s+(?:MRI|CT|X-?RAY|ULTRASOUND|ECHO)\b', 'IMAGING STUDY'),
    ]
    
    for pattern, test_name in enhanced_order_patterns:
        if re.search(pattern, filtered_text, re.IGNORECASE):
            matched_labs.add(test_name)

    # --- Step 6: DEDUPLICATION - Remove "IMAGING STUDY" if specific imaging found ---
    specific_imaging_terms = ['MRI', 'CT SCAN', 'COMPUTED TOMOGRAPHY', 'X-RAY', 'ULTRASOUND', 'ECHOCARDIOGRAM', 'EKG', 'ECG']
    if any(term in matched_labs for term in specific_imaging_terms) and 'IMAGING STUDY' in matched_labs:
        matched_labs.remove('IMAGING STUDY')

    # --- Step 6: Check panels (only if ALL labs are present) ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]
    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]
        
        panel_labs_normalized = [re.sub(r'[-\s]+', ' ', lab.upper()) for lab in panel_labs]

        if panel_labs and all(re.search(r'\b' + re.escape(lab_norm) + r'\b', filtered_text) for lab_norm in panel_labs_normalized):
            results.append({"Lab Order": panel_name})
            # Remove labs that are part of this full panel
            matched_labs = matched_labs - set(panel_labs)

    # --- Step 7: Add remaining unmatched individual labs ---
    for lab in matched_labs:
        results.append({"Lab Order": lab})

    # --- Step 8: If nothing found ---
    if not results:
        return [{"Lab Order": "No Evidence Found"}]

    return results

def lab_review_wa(lab_str, dos=None):
    """Modified to detect labs AND scans mentioned in clinical text"""
    
    # --- Step 1: Load databases ---
    lab_df = LAB_DF
    group_test_df = PANEL_DF

    # --- NEW STEP: Extract and process imaging studies from entire text WITH ROBUST DOS FILTERING ---
    def extract_imaging_studies_with_dos(text, target_dos=None):
        """Extract imaging studies from text with robust DOS filtering"""
        text_str = str(text)
        
        imaging_results = set()
        lines = text_str.split('\n')
        
        # Normalize target DOS for comparison
        if target_dos:
            # Remove any extra characters and normalize the target DOS
            target_dos_clean = re.sub(r'[^\d/]', '', target_dos)  # Keep only digits and slashes
            # Ensure consistent format (MM/DD/YYYY)
            target_dos_parts = target_dos_clean.split('/')
            if len(target_dos_parts) == 3:
                target_dos_normalized = f"{target_dos_parts[0]}/{target_dos_parts[1]}/{target_dos_parts[2]}"
            else:
                target_dos_normalized = target_dos_clean
        else:
            target_dos_normalized = None

        # print(f"DEBUG: Processing imaging with DOS: {target_dos_normalized}")
        
        for line in lines:
            line_upper = line.upper()
            line_upper = re.sub(r'[-\s]+', ' ', line_upper)
            
            # Normalize common imaging variations
            line_upper = re.sub(r'\bAXIALT\b', 'AXIAL', line_upper)
            line_upper = re.sub(r'\bCOMPUTERIZED\b', 'COMPUTED', line_upper)
            line_upper = re.sub(r'TOMOGRAPHY:', 'TOMOGRAPHY', line_upper)
            
            # Check if this line should be processed based on DOS
            should_process_line = False
            
            if target_dos_normalized:
                # Extract and normalize date from this line
                date_pattern = r'(\d{1,2}/\d{1,2}/\d{2,4})'
                date_match = re.search(date_pattern, line)
                
                if date_match:
                    line_date = date_match.group(1)
                    # Clean and normalize the line date
                    line_date_clean = re.sub(r'[^\d/]', '', line_date)
                    line_date_parts = line_date_clean.split('/')
                    
                    if len(line_date_parts) == 3:
                        # Handle 2-digit vs 4-digit years
                        year = line_date_parts[2]
                        if len(year) == 2:
                            year = '20' + year  # Assuming 21st century
                        line_date_normalized = f"{line_date_parts[0]}/{line_date_parts[1]}/{year}"
                        
                        # Check if the normalized line date matches target DOS
                        if line_date_normalized == target_dos_normalized:
                            should_process_line = True
                        else:
                            should_process_line = False
                    else:
                        should_process_line = False
                else:
                    # If no date in this line, but we have target DOS, skip it
                    should_process_line = False
            else:
                # No DOS provided, process all lines
                should_process_line = True
            
            if should_process_line:
                # DEBUG: Print which line is being processed
                #print(f"DEBUG: Processing line: {line_upper[:100]}...")
                
                # Imaging patterns (NEW)
                imaging_patterns = [
                    # CT variations
                    (r'\b(?:COMPUTED\s+)?(?:AXIAL\s+)?TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
                    (r'\bCT\s+(?:SCAN)?\b', 'CT SCAN'),
                    (r'\bCTA\b', 'CTA'),
                    (r'\bCAT\s+SCAN\b', 'CT SCAN'),
                    (r'\bAXIAL\s+TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
                    
                    # MRI variations
                    (r'\bMRI\s+(?:SCAN)?\b', 'MRI'),
                    
                                   
                    # Other imaging
                    (r'\bULTRASOUND\b', 'ULTRASOUND'),
                    (r'\bECHOCARDIOGRAM\b', 'ECHOCARDIOGRAM'),
                ]
                
                for pattern, imaging_name in imaging_patterns:
                    if re.search(pattern, line_upper, re.IGNORECASE):
                        imaging_results.add(imaging_name)
                        #print(f"DEBUG: Found {imaging_name} in line")
        
        
        return imaging_results

    # Process imaging studies with DOS filtering (NEW)
    imaging_results = extract_imaging_studies_with_dos(lab_str, dos)

    # --- ORIGINAL FUNCTIONALITY ---
    # --- Step 2: Split lab_str into clinical text vs dated lab data ---
    def extract_clinical_text_before_dates(text):
        """Extract text that appears before the first date pattern (clinical impressions)"""
        text_str = str(text)
        if not text_str.strip():
            return ""
            
        # Find the first date pattern in the text
        date_pattern = r'(\d{1,2}/\d{1,2}/\d{2,4}|[A-Za-z]{3}-\d{1,2}-\d{4})'
        first_date_match = re.search(date_pattern, text_str)
        
        if first_date_match:
            # Return text before the first date
            clinical_text = text_str[:first_date_match.start()].strip()
            return clinical_text
        else:
            # No dates found, return entire text
            return text_str

    # Extract clinical text (scan interpretations, impressions before dated data)
    clinical_text = extract_clinical_text_before_dates(lab_str)
    # NEW: Clean "nan" from the beginning of clinical text
    clinical_text = re.sub(r'^nan\s*', '', clinical_text)
    dated_lab_data = str(lab_str)  # Keep original for DOS filtering
    
    # --- Step 3: Process clinical text for scans/imaging ---
    results = []
    matched_labs = set()
    
    # Normalize clinical text
    clinical_text_upper = clinical_text.upper()
    clinical_text_upper = re.sub(r'[-\s]+', ' ', clinical_text_upper)
    clinical_text_upper = re.sub(r'\bAXIALT\b', 'AXIAL', clinical_text_upper)
    clinical_text_upper = re.sub(r'\bCOMPUTERIZED\b', 'COMPUTED', clinical_text_upper)
    clinical_text_upper = re.sub(r'TOMOGRAPHY:', 'TOMOGRAPHY', clinical_text_upper)
    
    # print(f"DEBUG: Normalized clinical text: '{clinical_text_upper}'") 
    # --- Step 4: Enhanced scan/imaging detection in clinical text ---
    scan_patterns = [
        # High priority - specific scans
        (r'\b(?:HEAD\s+)?COMPUTED?\s+(?:AXIAL\s+)?TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\b(?:HEAD\s+)?CT\s+(?:SCAN)?\b', 'CT SCAN'),
        (r'\b(?:HEAD\s+)?CAT\s+SCAN\b', 'CT SCAN'),
        (r'\bAXIAL\s+TOMOGRAPHY\b', 'COMPUTED TOMOGRAPHY'),
        (r'\bMRI\s+(?:SCAN)?\b', 'MRI'),
        
        # UPDATED X-RAY PATTERNS - HANDLE BOTH "X-RAY" AND "X RAY"
        (r'\bCHEST\s*>?\s*X[-\s]?RAY\b', 'CHEST X-RAY'),  # Handles both hyphen and space
        (r'\bCHEST\s*>?\s*X[-\s]?RAY', 'CHEST X-RAY'),    # Without word boundary at end
        (r'CHEST\s*>?\s*X[-\s]?RAY', 'CHEST X-RAY'),      # Most flexible
        (r'\bX[-\s]?RAY\b', 'X-RAY'),                     # Generic x-ray
        
        # Other imaging
        (r'\bULTRASOUND\b', 'ULTRASOUND'),
        (r'\bECHOCARDIOGRAM\b', 'ECHOCARDIOGRAM'),
        (r'\bEKG\b', 'EKG'),
        (r'\bECG\b', 'ELECTROCARDIOGRAM'),
    ]

    # Detect scans in clinical text
    for pattern, scan_name in scan_patterns:
        if re.search(pattern, clinical_text_upper, re.IGNORECASE):
            matched_labs.add(scan_name)
            #print(f"DEBUG: Found in clinical text: {scan_name}") 
    # Only add generic scan if no specific scans were detected
    if not matched_labs and re.search(r'\bSCAN\b', clinical_text_upper, re.IGNORECASE):
        matched_labs.add('IMAGING STUDY')
    
    # --- Step 5: Also check for scans in lab database in clinical text ---
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_upper = lab_name.upper().strip()
        lab_name_normalized = re.sub(r'[-\s]+', ' ', lab_name_upper)
        
        # Only check for imaging/scan-related tests in clinical text
        imaging_keywords = ['TOMOGRAPHY', 'CT', 'MRI', 'SCAN', 'X-RAY', 'ULTRASOUND', 'ECHO', 'IMAGING']
        if any(keyword in lab_name_normalized for keyword in imaging_keywords):
            if re.search(r'\b' + re.escape(lab_name_normalized) + r'\b', clinical_text_upper, re.IGNORECASE):
                matched_labs.add(lab_name)

    # --- Step 6: Process dated lab data with DOS filtering ---
    def has_dates(text):
        date_pattern = r'(\d{1,2}/\d{1,2}/\d{2,4}|[A-Za-z]{3}-\d{1,2}-\d{4})'
        return bool(re.search(date_pattern, text))
    
    if dos and has_dates(dated_lab_data):
        filtered_lab_str = get_lab_content_by_dos(dated_lab_data, dos)
    else:
        filtered_lab_str = dated_lab_data
    
    # MINIMAL FIX: If filtered content is empty but original has the target date, use broader matching
    if not filtered_lab_str.strip() and dos and dos in dated_lab_data:
        #print(f"DEBUG: Applying fallback - using original lab data")
        lines = dated_lab_data.split('\n')
        matching_lines = []
        for line in lines:
            if dos in line:
                matching_lines.append(line)
            elif matching_lines and line.strip() and not re.search(r'[A-Za-z]{3}-\d{1,2}-\d{4}', line):
                matching_lines.append(line)
        filtered_lab_str = '\n'.join(matching_lines)

    # Normalize input text for dated data processing
    input_str = (filtered_lab_str or "").upper()
    input_str = re.sub(r'[-\s]+', ' ', input_str)
    
    # print(f"DEBUG: Filtered lab data length: {len(filtered_lab_str)}")
    # print(f"DEBUG: Filtered lab data: {filtered_lab_str}")
    # --- Step 7: Enhanced individual lab matching for dated data ---
    for lab_name in lab_df["LAB_NAME"].dropna().unique():
        lab_name_upper = lab_name.upper().strip()
        
        # Define patterns based on lab name length and type
        if len(lab_name_upper) <= 2:
            # Short codes: require lab-value format (K: 3.5, CA=8.5, K 3.5, NA 136, K4.1, etc.)
            pattern1 = r'\b' + re.escape(lab_name_upper) + r'\s*[:=]\s*[\d\.]+'  # K: 3.5 or K=3.5
            pattern2 = r'\b' + re.escape(lab_name_upper) + r'\s+[\d\.]+'         # K 3.5 or NA 136  
            pattern3 = r'\b' + re.escape(lab_name_upper) + r'[\d\.]+'            # K4.1 (no space)
            
            if (re.search(pattern1, input_str, re.IGNORECASE) or 
                re.search(pattern2, input_str, re.IGNORECASE) or
                re.search(pattern3, input_str, re.IGNORECASE)):
                matched_labs.add(lab_name)
                
        elif len(lab_name_upper) <= 4:
            # Medium codes: can be standalone but prefer with values
            pattern1 = r'\b' + re.escape(lab_name_upper) + r'\s*[:=]\s*[\d\.]+'
            pattern2 = r'\b' + re.escape(lab_name_upper) + r'\s+[\d\.]+'
            pattern3 = r'\b' + re.escape(lab_name_upper) + r'\b'
            
            # Try patterns in order of specificity
            if re.search(pattern1, input_str, re.IGNORECASE) or \
            re.search(pattern2, input_str, re.IGNORECASE) or \
            re.search(pattern3, input_str, re.IGNORECASE):
                matched_labs.add(lab_name)
        else:
            # Long names: normal word boundary matching
            if re.search(r'\b' + re.escape(lab_name_upper) + r'\b', input_str, re.IGNORECASE):
                matched_labs.add(lab_name)
    
    # --- Step 8: Enhanced common lab pattern matching for dated data ---
    enhanced_patterns = [
        # Medication levels
        (r'\b(VANCOMYCIN\s+(?:TROUGH|LEVEL)\s*[:=]?\s*[\d\.]+)\b', 'VANCOMYCIN TROUGH'),
        (r'\b(GENTAMICIN\s+(?:TROUGH|LEVEL|PEAK)\s*[:=]?\s*[\d\.]+)\b', 'GENTAMICIN LEVEL'),
        (r'\b(TOBRAMYCIN\s+(?:TROUGH|LEVEL|PEAK)\s*[:=]?\s*[\d\.]+)\b', 'TOBRAMYCIN LEVEL'),
        (r'\b(DIGOXIN\s+LEVEL\s*[:=]?\s*[\d\.]+)\b', 'DIGOXIN LEVEL'),
        
        # Common lab tests in narrative format - REQUIRE NUMBERS
        (r'\b(INR\s*[:=]?\s*[\d\.]+)\b', 'INR'),
        (r'\b(PTT?\s*[:=]?\s*[\d\.]+)\b', 'PTT'),
        (r'\b(PCO2\s*[:=]?\s*[\d\.]+)\b', 'PCO2'),
        (r'\b(PO2\s*[:=]?\s*[\d\.]+)\b', 'PO2'),
        (r'\b(O2\s+SAT\w*\s*[:=]?\s*[\d\.]+)\b', 'O2 SATURATION'),
        
        # X-RAY PATTERNS - don't require digits
        (r'\bX-?RAY\b', 'X-RAY'),
        (r'\bCHEST\s*>?\s*X-?RAY\b', 'CHEST X-RAY'),
        (r'\bCHEST\s+X-?RAY\b', 'CHEST X-RAY'),
        (r'\bABDOMINAL\s*>?\s*X-?RAY\b', 'ABDOMINAL X-RAY'),
        (r'\bEXTREMITY\s*>?\s*X-RAY\b', 'EXTREMITY X-RAY'),
        (r'\bKUB\s*>?\s*X-?RAY\b', 'KUB X-RAY'),

        # Additional common patterns - REQUIRE NUMBERS
        (r'\b(HEMOGLOBIN\s*[:=]?\s*[\d\.]+)\b', 'HEMOGLOBIN'),
        (r'\b(HEMATOCRIT\s*[:=]?\s*[\d\.]+)\b', 'HEMATOCRIT'),
        (r'\b(WBC(?!S)\s*[:=]?\s*[\d\.]+)\b', 'WBC'),
        (r'\b(?:SODIUM\s*[:=]?\s*[\d\.]+|NA\s*[:=]?\s*[\d\.]+|NA\s+[\d\.]+|NA[\d\.]+)\b', 'SODIUM'),
        (r'\b(POTASSIUM\s*[:=]?\s*[\d\.]+|K\s*[:=]?\s*[\d\.]+|K\s+[\d\.]+|K[\d\.]+)\b', 'POTASSIUM'),
        (r'\b(CREATININE\s*[:=]?\s*[\d\.]+|CREAT\s*[:=]?\s*[\d\.]+)\b', 'CREATININE'),
        (r'\b(BUN\s*[:=]?\s*[\d\.]+)\b', 'BUN'),
        (r'\b(CHLORIDE\s*[:=]?\s*[\d\.]+|CL\s*[:=]?\s*[\d\.]+|CL\s+[\d\.]+)\b', 'CHLORIDE'),
        (r'\b(CARBON\s+DIOXIDE\s*[:=]?\s*[\d\.]+|BICARB\s*[:=]?\s*[\d\.]+|CO2\s*[:=]?\s*[\d\.]+)\b', 'CARBON DIOXIDE'),
        (r'\b(GLUCOSE\s*[:=]?\s*[\d\.]+|GLU\s*[:=]?\s*[\d\.]+)\b', 'GLUCOSE'),
        (r'\b(CALCIUM\s*[:=]?\s*[\d\.]+|CA\s*[:=]?\s*[\d\.]+)\b', 'CALCIUM'),
        (r'\b(ANION\s+GAP\s*[:=]?\s*[\d\.]+)\b', 'ANION GAP'),
        (r'\b(GFR\s*[:=]?\s*[\d\.]+)\b', 'GFR'),

        # Structured chemistry panel pattern
        (r'\bNA:\s*([\d\.]+)\s+K([\d\.]+)\s+CL:\s*([\d\.]+)\s+BICARB:\s*([\d\.]+)', 'CHEMISTRY PANEL'),
    ]
    
    for pattern, lab_type in enhanced_patterns:
        matches = re.finditer(pattern, input_str, re.IGNORECASE)
        for match in matches:
            full_match = match.group(0)
            #print(f"DEBUG: Pattern '{pattern}' matched '{full_match}' -> '{lab_type}'")
            
            # NEW: X-ray and imaging don't need digits
            is_imaging = any(term in lab_type for term in ['X-RAY', 'CT', 'MRI', 'TOMOGRAPHY', 'ULTRASOUND', 'ECHO'])
            
            if is_imaging:
                # Imaging studies don't require digits
                matched_labs.add(lab_type)
                #print(f"DEBUG: Added imaging '{lab_type}' from '{full_match}'")
            elif re.search(r'\d', full_match):
                # Lab tests require numbers for validation
                matched_labs.add(lab_type)
                #print(f"DEBUG: Added lab '{lab_type}' from '{full_match}'")
        
    # --- Step 9: Check panels (only if ALL labs are present) ---
    lab_columns = [col for col in group_test_df.columns if col.startswith("LAB")]

    # Create equivalence mapping for panel detection
    panel_equivalence = {
        "NA": "SODIUM",
        "K": "POTASSIUM", 
        "CL": "CHLORIDE",
        "BICARB": "CARBON DIOXIDE",
        "CO2": "CARBON DIOXIDE", 
        "HGB": "HEMOGLOBIN",
        "HCT": "HEMATOCRIT",
        "WBC": "WHITE BLOOD CELL COUNT",
        "RBC": "RED BLOOD CELL COUNT",
        "PLT": "PLATELET COUNT",
        "PLTCT": "PLATELET COUNT",
        "BUN": "UREA NITROGEN",
        "CREAT": "CREATININE",
        "GLU": "GLUCOSE",
        "CA": "CALCIUM",
        "ANION GA": "ANION GAP",
        "ANIONO GA": "ANION GAP",
        "GFR": "GLOMERULAR FILTRATION RATE",
    }

    for _, row in group_test_df.iterrows():
        panel_name = row["Panel Name"]
        panel_labs = [row[col] for col in lab_columns if pd.notna(row[col])]
        
        # Check if all panel labs are present (with equivalence mapping)
        all_panel_labs_present = True
        for panel_lab in panel_labs:
            panel_lab_upper = panel_lab.upper()
            
            # Check for the panel lab directly
            direct_match = re.search(r'\b' + re.escape(panel_lab_upper) + r'\b', input_str, re.IGNORECASE)
            
            # Check for equivalent names
            equivalent_match = False
            for short_name, long_name in panel_equivalence.items():
                if long_name.upper() == panel_lab_upper:
                    equivalent_match = re.search(r'\b' + re.escape(short_name.upper()) + r'\b', input_str, re.IGNORECASE)
                    if equivalent_match:
                        break
            
            if not (direct_match or equivalent_match):
                all_panel_labs_present = False
                break
        
        if all_panel_labs_present:
            results.append({"Lab Review": panel_name})
            # Remove equivalent labs that are part of this panel
            labs_to_remove = set()
            for panel_lab in panel_labs:
                panel_lab_upper = panel_lab.upper()
                # Add the main lab name
                labs_to_remove.add(panel_lab_upper)
                # Add equivalent short names
                for short_name, long_name in panel_equivalence.items():
                    if long_name.upper() == panel_lab_upper:
                        labs_to_remove.add(short_name.upper())
            
            matched_labs = matched_labs - labs_to_remove

    # --- COMBINE IMAGING RESULTS WITH LAB RESULTS ---
    # Add imaging results to the matched_labs set
    for imaging_result in imaging_results:
        matched_labs.add(imaging_result)

    # --- Step 10: Add remaining unmatched individual labs ---
    for lab in matched_labs:
        results.append({"Lab Review": lab})

    # --- Step 11: Deduplicate equivalent tests ---
    equivalence_map = {
        "CMP": "COMPREHENSIVE METABOLIC PANEL",
        "BMP": "BASIC METABOLIC PANEL", 
        "CBC": "COMPLETE BLOOD COUNT",
        "LFT": "LIVER FUNCTION TESTS",
        "RFT": "RENAL FUNCTION TESTS",
        "HEPATIC FUNCTION PANEL": "LIVER FUNCTION TESTS",
        "VANCOMYCIN TROUGH": "VANCOMYCIN LEVEL",
        "PT": "PTT",
        "K": "POTASSIUM",  
        "NA": "SODIUM",   
        "CT SCAN": "COMPUTED TOMOGRAPHY",
        "CAT SCAN": "COMPUTED TOMOGRAPHY",
        "CT ANGIOGRAPHY": "CTA",
        "COMPUTED TOMOGRAPHY ANGIOGRAPHY": "CTA",
        "SINGLE-VIEW": "X-RAY",  # ADDED: Map single-view to X-RAY
        "X-RAY": "CHEST X-RAY",  # Map generic X-RAY to CHEST X-RAY when both exist
        "CHEST X-RAY": "CHEST X-RAY",  # Self-reference
    }

    # Normalize results to avoid duplicates
    normalized = []
    seen = set()

    for entry in results:
        test = entry["Lab Review"].upper().strip()
        # Convert equivalent short forms to full name
        normalized_name = equivalence_map.get(test, test)

        # Avoid adding duplicates
        if normalized_name not in seen:
            seen.add(normalized_name)
            normalized.append({"Lab Review": normalized_name})

    # --- Step 12: Final fallback for very specific cases ---
    if not normalized:
        # Simple keyword presence check as last resort
        keywords = [
            "VANCOMYCIN", "GENTAMICIN", "TOBRAMYCIN", "CULTURE", 
            "INR", "PTT", "BLOOD GAS", "O2 SAT", "PCO2", "PO2"
        ]
        
        for keyword in keywords:
            if keyword in input_str:
                normalized.append({"Lab Review": keyword})

    # --- Step 13: If nothing found ---
    if not normalized:
        return [{"Lab Review": "No Evidence Found"}]
    
    return normalized

def discussion_management_wa(assessment_str, lab_str, consultation_str):
    """
    Extracts consultation/discussion information from consultation_str (discharge to)
    and fallback to assessment/lab text.
    """
    medical_specialties = [
            'CARDIOLOGY', 'NEPHROLOGY', 'NEUROLOGY', 'UROLOGY', 'PULMONOLOGY',
            'CRITICAL CARE', 'INTENSIVE CARE', 'ORTHOPEDIC', 'ORTHOPEDICS',
            'VASCULAR SURGERY', 'VASCULARS SURGERY', 'GENERAL SURGERY', 'CARDIAC SURGERY',
            'CARDIOVASCULAR SURGERY', 'PODIATRY', 'PHYSICAL THERAPY', 'OCCUPATIONAL THERAPY',
            'CASE MANAGEMENT', 'PULMONARY', 'TELE NEUROLOGY', 'GI', 'GASTROENTEROLOGY',
            'ONCOLOGY', 'HEMATOLOGY', 'NEUROSURGERY'
        ]
    
    final_results = []

    # --- Step 1: Process consultation_str (if present and not empty) ---
    #print(f"\n[WA DEBUG] consultation_str = '{consultation_str}'")
    if consultation_str and str(consultation_str).strip() and str(consultation_str).upper() != 'NAN':
        raw_consultation_terms = [str(consultation_str)]
        clean_consultation_terms = []
        seen_terms = set()

        for term in raw_consultation_terms:
            cleaned_term = term.strip().upper()
            if not cleaned_term:
                continue

            if re.search(r'\b\d+of\d+\b', cleaned_term) or 'PAGE' in cleaned_term:
                continue
            if any(noise in cleaned_term for noise in ['HOSPITALIST', 'DISCHARGE SUMMARY', 'WESTERN ARIZONA', 'REGIONAL MEDICAL', 'ONECONTENT']):
                continue
            if re.search(r'\bDR\.?\s+[A-Z]', cleaned_term) or re.search(r'[A-Z]+\s+PHY\b', cleaned_term):
                continue

            cleaned_term = re.sub(r'["\']', '', cleaned_term)

            noisy_patterns = [
                r'PATIENT IN THE PROCESS OF TRANSFERRING.*',
                r'EMERGENCY ROOM.*',
                r'SEE .*',
                r'GENERATED BY.*',
                r'GENERATED ON.*',
                r'ATTENDING.*',
                r'ADMITTED.*',
                r'ENCOUNTER.*',
                r'NAME.*',
            ]
            for pattern in noisy_patterns:
                cleaned_term = re.sub(pattern, '', cleaned_term).strip()

            if len(cleaned_term) < 3 or cleaned_term in ['NONE', '2OF3', '3OF4']:
                continue

            found_specialties = []
            for specialty in medical_specialties:
                if specialty in cleaned_term:
                    found_specialties.append(specialty)
            specialties = found_specialties if len(found_specialties) > 1 else [cleaned_term]

            for specialty in specialties:
                specialty = specialty.strip()
                if specialty and specialty not in seen_terms:
                    clean_consultation_terms.append(specialty)
                    seen_terms.add(specialty)

        for consult_term in clean_consultation_terms:
            final_results.append(consult_term.title() + " Consulted")
        #print(f"[WA DEBUG] consultation_str branch results: {final_results}")

    # --- Step 2: Fallback to parsing assessment_str and lab_str if consultation_str gave nothing ---
    if not final_results:
        input_str = " ".join(filter(None, [assessment_str, lab_str]))
        input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)
        #print(f"[WA DEBUG] Fallback input_str (first 500 chars): {input_str[:500]}")

        # REMOVED the huge exclusion regex block – only keep future consultation patterns
        future_consultation_patterns = [
            r'WARRANTS\s+.*\s+CONSULTATION',
            r'NEEDS?\s+.*\s+CONSULT',
            r'RECOMMEND\s+.*\s+CONSULT',
            r'CONSIDER\s+.*\s+CONSULT',
            r'PLAN\s+FOR\s+.*\s+CONSULT',
            r'FUTURE\s+.*\s+CONSULT',
            r'OUTPATIENT\s+.*\s+CONSULT',
            r'AS\s+AN\s+OUTPATIENT',
            r'IN\s+THE\s+FUTURE',
            r'TO\s+BE\s+CONSULTED',
        ]
        for pattern in future_consultation_patterns:
            input_str = re.sub(pattern, '', input_str, flags=re.IGNORECASE)

        input_upper = input_str.upper()

        discard_phrases = [
            'to history', 'refer to history', 'please refer to history',
            'history physical exam', 'refer to physical exam', 'to daily',
            'warrants', 'needs', 'recommend', 'consider', 'future', 'outpatient'
        ]

        discussed_keywords = [
            "DISCUSSED CASE WITH", "DISCUSSED WITH DR", "DISCUSSED WITH DOCTOR",
            "D/W DR.", "DISCUSSED WITH CARDIOLOGY", "CONSULTED WITH", "CASE DISCUSSED WITH",
            "CARDIOLOGY CONSULT", "NEUROLOGY ON BOARD", "RESPIRATORY THERAPY CONSULTED",
            "GI CONSULTED", "IR CONSULTED", "PULMONARY CONSULT", "CONSULT PULMONOLOGY",
            "CRITICAL CARE CONSULTED", "SURGERY CONSULT", "CRITICAL CARE CONSULT", "SURGERY CONSULT PLACED"
        ]

        discussed_patterns = [
            r"DISCUSSED\s+(CASE\s+)?WITH\s+DR\.?\s+\w+",
            r"DISCUSSED\s+(WITH\s+)?DOCTOR\s+\w+",
            r"CONSULTED\s+WITH\s+DR\.?\s+\w+",
            r"(?i)SEE\s+(?:TELE\s+)?(NEUROLOGY|CARDIOLOGY)\s+RECOMMENDATIONS",
            r"(?i)TELE\s+(NEUROLOGY|CARDIOLOGY)\s+(?:CONSULT|RECOMMENDATIONS)",
            r"(?i)RECOMMENDATIONS\s+FROM\s+(?:TELE\s+)?(NEUROLOGY|CARDIOLOGY)",
            r"(?i)\bPT\s+(?:AND\s+)?OT\s+EVALUATIONS",
            r"(?i)\bPHYSICAL\s+THERAPY\s+(?:AND\s+)?OCCUPATIONAL\s+THERAPY",
            r"(?i)\b(?:PT|OT)\s+EVAL",
            r"(?i)\b(CRITICAL CARE|CARDIOLOGY|NEPHROLOGY|NEUROLOGY|PULMONOLOGY|GASTROENTEROLOGY|HEMATOLOGY|INFECTIOUS DISEASE|UROLOGY|ORTHOPEDICS|SURGERY|VASCULAR SURGERY|GENERAL SURGERY)\s+(?:hasb?\s+)?been\s+consulted\b",
            r"(?i)(?:Case discussed|Discussed|Spoke with|Consulted(?: with)?|Contacted)\s+(?:Dr\. [A-Z][a-z]+(?: \([A-Za-z\s]+\))?|[A-Za-z\s]+ (?:physician|nurse|caregiver|team|consultant))",
            r"(?i)\b(?:CARDIOLOGY|NEUROLOGY|GI|IR|PULMONARY|RESPIRATORY\s+THERAPY|CRITICAL CARE|SURGERY)\s+(?:CONSULT|CONSULTED|EVALUATION)\b",
            r"\bON\s+BOARD\b",
            r"(?i)\bper\s+(?:rec(?:ommendation)?\s+of\s+)?(CARDIOLOGY|NEPHROLOGY|CRITICAL CARE|NEUROLOGY|PULMONOLOGY|GASTROENTEROLOGY|HEMATOLOGY|INFECTIOUS DISEASE|UROLOGY|ORTHOPEDICS|SURGERY|VASCULAR SURGERY|GENERAL SURGERY)\b",
            r"(?i)\bas\s+per\s+(CARDIOLOGY|NEPHROLOGY|CRITICAL CARE|NEUROLOGY|PULMONOLOGY|GASTROENTEROLOGY|HEMATOLOGY|INFECTIOUS DISEASE|UROLOGY|ORTHOPEDICS|SURGERY|VASCULAR SURGERY|GENERAL SURGERY)\b",
        ]

        results_temp = []
        for item in discussed_keywords:
            if item in input_upper:
                results_temp.append(item)
        for pattern in discussed_patterns:
            matches = re.findall(pattern, input_str, flags=re.IGNORECASE)
            for m in matches:
                if isinstance(m, str):
                    # Check if this capture is a specialty name (all caps, short)
                    if m.upper() in [s.upper() for s in medical_specialties]:
                        results_temp.append(f"{m.title()} Consulted")
                    else:
                        results_temp.append(m.strip())
                elif isinstance(m, tuple):
                    combined = " ".join([x for x in m if x and isinstance(x, str)]).strip()
                    if combined:
                        # If combined is a single specialty (e.g., "CARDIOLOGY")
                        if combined.upper() in [s.upper() for s in medical_specialties]:
                            results_temp.append(f"{combined.title()} Consulted")
                        else:
                            results_temp.append(combined)

        #print(f"[WA DEBUG] results_temp before normalization: {results_temp}")
        # Convert any raw specialty name to "Specialty Consulted"
        converted = []
        for item in results_temp:
            item_upper = item.upper().strip()
            if item_upper in [s.upper() for s in medical_specialties]:
                converted.append(f"{item.title()} Consulted")
            else:
                converted.append(item)
        results_temp = converted
        def normalize_consultation(consult_text):
            consult_upper = consult_text.upper()
            # If the text is exactly a known specialty (e.g., "CARDIOLOGY")
            if consult_upper in [s.upper() for s in medical_specialties]:
                return f"{consult_text.title()} Consulted"
            if "TELE NEUROLOGY" in consult_upper or "SEE TELE NEUROLOGY" in consult_upper:
                return "Tele Neurology Consulted"
            elif "PT" in consult_upper and "OT" in consult_upper:
                return "Physical Therapy, Occupational Therapy Consulted"
            elif "PT" in consult_upper and "EVAL" in consult_upper:
                return "Physical Therapy Consulted"
            elif "OT" in consult_upper and "EVAL" in consult_upper:
                return "Occupational Therapy Consulted"
            elif "NEURO SURGICAL" in consult_upper or "NEUROSURGICAL" in consult_upper:
                if any(term in consult_upper for term in ['WARRANTS', 'NEEDS', 'FUTURE', 'OUTPATIENT']):
                    return None
                else:
                    return "Neurosurgery Consulted"
            elif "PHYSICAL THERAPY" in consult_upper:
                return "Physical Therapy Consulted"
            elif "OCCUPATIONAL THERAPY" in consult_upper:
                return "Occupational Therapy Consulted"
            elif "CONSULT" == consult_upper.strip():
                return None
            elif "NEUROLOGY" == consult_upper.strip():
                return None
            return consult_text

        normalized_results = []
        for result in results_temp:
            normalized = normalize_consultation(result)
            if normalized:
                normalized_results.append(normalized)

        filtered_results = []
        for result in normalized_results:
            result_lower = result.lower()
            if not any(discard in result_lower for discard in discard_phrases):
                filtered_results.append(result)

        unique_results = []
        seen = set()
        filtered_results_sorted = sorted(filtered_results, key=len, reverse=True)
        for res in filtered_results_sorted:
            if not any(res.lower() in existing.lower() for existing in seen):
                seen.add(res)
                unique_results.append(res)

        final_results = [r for r in unique_results if r and str(r).strip()]
        #print(f"[WA DEBUG] final_results after processing: {final_results}")

    return [{"Discussed Management": final_results if final_results else ["No Evidence Found"]}]

def independent_interpretation_wa(lab_str, assessment_str, hpi_str):
    # --- Step 1: Combine safely ---
    input_str = " ".join(filter(None, [lab_str, assessment_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str)

    # --- Step 2: Keywords (generic only, no variants) ---
    interpretation_keywords = [
            "INDEPENDENTLY INTERPRETED", "INDEPENDENT INTERPRETATION",
            "PERSONALLY REVIEWED AND INTERPRETED", "REVIEWED AND INTERPRETED BY ME",
            "INTERPRETED BY ME", "MY INTERPRETATION", "MY EKG INTERPRETATION",
            "I INTERPRETED THE EKG", "EKG INTERPRETED", "I INTERPRETED THE ECHO",
            "ECHO INTERPRETED", "MY ECHO INTERPRETATION", "I INTERPRETED THE XRAY",
            "I INTERPRETED THE CT", "I INTERPRETED THE MRI", "XRAY INTERPRETED",
            "CT INTERPRETED", "MRI INTERPRETED", "I INTERPRETED THE PFT",
            "PFT INTERPRETED", "I INTERPRETED THE HOLTER", "HOLTER INTERPRETED",
            "PACEMAKER INTERROGATION INTERPRETED", "MY EKG INTERPRETATION IS NSR",
            "MY CT INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
            "MY X-RAY INTERPRETATION: I AGREE WITH RADIOLOGIST REPORT",
            "INTERPRETATION BY ME", "REVIEWED BY ME", "I PERSONALLY VIEWED AND INTERPRETED"
    ]

    # --- Step 3: Regex patterns (handles variants) ---
    interpretation_patterns = [
            r"I\s+(PERSONALLY\s+)?INTERPRETED\s+(THE\s+)?(EKG|ECHO|XRAY|X-RAY|CT|MRI|PFT|HOLTER|PACEMAKER)",
            r"MY\s+(EKG|ECHO|XRAY|CT|MRI|INTERPRETATION)",
            r"(EKG|ECHO|XRAY|CT|MRI|HOLTER|PACEMaker|PFT)\s+INTERPRETED",
            r"INDEPENDENTLY\s+INTERPRETED",
            r"REVIEWED\s+AND\s+INTERPRETED\s+BY\s+ME",
            r"(?:^|\W)MY\s+(CT|X-?RAY|EKG)\s+INTERPRETATION(?::| IS)\s+.*"
    ]
    results = []

    # --- Step 4: Keyword matches ---
    for phrase in interpretation_keywords:
        if phrase in input_str.upper():
            results.append(phrase)

    # --- Step 5: Regex matches ---
    for pattern in interpretation_patterns:
        matches = re.findall(pattern, input_str, flags=re.IGNORECASE)
        results.extend([m.strip() for m in matches])

    # --- Step 6: Unique + ordered ---
    seen = set()
    unique_results = [x for x in results if not (x in seen or seen.add(x))]

    return [{"Independent Interpretation": unique_results or ["No Evidence Found"]}]


def independent_historian_wa(assessment_str, hpi_str):
    
    # --- Step 1: Combine safely ---
    input_str = " ".join(filter(None, [assessment_str, hpi_str]))
    input_str = re.sub(r'^[\s.]+|[\s.]+$', '', input_str).upper()

    # --- Step 2: Define key lists ---
    relation_keywords = [
        "PARENT","GUARDIAN","SPOUSE","HUSBAND","WIFE","SON","DAUGHTER","FAMILY MEMBER",
        "RELATIVE","BROTHER","SISTER","UNCLE","AUNT","GRANDMOTHER","GRANDFATHER",
        "FRIEND","NEIGHBOR","CAREGIVER","CASE MANAGER","NURSE","PHYSICIAN ASSISTANT",
        "CLINICAL STAFF","EMS","EMT","PARAMEDIC","EMPLOYER","WITNESS","LEGAL GUARDIAN",
        "SURROGATE","TEAM","STAFF"
    ]

    action_keywords = [
        "REPORTED","STATED","TOLD","MENTIONED","INFORMED","SAID","PROVIDED","GIVEN",
        "OBTAINED","HISTORY TAKEN","HISTORY PROVIDED","OBSERVED","DOCUMENTED","COLLECTED",
        "PRESENTED","ARRIVED","BROUGHT","CAME","ACCOMPANIED"
    ]

    phrase_patterns = [
        r"(?i)\bINDEPENDENT HISTORIAN\b",
        r"(?i)\bHISTORY (?:PROVIDED|TAKEN|OBTAINED)\s+FROM\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bINFORMATION\s+(?:GIVEN|PROVIDED)\s+BY\s+(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bPRESENTED\s+(?:WITH|BY)\s+(?:HIS|HER|THE)?\s*(?:{})\b".format("|".join(relation_keywords)),
        r"(?i)\bACCOMPANIED\s+BY\s+(?:HIS|HER|THE)?\s*(?:{})\b".format("|".join(relation_keywords))
    ]

    # --- Step 3: Split text roughly into sentences ---
    sentences = [s.strip() for s in re.split(r'[.;!\n]', input_str) if s.strip()]

    results = []

    # --- Step 4: Main logic ---
    for sentence in sentences:
        # Check if any key phrase matches
        if any(re.search(p, sentence, re.IGNORECASE) for p in phrase_patterns):
            results.append(sentence)
            continue

        # Find combination of relation + action keywords
        if any(r in sentence for r in relation_keywords) and any(a in sentence for a in action_keywords):
            results.append(sentence)

    # --- Step 5: Context limiter (keep relevant ~15 words around the match)
    trimmed_results = []
    for s in results:
        words = s.split()
        joined = " ".join(words)

        # find first occurrence of any keyword
        match = re.search(
            r"(" + "|".join(relation_keywords + action_keywords) + r")",
            joined
        )
        if match:
            idx = joined[:match.start()].count(" ")
            start = max(0, idx - 8)
            end = min(len(words), idx + 8)
            trimmed_results.append(" ".join(words[start:end]))
        else:
            trimmed_results.append(s[:120])  # fallback limit

    # --- Step 6: Return clean output ---
    if trimmed_results:
        return [{"Independent Historian": list(dict.fromkeys(trimmed_results))}]
    else:
        return [{"Independent Historian": ["No Evidence Found"]}]

def process_row_wa(row, config):
    """
    Process a single row for facility WA.
    Expects the following helper functions to be defined:
        review_prior_external_notes_wa(lab_str, assessment_str, hpi_str)
        independent_interpretation_wa(lab_str, assessment_str, hpi_str)
        discussion_management_wa(assessment_str, lab_str)
        lab_order_wa(assessment_str)
        lab_review_wa(lab_str, dos=None)
        independent_historian_wa(assessment_str, hpi_str)
    """
    # --- Run helper functions (order matches notebook's compute_mdm2_details) ---
    discussion = discussion_management_wa(row["assessment_str"], row["lab_str"], row.get("consultation_str", ""))
    #print(f"[process_row_wa] discussion = {discussion}")
    interpretation = independent_interpretation_wa(
        row["lab_str"], row["assessment_str"], row["hpi_str"]
    )
    prior_review = review_prior_external_notes_wa(
        row["lab_str"], row["assessment_str"], row["hpi_str"]
    )
    lab_orders = lab_order_wa(row["assessment_str"])
    lab_review_result = lab_review_wa(row["lab_str"], row["DOS"])
    historian = independent_historian_wa(row["assessment_str"], row["hpi_str"])

    # --- Run MDM2 logic (uses utils.Process_MDM2) ---
    from utils import Process_MDM2, flatten_list_of_dicts, simplify_list_of_dicts
    mdm2_level, label, reasons = Process_MDM2(
        discussion, interpretation, prior_review,
        lab_orders, lab_review_result, historian
    )

    # --- Flatten results for the REASONS column ---
    prior_review_vals = flatten_list_of_dicts(prior_review, "Prior Review")
    lab_orders_simple = simplify_list_of_dicts(lab_orders, "Lab Order")
    lab_review_simple = simplify_list_of_dicts(lab_review_result, "Lab Review")
    discussion_vals = flatten_list_of_dicts(discussion, "Discussed Management")
    interpretation_vals = flatten_list_of_dicts(interpretation, "Independent Interpretation")
    historian_vals = flatten_list_of_dicts(historian, "Independent Historian")

    details_parts = [
        f"Review Prior Notes> {prior_review_vals or ['No Evidence Found']}",
        f"Lab Order> {lab_orders_simple or ['No Evidence Found']}",
        f"Lab Review> {lab_review_simple or ['No Evidence Found']}",
        f"Discussion Management/Test> {discussion_vals or ['No Evidence Found']}",
        f"Independent Interpretation> {interpretation_vals or ['No Evidence Found']}",
        f"Independent Historian> {historian_vals or ['No Evidence Found']}"
    ]
    details = "~".join(details_parts)

    # --- Build reference text (selected sections) ---
    def safe_text(value):
        return str(value).replace(";", ",").strip()

    sections = []
    if row.get("assessment_str"):
        sections.append(f"[Assessment]: {safe_text(row['assessment_str'])}")
    if row.get("hpi_str"):
        sections.append(f"[HPI]: {safe_text(row['hpi_str'])}")
    if row.get("lab_str"):
        sections.append(f"[Lab]: {safe_text(row['lab_str'])}")
    if row.get("phy_str"):
        sections.append(f"[Physical]: {safe_text(row['phy_str'])}")
    if row.get("objective_str"):
        sections.append(f"[Objective]: {safe_text(row['objective_str'])}")
    combined_text = " ~ ".join(sections).replace("\n", " ").strip()

    # --- Extract Chart ID (use existing "Chart" column, or fallback) ---
    chart = row.get("Chart", row["Filename"].replace("WA_", "").replace(".TIF", ""))

    # --- Return Series with expected column names (matches notebook output) ---
    # Note: Notebook uses "Page_No", config uses "Page No" - handle in config mapping
    return pd.Series({
        "Filename": row["Filename"],
        "Chart": chart,
        "DOS": row["DOS"],
        "Visit": row["Visit"],
        "Visit Time": row["Visit_time"],
        "MDM2_Level": label.upper(),
        "REASONS FOR MDM2": details,
        "REFERENCE TEXT MDM2": combined_text,
        "Page_No": row["Page_No"]   # keep as in notebook; config can map to "Page No"
    })

